-- Poems batch 467
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-37','長安書懷投知己','李頻','唐','御定全唐诗','yuding','','[]','所學近雕蟲，知難謁至公。徒隨眾人後，擬老一生中。',144,'御定全唐詩/json/589.json','["所學近雕蟲，知難謁至公。徒隨眾人後，擬老一生中。", "間歲家書到，經荒世業空。心懸滄海斷，夢與白雲通。", "玉漏聲連北，銀河氣極東。關門迢遞月，禁苑寂寥鴻。", "地廣身難束，時平道獨窮。蕭條苔長雨，淅瀝葉危風。", "久愧幹朝客，多慚別釣翁。因依非不忝，延薦況曾蒙。", "與善應無替，垂恩本有終。霜天搖落日，莫使逐孤蓬。"]'),
('yuding-38','送姚侍禦充渭北掌書記','李頻','唐','御定全唐诗','yuding','','[]','北境烽煙急，南山戰伐頻。撫綏初易帥，參畫盡須人。',120,'御定全唐詩/json/589.json','["北境烽煙急，南山戰伐頻。撫綏初易帥，參畫盡須人。", "書記才偏稱，朝廷意更親。繡衣行李日，綺陌別離塵。", "報國將臨虜，之藩不離秦。豸冠嚴在首，雄筆健隨身。", "飲馬河聲暮，休兵塞色春。敗亡仍暴骨，冤哭可傷神。", "上策何當用，邊情此是真。雕陰曾久客，拜送欲沾巾。"]'),
('yuding-39','長安書情投知己','李頻','唐','御定全唐诗','yuding','','[]','陝服因詩句，從容已半年。一從歸闕下，罕得到門前。',288,'御定全唐詩/json/589.json','["陝服因詩句，從容已半年。一從歸闕下，罕得到門前。", "每候朝軒出，常看列宿懸。重投期見獎，數首果蒙傳。", "轉覺功宜倍，兼令住更堅。都忘春暫醉，少省夜曾眠。", "煩暑燈誰讀，孤雲業自專。精華搜未竭，騷雅琢須全。", "此事勤雖過，他謀拙莫先。槐街勞白日，桂路在青天。", "取第殊無序，還鄉可有緣。旅情長越鳥，秋思幾秦蟬。", "月色千樓滿，砧聲萬井連。江山阻迢遞，時節暗推遷。", "道即窮通守，才應始末憐。書紳相戒語，藏篋贈行篇。", "致主當齊聖，為郎本是仙。人心期際會，鳳翼許遷延。", "畢竟良圖在，何妨逸性便。幽齋中寢覺，珍木正陰圓。", "隱幾閑瞻夜，臨雲興渺然。五陵供麗景，六義動花箋。", "倘與潛生翼，寧非助化權。免教垂素發，歸種海隅田。"]'),
('yuding-40','府試丹浦非樂戰','李頻','唐','御定全唐诗','yuding','','[]','自古為君道，垂衣致理難。懷仁須去殺，用武即勝殘。',72,'御定全唐詩/json/589.json','["自古為君道，垂衣致理難。懷仁須去殺，用武即勝殘。", "毒幟誅方及，兵臨釁可觀。居來彭蠡固，戰罷洞庭寬。", "雪國知天遠，霜林是血丹。吾皇則堯典，薄伐至桑幹。"]'),
('yuding-41','府試風雨聞雞','李頻','唐','御定全唐诗','yuding','','[]','不為風雨變，雞德一何貞。在暗長先覺，臨晨即自鳴。',72,'御定全唐詩/json/589.json','["不為風雨變，雞德一何貞。在暗長先覺，臨晨即自鳴。", "陰霾方見信，頃刻詎移聲。向晦如相警，知時似獨清。", "蕭蕭和斷漏，喔喔報重城。欲識詩人興，中含君子情。"]'),
('yuding-42','府試觀蘭亭圖','李頻','唐','御定全唐诗','yuding','','[]','往會人何處，遺蹤事可觀。林亭今日在，草木古春殘。',72,'御定全唐詩/json/589.json','["往會人何處，遺蹤事可觀。林亭今日在，草木古春殘。", "筆想吟中駐，杯疑飲後幹。向青穿峻嶺，當白認回湍。", "月影窗間夜，湖光枕上寒。不知詩酒客，誰更慕前歡。"]'),
('yuding-43','府試老人星見','李頻','唐','御定全唐诗','yuding','','[]','良宵出戶庭，極目向青冥。海內逢康日，天邊見壽星。',72,'御定全唐詩/json/589.json','["良宵出戶庭，極目向青冥。海內逢康日，天邊見壽星。", "臨空遙的的，竟曉獨熒熒。春後先依景，秋來忽近丁。", "垂休臨有道，作瑞掩前經。豈比周王夢，徒言得九齡。"]'),
('yuding-44','省試振鷺','李頻','唐','御定全唐诗','yuding','','[]','有鳥生江浦，霜華作羽翰。君臣將比潔，朝野共相歡。',72,'御定全唐詩/json/589.json','["有鳥生江浦，霜華作羽翰。君臣將比潔，朝野共相歡。", "月影林梢下，冰光水際殘。翻飛時共樂，飲啄道皆安。", "迥翥宜高詠，群棲入靜看。由來鴛鷺侶，濟濟列千官。"]'),
('yuding-45','寄辛明府','李頻','唐','御定全唐诗','yuding','','[]','何處無苛政，東南有子男。細將朝客說，須是邑人諳。',72,'御定全唐詩/json/589.json','["何處無苛政，東南有子男。細將朝客說，須是邑人諳。", "別業空經稔，歸田獨未甘。目凝煙積樹，心貯月明潭。", "曉鼓愁方亂，春山睡正酣。不任啼鳥思，鄉社欲桑蠶。"]'),
('yuding-46','苑中題友人林亭','李頻','唐','御定全唐诗','yuding','','[]','井邑藏岩穴，幽棲趣若何。春篁抽筍密，夏鳥雜雛多。',72,'御定全唐詩/json/589.json','["井邑藏岩穴，幽棲趣若何。春篁抽筍密，夏鳥雜雛多。", "坐有清風至，林無暑氣過。亂書還就葉，真飲不聽歌。", "片影明紅蘚，斜陰映綠蘿。雄文終可惜，莫更棄高科。"]'),
('yuding-47','投京兆府試官任文學先輩','李頻','唐','御定全唐诗','yuding','','[]','高興每論詩，非才獨見推。應當明試日，不比暗投時。',96,'御定全唐詩/json/589.json','["高興每論詩，非才獨見推。應當明試日，不比暗投時。", "出口人皆信，操心自可知。孤單雖有托，際會別無期。", "取捨知由己，窮通斷在茲。賤身何足數，公道自難欺。", "澤國違甘旨，漁舟積夢思。長安未歸去，為倚鑒妍媸。"]'),
('yuding-48','宋少府東溪泛舟','李頻','唐','御定全唐诗','yuding','','[]','登岸還入舟，水禽驚笑語。晚葉低眾色，濕雲帶繁暑。',36,'御定全唐詩/json/589.json','["登岸還入舟，水禽驚笑語。晚葉低眾色，濕雲帶繁暑。", "落日乘醉歸，溪流複幾許。"]'),
('yuding-49','聞北虜入靈州二首','李頻','唐','御定全唐诗','yuding','','[]','河冰一夜合，虜騎入靈州。歲歲徵兵去，難防塞草秋。',48,'御定全唐詩/json/589.json','["河冰一夜合，虜騎入靈州。歲歲徵兵去，難防塞草秋。", "見說靈州戰，沙中血未幹。將軍日告急，走馬向長安。"]'),
('yuding-50','送友人下第歸感懷','李頻','唐','御定全唐诗','yuding','','[]','帝裏春無意，歸山對物華。即應來日去，九陌踏槐花。',24,'御定全唐詩/json/589.json','["帝裏春無意，歸山對物華。即應來日去，九陌踏槐花。"]'),
('yuding-51','贈桂林友人','李頻','唐','御定全唐诗','yuding','','[]','君家桂林住，日伐桂枝炊。何事東堂樹，年年待一枝。',24,'御定全唐詩/json/589.json','["君家桂林住，日伐桂枝炊。何事東堂樹，年年待一枝。"]'),
('yuding-52','長安感懷','李頻','唐','御定全唐诗','yuding','','[]','一第知何日，全家待此身。空將灞陵酒，酌送向東人。',24,'御定全唐詩/json/589.json','["一第知何日，全家待此身。空將灞陵酒，酌送向東人。"]'),
('yuding-53','題長孫桐樹','李頻','唐','御定全唐诗','yuding','','[]','一去龍門側，千年鳳影移。空餘剪圭處，無複在孫枝。',24,'御定全唐詩/json/589.json','["一去龍門側，千年鳳影移。空餘剪圭處，無複在孫枝。"]'),
('yuding-54','渡漢江','李頻','唐','御定全唐诗','yuding','','[]','嶺外音書絕，經年複曆春。近鄉情更怯，不敢問來人。',24,'御定全唐詩/json/589.json','["嶺外音書絕，經年複曆春。近鄉情更怯，不敢問來人。"]'),
('yuding-55','嵩山夜還','李頻','唐','御定全唐诗','yuding','','[]','家住東皋去，好采舊山薇。自省游泉石，何曾不夜歸。',24,'御定全唐詩/json/589.json','["家住東皋去，好采舊山薇。自省游泉石，何曾不夜歸。"]'),
('yuding-56','暮秋宿清源上人院','李頻','唐','御定全唐诗','yuding','','[]','野客愁來日，山房木落中。微風生夜半，積雨向秋終。',48,'御定全唐詩/json/589.json','["野客愁來日，山房木落中。微風生夜半，積雨向秋終。", "證道方離法，安禪不住空。迷途將覺路，語默見西東。"]'),
('yuding-57','秋夜宿重本上人院','李頻','唐','御定全唐诗','yuding','','[]','卻憶涼堂坐，明河幾度流。安禪逢小暑，抱疾入高秋。',48,'御定全唐詩/json/589.json','["卻憶涼堂坐，明河幾度流。安禪逢小暑，抱疾入高秋。", "水國曾重講，雲林半舊遊。此來看月落，還似道相求。"]'),
('yuding-58','贈立規上人','李頻','唐','御定全唐诗','yuding','','[]','竹向空齋合，無僧在四鄰。去雲離坐石，斜月到禪身。',48,'御定全唐詩/json/589.json','["竹向空齋合，無僧在四鄰。去雲離坐石，斜月到禪身。", "樹老風終夜，山寒雪見春。不知諸祖後，傳印是何人。"]'),
('yuding-59','蘇州寒食日送人歸覲','李頻','唐','御定全唐诗','yuding','','[]','江城寒食下，花木慘離魂。幾宿投山寺，孤帆過海門。',48,'御定全唐詩/json/589.json','["江城寒食下，花木慘離魂。幾宿投山寺，孤帆過海門。", "□聲潑火雨，柳色禁煙村。定看堂高後，斑衣滅淚痕。"]'),
('yuding-60','即席送許□之曹南省兄','李頻','唐','御定全唐诗','yuding','','[]','梅爛荷圓六月天，歸帆高背虎丘煙。到時自見成行雁，',40,'御定全唐詩/json/589.json','["梅爛荷圓六月天，歸帆高背虎丘煙。到時自見成行雁，", "待看春榜來江外，名占蓬萊第幾仙。"]'),
('yuding-61','送羅著作兩浙按獄','李頻','唐','御定全唐诗','yuding','','[]','使印星車適舊游，陶潛今日在瀛洲。科條盡曉三千罪，',40,'御定全唐詩/json/589.json','["使印星車適舊游，陶潛今日在瀛洲。科條盡曉三千罪，", "歸來重過姑蘇郡，莫忘題名在虎丘。"]'),
('yuding-62','下第後屏居書懷寄張侍禦','李頻','唐','御定全唐诗','yuding','','[]','刖足豈一生，良工隔千里。故山彭澤上，歸夢向汾水。',96,'御定全唐詩/json/589.json','["刖足豈一生，良工隔千里。故山彭澤上，歸夢向汾水。", "低催神氣盡，僮僕心亦恥。未達誰不知，達者多忘此。", "行年忽已壯，去老年更幾。功名如不彰，身歿豈為鬼。", "才看芳草歇，即歎涼風起。驄馬未來朝，嘶聲尚在耳。"]'),
('yuding-63','答韓中丞容不飲酒','李頻','唐','御定全唐诗','yuding','','[]','老大成名仍足病，強聽絲竹亦無歡。',32,'御定全唐詩/json/589.json','["老大成名仍足病，強聽絲竹亦無歡。", "高情太守容閑坐，借與青山盡日看。"]'),
('yuding-64','句','李頻','唐','御定全唐诗','yuding','','[]','只將五字句，用破一生心。',36,'御定全唐詩/json/589.json','["只將五字句，用破一生心。", "楚裏八千里，盤盤此都會。巍峨數裏城，遠水相映帶。"]'),
('yuding-0','冬至後西湖泛舟看斷冰偶成長句','李郢','唐','御定全唐诗','yuding','','[]','一陽生後陰飆竭，湖上層冰看折時。雲母扇搖當殿色，',48,'御定全唐詩/json/590.json','["一陽生後陰飆竭，湖上層冰看折時。雲母扇搖當殿色，", "山影淺中留瓦礫，日光寒外送漣漪。崖崩葦岸縱橫散，"]'),
('yuding-1','陽羨春歌','李郢','唐','御定全唐诗','yuding','','[]','石亭梅花落如積，玉蘚斕班竹姑赤。祝陵有酒清若空，',72,'御定全唐詩/json/590.json','["石亭梅花落如積，玉蘚斕班竹姑赤。祝陵有酒清若空，", "溪頭鐃鼓狂殺儂，青蓋紅裙偶相值。風光何處最可憐，", "三月未有二月殘，靈龜可信淹水幹。葑草青青促歸去，"]'),
('yuding-2','茶山貢焙歌','李郢','唐','御定全唐诗','yuding','','[]','使君愛客情無已，客在金台價無比。春風三月貢茶時，',144,'御定全唐詩/json/590.json','["使君愛客情無已，客在金台價無比。春風三月貢茶時，", "陵煙觸露不停探，官家赤印連帖催。朝饑暮匐誰興哀，", "研膏架動轟如雷，茶成拜表貢天子。萬人爭啖春山摧，", "到時須及清明宴，吾君可謂納諫君。諫官不諫何由聞，", "就焙嘗茶坐諸客，幾回到口重咨嗟。嫩綠鮮芳出何力，", "金絲宴饌隨經過，使君是日憂思多。客亦無言征綺羅，"]'),
('yuding-3','夏日登信州北樓','李郢','唐','御定全唐诗','yuding','','[]','高樓上長望，百里見靈山。雨歇河珠定，雲開穀鳥還。',48,'御定全唐詩/json/590.json','["高樓上長望，百里見靈山。雨歇河珠定，雲開穀鳥還。", "田苗映林合，牛犢傍村閑。始得消憂處，蟬聲催入關。"]'),
('yuding-4','遊天柱觀','李郢','唐','御定全唐诗','yuding','','[]','聽鐘到靈觀，仙子喜相尋。茅洞幾千載，水聲寒至今。',48,'御定全唐詩/json/590.json','["聽鐘到靈觀，仙子喜相尋。茅洞幾千載，水聲寒至今。", "讀碑丹井上，坐石澗亭陰。清興未雲盡，煙霞生夕林。"]'),
('yuding-5','酬劉穀除夜見寄','李郢','唐','御定全唐诗','yuding','','[]','坐恐三更至，流年此夜分。客心無限事，愁雨不堪聞。',48,'御定全唐詩/json/590.json','["坐恐三更至，流年此夜分。客心無限事，愁雨不堪聞。", "灞上家殊遠，爐前酒暫醺。劉郎亦多恨，詩憶故山雲。"]'),
('yuding-6','元日作','李郢','唐','御定全唐诗','yuding','','[]','鏘鏘華駟客，門館賀新正。野雪江山霽，微風竹樹清。',48,'御定全唐詩/json/590.json','["鏘鏘華駟客，門館賀新正。野雪江山霽，微風竹樹清。", "蕪庭春意曉，殘枿燼煙生。忽憶王孫草，前年在帝京。"]'),
('yuding-7','酬劉谷立春日吏隱亭見寄','李郢','唐','御定全唐诗','yuding','','[]','孤亭遙帶寺，靜者獨登臨。楚霽江流慢，春歸澤氣陰。',48,'御定全唐詩/json/590.json','["孤亭遙帶寺，靜者獨登臨。楚霽江流慢，春歸澤氣陰。", "野田青牧馬，幽竹暖鳴禽。日日年光盡，何堪故國心。"]'),
('yuding-8','宿憐上人房','李郢','唐','御定全唐诗','yuding','','[]','重公舊相識，一夕話勞生。藥裹關身病，經函寄道情。',48,'御定全唐詩/json/590.json','["重公舊相識，一夕話勞生。藥裹關身病，經函寄道情。", "嶽寒當寺色，灘夜入樓聲。不待移文誚，三年別赤城。"]'),
('yuding-9','園居','李郢','唐','御定全唐诗','yuding','','[]','暮雨揚雄宅，秋風向秀園。不聞砧杵動，時看桔槔翻。',48,'御定全唐詩/json/590.json','["暮雨揚雄宅，秋風向秀園。不聞砧杵動，時看桔槔翻。", "釣下魚初食，船移鴨暫喧。橘寒才弄色，須帶早霜繁。"]'),
('yuding-10','中元夜','李郢','唐','御定全唐诗','yuding','','[]','江南水寺中元夜，金粟欄邊見月娥。紅燭影回仙態近，',40,'御定全唐詩/json/590.json','["江南水寺中元夜，金粟欄邊見月娥。紅燭影回仙態近，", "湘水夜空巫峽遠，不知歸路欲如何。"]'),
('yuding-11','贈羽林將軍','李郢','唐','御定全唐诗','yuding','','[]','虯須憔悴羽林郎，曾入甘泉侍武皇。雕沒夜雲知御苑，',40,'御定全唐詩/json/590.json','["虯須憔悴羽林郎，曾入甘泉侍武皇。雕沒夜雲知御苑，", "唯有桓伊江上笛，臥吹三弄送殘陽。"]'),
('yuding-12','送人之嶺南','李郢','唐','御定全唐诗','yuding','','[]','關山迢遞古交州，歲晏憐君走馬遊。謝氏海邊逢素女，',40,'御定全唐詩/json/590.json','["關山迢遞古交州，歲晏憐君走馬遊。謝氏海邊逢素女，", "回望長安五千里，刺桐花下莫淹留。"]'),
('yuding-13','晚泊松江驛','李郢','唐','御定全唐诗','yuding','','[]','片帆孤客晚夷猶，紅蓼花前水驛秋。歲月方驚離別盡，',40,'御定全唐詩/json/590.json','["片帆孤客晚夷猶，紅蓼花前水驛秋。歲月方驚離別盡，", "還有吳娃舊歌曲，棹聲遙散采菱舟。"]'),
('yuding-14','江亭春霽','李郢','唐','御定全唐诗','yuding','','[]','江蘺漠漠荇田田，江上雲亭霽景鮮。蜀客帆檣背歸燕，',40,'御定全唐詩/json/590.json','["江蘺漠漠荇田田，江上雲亭霽景鮮。蜀客帆檣背歸燕，", "金磬泠泠水南寺，上方僧室翠微連。"]'),
('yuding-15','早秋書懷','李郢','唐','御定全唐诗','yuding','','[]','高梧一葉墜涼天，宋玉悲秋淚灑然。霜拂楚山頻見菊，',40,'御定全唐詩/json/590.json','["高梧一葉墜涼天，宋玉悲秋淚灑然。霜拂楚山頻見菊，", "青鬢已緣多病鑷，可堪風景促流年。"]'),
('yuding-16','為妻作生日寄意','李郢','唐','御定全唐诗','yuding','','[]','謝家生日好風煙，柳暖花春二月天。金鳳對翹雙翡翠，',40,'御定全唐詩/json/590.json','["謝家生日好風煙，柳暖花春二月天。金鳳對翹雙翡翠，", "應恨客程歸未得，綠窗紅淚冷涓涓。"]'),
('yuding-17','重陽日寄浙東諸從事','李郢','唐','御定全唐诗','yuding','','[]','野人多病門長掩，荒圃重陽菊自開。愁裏又聞清笛怨，',40,'御定全唐詩/json/590.json','["野人多病門長掩，荒圃重陽菊自開。愁裏又聞清笛怨，", "紅旆紛紛碧江暮，知君醉下望鄉台。"]'),
('yuding-18','和湖州杜員外冬至日白蘋洲見憶','李郢','唐','御定全唐诗','yuding','','[]','白蘋亭上一陽生，謝脁新裁錦繡成。千嶂雪消溪影淥，',40,'御定全唐詩/json/590.json','["白蘋亭上一陽生，謝脁新裁錦繡成。千嶂雪消溪影淥，", "多愧龍門重招引，即拋田舍棹舟行。"]'),
('yuding-19','上裴晉公','李郢','唐','御定全唐诗','yuding','','[]','四朝憂國鬢如絲，龍馬精神海鶴姿。天上玉書傳詔夜，',40,'御定全唐詩/json/590.json','["四朝憂國鬢如絲，龍馬精神海鶴姿。天上玉書傳詔夜，", "惆悵舊堂扃綠野，夕陽無限鳥飛遲。"]'),
('yuding-20','錢塘青山題李隱居西齋','李郢','唐','御定全唐诗','yuding','','[]','小隱西齋為客開，翠蘿深處遍青苔。林間掃石安棋局，',40,'御定全唐詩/json/590.json','["小隱西齋為客開，翠蘿深處遍青苔。林間掃石安棋局，", "湖山繞屋猶嫌淺，欲棹漁舟近釣台。"]'),
('yuding-21','友人適越路過桐廬寄題江驛','李郢','唐','御定全唐诗','yuding','','[]','桐廬縣前洲渚平，桐廬江上晚潮生。莫言獨有山川秀，',40,'御定全唐詩/json/590.json','["桐廬縣前洲渚平，桐廬江上晚潮生。莫言獨有山川秀，", "王孫客棹殘春去，相送河橋羨此行。"]'),
('yuding-22','送劉谷','李郢','唐','御定全唐诗','yuding','','[]','村橋西路雪初晴，雲暖沙幹馬足輕。寒澗渡頭芳草色，',40,'御定全唐詩/json/590.json','["村橋西路雪初晴，雲暖沙幹馬足輕。寒澗渡頭芳草色，", "落日千峰轉迢遞，知君回首望高城。"]'),
('yuding-23','七夕','李郢','唐','御定全唐诗','yuding','','[]','烏鵲橋頭雙扇開，年年一度過河來，莫嫌天上稀相見，',40,'御定全唐詩/json/590.json','["烏鵲橋頭雙扇開，年年一度過河來，莫嫌天上稀相見，", "別時舊路長清淺，豈肯離情似死灰。"]'),
('yuding-24','秦處士移家富春發樟亭懷寄','李郢','唐','御定全唐诗','yuding','','[]','潮落空江洲渚生，知君已上富春亭。嘗聞郭邑山多秀，',40,'御定全唐詩/json/590.json','["潮落空江洲渚生，知君已上富春亭。嘗聞郭邑山多秀，", "仙翁白石高歌調，無複松齋半夜聽。"]'),
('yuding-25','故洛陽城','李郢','唐','御定全唐诗','yuding','','[]','胡兵一動朔方塵，不使鑾輿此重巡。清洛但流嗚咽水，',40,'御定全唐詩/json/590.json','["胡兵一動朔方塵，不使鑾輿此重巡。清洛但流嗚咽水，", "欲問升平無故老，鳳樓回首落花頻。"]'),
('yuding-26','紫極宮上元齋次呈諸道流','李郢','唐','御定全唐诗','yuding','','[]','碧簡朝天章奏頻，清宮仿佛降靈真。五龍金角向星斗，',40,'御定全唐詩/json/590.json','["碧簡朝天章奏頻，清宮仿佛降靈真。五龍金角向星斗，", "明朝醮罷羽客散，塵土滿城空世人。"]'),
('yuding-27','立春一日江村偶興','李郢','唐','御定全唐诗','yuding','','[]','舊曆年光看卷盡，立春何用更相催。江邊野店寒無色，',40,'御定全唐詩/json/590.json','["舊曆年光看卷盡，立春何用更相催。江邊野店寒無色，", "南州近有秦中使，聞道胡兵索戰來。"]'),
('yuding-28','立秋後自京歸家','李郢','唐','御定全唐诗','yuding','','[]','籬落秋歸見豆花，竹門當水岸橫槎。松齋一雨宜清簟，',40,'御定全唐詩/json/590.json','["籬落秋歸見豆花，竹門當水岸橫槎。松齋一雨宜清簟，", "西江近有鱸魚否，張翰扁舟始到家。"]'),
('yuding-29','奉陪裴相公重陽日游安樂池亭','李郢','唐','御定全唐诗','yuding','','[]','絳霄輕靄翊三台，稽阮襟懷管樂才。蓮沼昔為王儉府，',40,'御定全唐詩/json/590.json','["絳霄輕靄翊三台，稽阮襟懷管樂才。蓮沼昔為王儉府，", "自笑吐茵還酩酊，日斜空從絳衣回。"]'),
('yuding-30','浙河館','李郢','唐','御定全唐诗','yuding','','[]','雨濕菰蒲斜日明，茅廚煮繭掉車聲。青蛇上竹一種色，',40,'御定全唐詩/json/590.json','["雨濕菰蒲斜日明，茅廚煮繭掉車聲。青蛇上竹一種色，", "千峰萬瀨水潏潏，羸馬此中愁獨行。"]'),
('yuding-31','春日題山家','李郢','唐','御定全唐诗','yuding','','[]','偶與樵人熟，春殘日日來。依岡尋紫蕨，挽樹得青梅。',72,'御定全唐詩/json/590.json','["偶與樵人熟，春殘日日來。依岡尋紫蕨，挽樹得青梅。", "燕靜銜泥起，蜂喧抱蕊回。嫩茶重攪綠，新酒略炊醅。", "漠漠蠶生紙，涓涓水弄苔。丁香政堪結，留步小庭隈。"]'),
('yuding-32','江亭晚望','李郢','唐','御定全唐诗','yuding','','[]','碧天涼冷雁來疏，閑望江雲思有餘。秋館池亭荷葉後，',40,'御定全唐詩/json/590.json','["碧天涼冷雁來疏，閑望江雲思有餘。秋館池亭荷葉後，", "聞說故園香稻熟，片帆歸去就鱸魚。"]'),
('yuding-33','長安夜訪澈上人','李郢','唐','御定全唐诗','yuding','','[]','關西木落夜霜凝，烏帽閑尋紫閣僧。松迥月光先照鶴，',40,'御定全唐詩/json/590.json','["關西木落夜霜凝，烏帽閑尋紫閣僧。松迥月光先照鶴，", "聞說天臺舊禪處，石房獨有一龕燈。"]'),
('yuding-34','送圓鑒上人游天臺','李郢','唐','御定全唐诗','yuding','','[]','西嶺草堂留不住，獨攜瓶錫向天臺。霜清海寺聞潮至，',40,'御定全唐詩/json/590.json','["西嶺草堂留不住，獨攜瓶錫向天臺。霜清海寺聞潮至，", "靈溪道者相逢處，陰洞泠泠竹室開。"]'),
('yuding-35','送僧之台州','李郢','唐','御定全唐诗','yuding','','[]','獨尋台嶺閒遊去，豈覺靈溪道裏賒。三井應潮通海浪，',40,'御定全唐詩/json/590.json','["獨尋台嶺閒遊去，豈覺靈溪道裏賒。三井應潮通海浪，", "到日初尋石橋路，莫教雲雨濕袈裟。"]'),
('yuding-36','傷賈島無可','李郢','唐','御定全唐诗','yuding','','[]','卻到京師事事傷，惠休歸寂賈生亡。何人收得文章篋，',40,'御定全唐詩/json/590.json','["卻到京師事事傷，惠休歸寂賈生亡。何人收得文章篋，", "蕭蕭竹塢斜陽在，葉覆閑階雪擁牆。"]'),
('yuding-37','孔雀','李郢','唐','御定全唐诗','yuding','','[]','越鳥青春好顏色，晴軒入戶看呫衣。一身金翠畫不得，',40,'御定全唐詩/json/590.json','["越鳥青春好顏色，晴軒入戶看呫衣。一身金翠畫不得，", "刺桐花謝芳草歇，南國同巢應望歸。"]'),
('yuding-38','秋晚寄題陸勳校書義興禪居時淮南從事','李郢','唐','御定全唐诗','yuding','','[]','禪居秋草晚，蕭索異前時。蓮幕青雲貴，翱翔絕後期。',96,'御定全唐詩/json/590.json','["禪居秋草晚，蕭索異前時。蓮幕青雲貴，翱翔絕後期。", "蘚房檉架掩，山砌石盆欹。劍戟晨趨靜，笙歌夜散遲。", "穀寒霜狖靜，林晚磬蟲悲。惠遠煙霞在，方平杖履隨。", "骨清須貴達，神重有威儀。萬卒千蹄馬，橫鞭從信騎。"]'),
('yuding-39','酬王舍人雪中見寄','李郢','唐','御定全唐诗','yuding','','[]','三日柴門擁不開，階庭平滿白皚皚。',32,'御定全唐詩/json/590.json','["三日柴門擁不開，階庭平滿白皚皚。", "今朝踏作瓊瑤跡，為有詩從鳳沼來。"]'),
('yuding-40','蟬','李郢','唐','御定全唐诗','yuding','','[]','飲蟬驚雨落高槐，山蟻移將入石階。',32,'御定全唐詩/json/590.json','["飲蟬驚雨落高槐，山蟻移將入石階。", "若使秦樓美人見，還應一為拔金釵。"]'),
('yuding-41','自水口入茶山','李郢','唐','御定全唐诗','yuding','','[]','蒨蒨紅裙好女兒，相偎相倚看人時。',32,'御定全唐詩/json/590.json','["蒨蒨紅裙好女兒，相偎相倚看人時。", "使君馬上應含笑，橫把金鞭為詠詩。"]'),
('yuding-42','重游天臺','李郢','唐','御定全唐诗','yuding','','[]','南國天臺山水奇，石橋危險古來知。',32,'御定全唐詩/json/590.json','["南國天臺山水奇，石橋危險古來知。", "龍潭直下一百丈，誰見生公獨坐時。"]'),
('yuding-43','山行','李郢','唐','御定全唐诗','yuding','','[]','小田微雨稻苗香，田畔清溪潏潏涼。',32,'御定全唐詩/json/590.json','["小田微雨稻苗香，田畔清溪潏潏涼。", "自憶東吳榜舟日，蓼花溝水半篙強。"]'),
('yuding-44','上元日寄湖杭二從事','李郢','唐','御定全唐诗','yuding','','[]','戀別山燈憶水燈，山光水焰百千層。',32,'御定全唐詩/json/590.json','["戀別山燈憶水燈，山光水焰百千層。", "謝公留賞山公喚，知入笙歌阿那朋。"]'),
('yuding-45','寒食野望','李郢','唐','御定全唐诗','yuding','','[]','舊墳新隴哭多時，流世都堪幾度悲。',32,'御定全唐詩/json/590.json','["舊墳新隴哭多時，流世都堪幾度悲。", "烏鳥亂啼人未遠，野風吹散白棠梨。"]'),
('yuding-46','清明日題一公禪室','李郢','唐','御定全唐诗','yuding','','[]','山頭蘭若石楠春，山下清明煙火新。',32,'御定全唐詩/json/590.json','["山頭蘭若石楠春，山下清明煙火新。", "此日何窮禮禪客，歸心誰是戀禪人。"]'),
('yuding-47','七夕寄張氏兄弟','李郢','唐','御定全唐诗','yuding','','[]','新秋牛女會佳期，紅粉筵開玉饌時。',32,'御定全唐詩/json/590.json','["新秋牛女會佳期，紅粉筵開玉饌時。", "好與檀郎寄花朵，莫教清曉羨蛛絲。"]'),
('yuding-48','春晚與諸同舍出城迎座主侍郎','李郢','唐','御定全唐诗','yuding','','[]','三十驊騮一哄塵，來時不鎖杏園春。',32,'御定全唐詩/json/590.json','["三十驊騮一哄塵，來時不鎖杏園春。", "東風柳絮輕如雪，應有偷遊曲水人。"]'),
('yuding-49','張郎中宅戲贈二首','李郢','唐','御定全唐诗','yuding','','[]','薄雪燕蓊紫燕釵，釵垂簏簌抱香懷。',64,'御定全唐詩/json/590.json','["薄雪燕蓊紫燕釵，釵垂簏簌抱香懷。", "一聲歌罷劉郎醉，脫取明金壓繡鞋。", "謝家青妓邃重關，誰省春風見玉顏。", "聞道彩鸞三十六，一雙雙對碧池蓮。"]'),
('yuding-50','醉送','李郢','唐','御定全唐诗','yuding','','[]','江梅冷豔酒清光，急拍繁弦醉畫堂。',32,'御定全唐詩/json/590.json','["江梅冷豔酒清光，急拍繁弦醉畫堂。", "無限柳條多少雪，一將春恨付劉郎。"]'),
('yuding-51','曉井','李郢','唐','御定全唐诗','yuding','','[]','桐陰覆井月斜明，百尺寒泉古甃清。',32,'御定全唐詩/json/590.json','["桐陰覆井月斜明，百尺寒泉古甃清。", "越女攜瓶下金索，曉天初放轆轤聲。"]'),
('yuding-52','南池','李郢','唐','御定全唐诗','yuding','','[]','小男供餌婦搓絲，溢榼香醪倒接z5。日出兩竿魚正食，一家歡笑在南池。',33,'御定全唐詩/json/590.json','["小男供餌婦搓絲，溢榼香醪倒接z5。日出兩竿魚正食，一家歡笑在南池。"]'),
('yuding-53','偶作','李郢','唐','御定全唐诗','yuding','','[]','一杯正發吟哦興，兩盞還生去住愁。',32,'御定全唐詩/json/590.json','["一杯正發吟哦興，兩盞還生去住愁。", "何似全家上船去，酒旗多處即淹留。"]'),
('yuding-54','畫鼓','李郢','唐','御定全唐诗','yuding','','[]','嘗聞畫鼓動歡情，及送離人恨鼓聲。',32,'御定全唐詩/json/590.json','["嘗聞畫鼓動歡情，及送離人恨鼓聲。", "兩杖一揮行纜解，暮天空使別魂驚。"]'),
('yuding-55','燕蓊花','李郢','唐','御定全唐诗','yuding','','[]','十二街中何限草，燕蓊盡欲占殘春。',32,'御定全唐詩/json/590.json','["十二街中何限草，燕蓊盡欲占殘春。", "黃花撲地無窮極，愁殺江南去住人。"]'),
('yuding-56','邵博士溪亭','李郢','唐','御定全唐诗','yuding','','[]','野茶無限春風葉，溪水千重返照波。',32,'御定全唐詩/json/590.json','["野茶無限春風葉，溪水千重返照波。", "只去長橋三十裏，誰人一解枉帆過。"]'),
('yuding-57','小石上見亡友題處','李郢','唐','御定全唐诗','yuding','','[]','筍石清琤入紫煙，陸雲題處是前年。',32,'御定全唐詩/json/590.json','["筍石清琤入紫煙，陸雲題處是前年。", "苔侵雨打依稀在，惆悵涼風樹樹蟬。"]'),
('yuding-58','洞靈觀流泉','李郢','唐','御定全唐诗','yuding','','[]','石上苔蕪水上煙，潺湲聲在觀門前。',32,'御定全唐詩/json/590.json','["石上苔蕪水上煙，潺湲聲在觀門前。", "千岩萬壑分流去，更引飛花入洞天。"]'),
('yuding-59','送李判官','李郢','唐','御定全唐诗','yuding','','[]','津市停橈送別難，熒熒蠟炬照更闌。',32,'御定全唐詩/json/590.json','["津市停橈送別難，熒熒蠟炬照更闌。", "東風萬疊吹江月，誰伴袁褒宿夜灘。"]'),
('yuding-60','宿杭州虛白堂','李郢','唐','御定全唐诗','yuding','','[]','秋月斜明虛白堂，寒蛩唧唧樹蒼蒼。',32,'御定全唐詩/json/590.json','["秋月斜明虛白堂，寒蛩唧唧樹蒼蒼。", "江風徹曉不得睡，二十五聲秋點長。"]'),
('yuding-0','道林寺','崔玨','唐','御定全唐诗','yuding','','[]','臨湘之濱麓之隅，西有松寺東岸無。松風千里擺不斷，',144,'御定全唐詩/json/591.json','["臨湘之濱麓之隅，西有松寺東岸無。松風千里擺不斷，", "四時唯夏不敢入，燭龍安敢停斯須？遠公池上種何物，", "野花市井栽不著，山雞飲啄聲相呼。金檻僧回步步影，", "遙江大船小於葉，遠村雜樹齊如蔬。潭州城郭在何處，", "長卿之門久寂寞，五言七字誇規模。我吟杜詩清入骨，", "明珠大貝采欲盡，蚌蛤空滿赤沙湖。今我題詩亦無味，"]'),
('yuding-1','美人嘗茶行','崔玨','唐','御定全唐诗','yuding','','[]','雲鬟枕落困春泥，玉郎為碾瑟瑟塵。閑教鸚鵡啄窗響，',48,'御定全唐詩/json/591.json','["雲鬟枕落困春泥，玉郎為碾瑟瑟塵。閑教鸚鵡啄窗響，", "朱唇啜破綠雲時，咽入香喉爽紅玉。明眸漸開橫秋水，"]'),
('yuding-2','門前柳','崔玨','唐','御定全唐诗','yuding','','[]','門前蜀柳□知春，風淡暖煙愁殺人。將謂只栽郡樓下，',118,'御定全唐詩/json/591.json','["門前蜀柳□知春，風淡暖煙愁殺人。將謂只栽郡樓下，", "夷陬蠻落相連接，故鄉莫道心先死。我今帝裏尚有家，", "別來三載當誰道，門前年年綠陰好。春來定解飛雪花，", "如今宛轉稊著地，常向綠陰勞夢思。不道彼樹好，", "為報門前楊柳栽，我應來歲當歸來。縱令樹下能攀折，"]'),
('yuding-3','岳陽樓晚望','崔玨','唐','御定全唐诗','yuding','','[]','乾坤千里水雲間，釣艇如萍去複還。樓上北風斜卷席，',40,'御定全唐詩/json/591.json','["乾坤千里水雲間，釣艇如萍去複還。樓上北風斜卷席，", "何事黃昏尚凝睇，數行煙樹接荊蠻。"]'),
('yuding-4','哭李商隱','崔玨','唐','御定全唐诗','yuding','','[]','成紀星郎字義山，適歸高壤抱長歎。詞林枝葉三春盡，',80,'御定全唐詩/json/591.json','["成紀星郎字義山，適歸高壤抱長歎。詞林枝葉三春盡，", "只應物外攀琪樹，便著霓裳上絳壇。", "虛負淩雲萬丈才，一生襟抱未曾開。鳥啼花落人何在，", "九泉莫歎三光隔，又送文星入夜台。"]'),
('yuding-5','和友人鴛鴦之什','崔玨','唐','御定全唐诗','yuding','','[]','翠鬣紅衣舞夕暉，水禽情似此禽稀。暫分煙島猶回首，',120,'御定全唐詩/json/591.json','["翠鬣紅衣舞夕暉，水禽情似此禽稀。暫分煙島猶回首，", "採蓮無限蘭橈女，笑指中流羨爾歸。", "寂寂春塘煙晚時，兩心和影共依依。溪頭日暖眠沙穩，", "蘭深芷密無人見，相逐相呼何處歸。", "舞鶴翔鸞俱別離，可憐生死兩相隨。紅絲毳落眠汀處，", "何如相見長相對，肯羨人間多所思。"]'),
('yuding-6','有贈','崔玨','唐','御定全唐诗','yuding','','[]','莫道妝成斷客腸，粉胸綿手白蓮香。煙分頂上三層綠，',80,'御定全唐詩/json/591.json','["莫道妝成斷客腸，粉胸綿手白蓮香。煙分頂上三層綠，", "雖然不似王孫女，解愛臨邛賣賦郎。", "錦裏芬芳少佩蘭，風流全占似君難。心迷曉夢窗猶暗，", "自嗟此地非吾土，不得如花歲歲看。"]'),
('yuding-7','和人聽歌','崔玨','唐','御定全唐诗','yuding','','[]','氣吐幽蘭出洞房，樂人先問調宮商。聲和細管珠才轉，',80,'御定全唐詩/json/591.json','["氣吐幽蘭出洞房，樂人先問調宮商。聲和細管珠才轉，", "巫山唱罷行雲過，猶自微塵舞畫梁。", "紅臉初分翠黛愁，錦筵歌板拍清秋。一樓春雪和塵落，", "莫辭更送劉郎酒，百斛明珠異日酬。"]'),
('yuding-8','水晶枕','崔玨','唐','御定全唐诗','yuding','','[]','千年積雪萬年冰，掌上初擎力不勝。南國舊知何處得，',40,'御定全唐詩/json/591.json','["千年積雪萬年冰，掌上初擎力不勝。南國舊知何處得，", "蘄簟蜀琴相對好，裁詩乞與滌煩襟。"]'),
('yuding-9','席間詠琴客','崔玨','唐','御定全唐诗','yuding','','[]','七條弦上五音寒，此藝知音自古難。',32,'御定全唐詩/json/591.json','["七條弦上五音寒，此藝知音自古難。", "唯有河南房次律，始終憐得董庭蘭。"]'),
('yuding-10','句','崔玨','唐','御定全唐诗','yuding','','[]','楚王宮地羅含宅，賴許時時聽法來。（早梅贈李商隱。',32,'御定全唐詩/json/591.json','["楚王宮地羅含宅，賴許時時聽法來。（早梅贈李商隱。", "見《商隱集注》）"]'),
('yuding-0','徒相逢','曹鄴','唐','御定全唐诗','yuding','','[]','江邊野花不須采，梁頭野燕不用親。',32,'御定全唐詩/json/592.json','["江邊野花不須采，梁頭野燕不用親。", "西施本是越溪女，承恩不薦越溪人。"]'),
('yuding-1','雜誡','曹鄴','唐','御定全唐诗','yuding','','[]','帶香入鮑肆，香氣同鮑魚。未入猶可悟，已入當何如。',24,'御定全唐詩/json/592.json','["帶香入鮑肆，香氣同鮑魚。未入猶可悟，已入當何如。"]'),
('yuding-2','捕漁謠','曹鄴','唐','御定全唐诗','yuding','','[]','天子好征戰，百姓不種桑。天子好年少，無人薦馮唐。',36,'御定全唐詩/json/592.json','["天子好征戰，百姓不種桑。天子好年少，無人薦馮唐。", "天子好美女，夫婦不成雙。"]'),
('yuding-3','四怨三愁五情詩十二首：一怨','曹鄴','唐','御定全唐诗','yuding','','[]','美人如新花，許嫁還獨守。豈無青銅鏡，終日自疑醜。',24,'御定全唐詩/json/592.json','["美人如新花，許嫁還獨守。豈無青銅鏡，終日自疑醜。"]'),
('yuding-4','四怨三愁五情詩十二首：二怨','曹鄴','唐','御定全唐诗','yuding','','[]','庭花已結子，岩花猶弄色。誰令生處遠，用盡春風力。',24,'御定全唐詩/json/592.json','["庭花已結子，岩花猶弄色。誰令生處遠，用盡春風力。"]'),
('yuding-5','四怨三愁五情詩十二首：三怨','曹鄴','唐','御定全唐诗','yuding','','[]','短鬟一如螓，長眉一如蛾。相共棹蓮舟，得花不如他。',24,'御定全唐詩/json/592.json','["短鬟一如螓，長眉一如蛾。相共棹蓮舟，得花不如他。"]'),
('yuding-6','四怨三愁五情詩十二首：四怨','曹鄴','唐','御定全唐诗','yuding','','[]','手推嘔啞車，朝朝暮暮耕。未曾分得谷，空得老農名。',24,'御定全唐詩/json/592.json','["手推嘔啞車，朝朝暮暮耕。未曾分得谷，空得老農名。"]'),
('yuding-7','四怨三愁五情詩十二首：一愁','曹鄴','唐','御定全唐诗','yuding','','[]','遠夢如水急，白髮如草新。歸期待春至，春至還送人。',24,'御定全唐詩/json/592.json','["遠夢如水急，白髮如草新。歸期待春至，春至還送人。"]'),
('yuding-8','四怨三愁五情詩十二首：二愁','曹鄴','唐','御定全唐诗','yuding','','[]','澗草短短青，山月朗朗明。此夜目不掩，屋頭烏啼聲。',24,'御定全唐詩/json/592.json','["澗草短短青，山月朗朗明。此夜目不掩，屋頭烏啼聲。"]'),
('yuding-9','四怨三愁五情詩十二首：三愁','曹鄴','唐','御定全唐诗','yuding','','[]','別家鬢未生，到城鬢似發。朝朝臨川望，灞水不入越。',24,'御定全唐詩/json/592.json','["別家鬢未生，到城鬢似發。朝朝臨川望，灞水不入越。"]'),
('yuding-10','四怨三愁五情詩十二首：一情','曹鄴','唐','御定全唐诗','yuding','','[]','東西是長江，南北是官道。牛羊不戀山，只戀山中草。',24,'御定全唐詩/json/592.json','["東西是長江，南北是官道。牛羊不戀山，只戀山中草。"]'),
('yuding-11','四怨三愁五情詩十二首：二情','曹鄴','唐','御定全唐诗','yuding','','[]','阿嬌生漢宮，西施住南國。專房莫相妒，各自有顏色。',24,'御定全唐詩/json/592.json','["阿嬌生漢宮，西施住南國。專房莫相妒，各自有顏色。"]'),
('yuding-12','四怨三愁五情詩十二首：三情','曹鄴','唐','御定全唐诗','yuding','','[]','蛺蝶空中飛，夭桃庭中春。見他夫婦好，有女初嫁人。',24,'御定全唐詩/json/592.json','["蛺蝶空中飛，夭桃庭中春。見他夫婦好，有女初嫁人。"]'),
('yuding-13','四怨三愁五情詩十二首：四情','曹鄴','唐','御定全唐诗','yuding','','[]','檳榔自無柯，椰葉自無陰。常羨庭邊竹，生筍高於林。',24,'御定全唐詩/json/592.json','["檳榔自無柯，椰葉自無陰。常羨庭邊竹，生筍高於林。"]'),
('yuding-14','四怨三愁五情詩十二首：五情','曹鄴','唐','御定全唐诗','yuding','','[]','野雀空城饑，交交複飛飛。勿怪官倉粟，官倉無空時。',24,'御定全唐詩/json/592.json','["野雀空城饑，交交複飛飛。勿怪官倉粟，官倉無空時。"]'),
('yuding-15','寄劉駕','曹鄴','唐','御定全唐诗','yuding','','[]','一川草色青嫋嫋，繞屋水聲如在家。',32,'御定全唐詩/json/592.json','["一川草色青嫋嫋，繞屋水聲如在家。", "悵望美人不攜手，牆東又發數枝花。"]'),
('yuding-16','風人體','曹鄴','唐','御定全唐诗','yuding','','[]','出門行一步，形影便相失。何況大堤上，驄馬如箭疾。',72,'御定全唐詩/json/592.json','["出門行一步，形影便相失。何況大堤上，驄馬如箭疾。", "夜夜如織婦，尋思待成匹。郎只不在家，在家亦如出。", "將金與蔔人，譎道遠行吉。念郎緣底事，不具天與日。"]'),
('yuding-17','杏園即席上同年','曹鄴','唐','御定全唐诗','yuding','','[]','岐路不在天，十年行不至。一旦公道開，青雲在平地。',120,'御定全唐詩/json/592.json','["岐路不在天，十年行不至。一旦公道開，青雲在平地。", "枕上數聲鼓，衡門已如市。白日探得珠，不待驪龍睡。", "匆匆出九衢，僮僕顏色異。故衣未及換，尚有去年淚。", "晴陽照花影，落絮浮野翠。對酒時忽驚，猶疑夢中事。", "自憐孤飛鳥，得接鸞鳳翅。永懷共濟心，莫起胡越意。"]'),
('yuding-18','恃寵','曹鄴','唐','御定全唐诗','yuding','','[]','二月樹色好，昭儀正驕奢。恐君愛陽豔，斫卻園中花。',84,'御定全唐詩/json/592.json','["二月樹色好，昭儀正驕奢。恐君愛陽豔，斫卻園中花。", "三十六宮女，髻鬟各如鴉。君王心所憐，獨自不見瑕。", "臺上紅燈盡，未肯下金車。一笑不得所，塵中悉無家。", "飛燕身更輕，何必恃容華。"]'),
('yuding-19','題女郎廟','曹鄴','唐','御定全唐诗','yuding','','[]','數點煙香出廟門，女娥飛去影中存。',32,'御定全唐詩/json/592.json','["數點煙香出廟門，女娥飛去影中存。", "年年嶺上春無主，露泣花愁斷客魂。"]'),
('yuding-20','四望樓','曹鄴','唐','御定全唐诗','yuding','','[]','背山見樓影，應合與山齊。座上日已出，城中未鳴雞。',60,'御定全唐詩/json/592.json','["背山見樓影，應合與山齊。座上日已出，城中未鳴雞。", "無限燕趙女，吹笙上金梯。風起洛陽東，香過洛陽西。", "公子長夜醉，不聞子規啼。"]'),
('yuding-21','築城三首','曹鄴','唐','御定全唐诗','yuding','','[]','郎有蘼蕪心，妾有芙蓉質。不辭嫁與郎，築城無休日。',72,'御定全唐詩/json/592.json','["郎有蘼蕪心，妾有芙蓉質。不辭嫁與郎，築城無休日。", "嗚嗚啄人鴉，軋軋上城車。力盡土不盡，得歸亦無家。", "築人非築城，圍秦豈圍我。不知城上土，化作宮中火。"]'),
('yuding-22','奉命齊州推事畢寄本府尚書','曹鄴','唐','御定全唐诗','yuding','','[]','越鳥棲不定，孤飛入齊鄉。日暮天欲雨，那兼羽翎傷。',241,'御定全唐詩/json/592.json','["越鳥棲不定，孤飛入齊鄉。日暮天欲雨，那兼羽翎傷。", "州民言刺史，蠹物甚於蝗。受命大執法，草草是行裝。", "僕隸皆分散，單車驛路長。四顧無相識，賓士若投荒。", "重門下長鎖，樹影空過牆。驅囚繞廊屋，bb々如牛羊。", "獄吏相對語，簿書堆滿床。敲枷打鎖聲，終日在目旁。", "既舍三山侶，來餘五鬥糧。忍學空城雀，潛身入官倉。", "國中天子令，頭上白日光。曲木用處多，不如直為梁。", "恐孤食恩地，晝夜心不遑。仲夏天氣熱，鬢須忽成霜。", "社鼠不可灌，城狐不易防。偶於擒縱間，盡得見否臧。", "截斷奸吏舌，擘開冤人腸。明朝向西望，走馬歸汶陽。"]'),
('yuding-23','北郭閑思','曹鄴','唐','御定全唐诗','yuding','','[]','山前山后是青草，盡日出門還掩門。',32,'御定全唐詩/json/592.json','["山前山后是青草，盡日出門還掩門。", "每思骨肉在天畔，來看野翁憐子孫。"]'),
('yuding-24','戰城南','曹鄴','唐','御定全唐诗','yuding','','[]','千金畫陣圖，自為弓劍苦。殺盡田野人，將軍猶愛武。',48,'御定全唐詩/json/592.json','["千金畫陣圖，自為弓劍苦。殺盡田野人，將軍猶愛武。", "性命換他恩，功成誰作主。鳳凰樓上人，夜夜長歌舞。"]'),
('yuding-25','自退','曹鄴','唐','御定全唐诗','yuding','','[]','寒女面如花，空寂常對影。況我不嫁容，甘為瓶墮井。',24,'御定全唐詩/json/592.json','["寒女面如花，空寂常對影。況我不嫁容，甘為瓶墮井。"]'),
('yuding-26','早起','曹鄴','唐','御定全唐诗','yuding','','[]','月墮滄浪西，門開樹無影。此時歸夢闌，立在梧桐井。',24,'御定全唐詩/json/592.json','["月墮滄浪西，門開樹無影。此時歸夢闌，立在梧桐井。"]'),
('yuding-27','古相送','曹鄴','唐','御定全唐诗','yuding','','[]','行人卜去期，白髮根已出。執君青松枝，空數別來日。',60,'御定全唐詩/json/592.json','["行人卜去期，白髮根已出。執君青松枝，空數別來日。", "心如七夕女，生死難再匹。且願車聲迫，莫使馬行疾。", "巫山千丈高，亦恐夢相失。"]'),
('yuding-28','甲第','曹鄴','唐','御定全唐诗','yuding','','[]','遊人未入門，花影出門前。將軍來此住，十裏無荒田。',24,'御定全唐詩/json/592.json','["遊人未入門，花影出門前。將軍來此住，十裏無荒田。"]'),
('yuding-29','望不來','曹鄴','唐','御定全唐诗','yuding','','[]','見花憶郎面，常願花色新。為郎容貌好，難有相似人。',24,'御定全唐詩/json/592.json','["見花憶郎面，常願花色新。為郎容貌好，難有相似人。"]'),
('yuding-30','官倉鼠','曹鄴','唐','御定全唐诗','yuding','','[]','官倉老鼠大如鬥，見人開倉亦不走。',32,'御定全唐詩/json/592.json','["官倉老鼠大如鬥，見人開倉亦不走。", "健兒無糧百姓饑，誰遣朝朝入君口。"]'),
('yuding-31','題濮廟','曹鄴','唐','御定全唐诗','yuding','','[]','曉祭瑤齋夜扣鐘，鼇頭風起浪重重。人間直有仙桃種，',40,'御定全唐詩/json/592.json','["曉祭瑤齋夜扣鐘，鼇頭風起浪重重。人間直有仙桃種，", "不知皇帝三宮駐，始向人間著袞龍。"]'),
('yuding-32','偶題','曹鄴','唐','御定全唐诗','yuding','','[]','白玉先生多在市，青牛道士不居山。',32,'御定全唐詩/json/592.json','["白玉先生多在市，青牛道士不居山。", "但能共得丹田語，正是忙時身亦閑。"]'),
('yuding-33','登岳陽樓有懷寄座主相公','曹鄴','唐','御定全唐诗','yuding','','[]','南登岳陽樓，北眺長安道。不見升平裏，千山樹如草。',72,'御定全唐詩/json/592.json','["南登岳陽樓，北眺長安道。不見升平裏，千山樹如草。", "骨肉在南楚，沈憂起常早。白社愁成空，秋蕪待誰掃。", "常聞詩人語，西子不宜老。賴識丹元君，時來語蓬島。"]'),
('yuding-34','出關','曹鄴','唐','御定全唐诗','yuding','','[]','山上黃犢走避人，山下女郎歌滿野。',32,'御定全唐詩/json/592.json','["山上黃犢走避人，山下女郎歌滿野。", "我獨南征恨此身，更有無成出關者。"]'),
('yuding-35','將赴天平職書懷寄翰林從兄','曹鄴','唐','御定全唐诗','yuding','','[]','居處絕人事，門前雀羅施。誰遣辟書至，僕隸皆展眉。',156,'御定全唐詩/json/592.json','["居處絕人事，門前雀羅施。誰遣辟書至，僕隸皆展眉。", "匹馬渡河洛，西風飄路岐。手執王粲筆，閑吟向旌旗。", "香晚翠蓮動，吟餘紅燭移。開口啖酒肉，將何報相知。", "況我魏公子，相顧不相疑。豈學官倉鼠，飽食無所為。", "白露沾碧草，芙蓉落清池。自小不到處，全家忽如歸。", "吾宗處清切，立在白玉墀。方得一侍座，單車又星飛。", "願將門底水，永托萬頃陂。"]'),
('yuding-36','賀雪寄本府尚書','曹鄴','唐','御定全唐诗','yuding','','[]','雨雪不順時，陰陽失明晦。麥根半成土，農夫泣相對。',96,'御定全唐詩/json/592.json','["雨雪不順時，陰陽失明晦。麥根半成土，農夫泣相對。", "我公誠訴天，天地忽已泰。長飆卷白雲，散落群峰外。", "拂砌花影明，交宮鶴翎碎。宿鳥晨不飛，猶疑月光在。", "碧樹香盡發，蠹蟲聲漸退。有客懷兔園，吟詩繞城內。"]'),
('yuding-37','寄嵩陽道人','曹鄴','唐','御定全唐诗','yuding','','[]','三山浮海倚蓬瀛，路入真元險盡平。華表千年孤鶴語，',40,'御定全唐詩/json/592.json','["三山浮海倚蓬瀛，路入真元險盡平。華表千年孤鶴語，", "見說嵩陽有仙客，欲持金簡問長生。"]'),
('yuding-38','去不返','曹鄴','唐','御定全唐诗','yuding','','[]','寒女不自知，嫁為公子妻。親情未識面，明日便東西。',84,'御定全唐詩/json/592.json','["寒女不自知，嫁為公子妻。親情未識面，明日便東西。", "但得上馬了，一去頭不回。雙輪如鳥飛，影盡東南街。", "九重十二門，一門四扇開。君從此路去，妾向此路啼。", "但得見君面，不辭插荊釵。"]'),
('yuding-39','送進士下第歸南海','曹鄴','唐','御定全唐诗','yuding','','[]','數片紅霞映夕陽，攬君衣袂更移觴。行人莫歎碧雲晚，',40,'御定全唐詩/json/592.json','["數片紅霞映夕陽，攬君衣袂更移觴。行人莫歎碧雲晚，", "應無惆悵滄波遠，十二玉樓非我鄉。"]'),
('yuding-40','送厲圖南下第歸澧州','曹鄴','唐','御定全唐诗','yuding','','[]','當春人盡歸，我獨無歸計。送君自多感，不是緣下第。',108,'御定全唐詩/json/592.json','["當春人盡歸，我獨無歸計。送君自多感，不是緣下第。", "君看山上草，盡有幹雲勢。結根既不然，何必更掩袂。", "澧水鱸魚賤，荊門楊柳細。勿為陽豔留，此處有月桂。", "言畢尊未幹，十二門欲閉。佇立望不見，登高更流涕。", "吟君別我詩，悵望水煙際。"]'),
('yuding-41','思不見','曹鄴','唐','御定全唐诗','yuding','','[]','但見出門蹤，不見入門跡。卻笑山頭女，無端化為石。',24,'御定全唐詩/json/592.json','["但見出門蹤，不見入門跡。卻笑山頭女，無端化為石。"]'),
('yuding-42','貴宅','曹鄴','唐','御定全唐诗','yuding','','[]','入門又到門，到門戟相對。玉簫聲尚遠，疑似人不在。',72,'御定全唐詩/json/592.json','["入門又到門，到門戟相對。玉簫聲尚遠，疑似人不在。", "公子厭花繁，買藥栽庭內。望遠不上樓，窗中見天外。", "此地日烹羊，無異我食菜。自是愁人眼，見之若奢泰。"]'),
('yuding-43','下第寄知己','曹鄴','唐','御定全唐诗','yuding','','[]','長安孟春至，枯樹花亦發。憂人此時心，冷若松上雪。',192,'御定全唐詩/json/592.json','["長安孟春至，枯樹花亦發。憂人此時心，冷若松上雪。", "自知才不堪，豈敢頻泣血。所痛無罪者，明時屢遭刖。", "故山秋草多，一卷成古轍。夜來遠心起，夢見瀟湘月。", "大賢冠蓋高，何事憐屑屑。不令傷弓鳥，日暮飛向越。", "聞知感激語，胸中如有物。舉頭望青天，白日頭上沒。", "歸來通濟裏，開戶山鼠出。中庭廣寂寥，但見薇與蕨。", "無慮數尺軀，委作泉下骨。唯愁攬清鏡，不見昨日發。", "願憐閨中女，晚嫁唯守節。勿惜四座言，女巧難自說。"]'),
('yuding-44','吳宮宴','曹鄴','唐','御定全唐诗','yuding','','[]','吳宮城闕高，龍鳳遙相倚。四面鏗鼓鐘，中央列羅綺。',72,'御定全唐詩/json/592.json','["吳宮城闕高，龍鳳遙相倚。四面鏗鼓鐘，中央列羅綺。", "春風時一來，蘭麝聞數裏。三度明月落，青娥醉不起。", "江頭鐵劍鳴，玉座成荒壘。適來歌舞處，未知身是鬼。"]'),
('yuding-45','長相思','曹鄴','唐','御定全唐诗','yuding','','[]','翦妾身上巾，贈郎傷妾神。郎車不暫停，妾貌甯長春。',48,'御定全唐詩/json/592.json','["翦妾身上巾，贈郎傷妾神。郎車不暫停，妾貌甯長春。", "春天無停雪，滄海無停津。遣妾空床夢，夜夜隨車輪。"]'),
('yuding-46','長城下','曹鄴','唐','御定全唐诗','yuding','','[]','遠水猶歸壑，征人合憶鄉。泣多盈袖血，吟苦滿頭霜。',48,'御定全唐詩/json/592.json','["遠水猶歸壑，征人合憶鄉。泣多盈袖血，吟苦滿頭霜。", "楚國連天浪，衡門到海荒。何當生燕羽，時得近雕梁。"]'),
('yuding-47','成名後獻恩門','曹鄴','唐','御定全唐诗','yuding','','[]','為物稍有香，心遭蠹蟲齧。平人登太行，萬萬車輪折。',192,'御定全唐詩/json/592.json','["為物稍有香，心遭蠹蟲齧。平人登太行，萬萬車輪折。", "一辭桂嶺猿，九泣東門月。年年孟春時，看花不如雪。", "僻居城南隅，顏子須泣血。沉埋若九泉，誰肯開口說。", "辛勤學機杼，坐對秋燈滅。織錦花不常，見之盡雲拙。", "自憐孤生竹，出土便有節。每聽浮競言，喉中似無舌。", "忽然風雷至，驚起池中物。拔上青雲巔，輕如一毫髮。", "瓏瓏金鎖甲，稍稍城烏絕。名字如鳥飛，數日便到越。", "幽蘭生雖晚，幽香亦難歇。何以保此身，終身事無缺。"]'),
('yuding-48','贈道師','曹鄴','唐','御定全唐诗','yuding','','[]','舉世皆問人，唯師獨求己。一馬無四蹄，頃刻行千里。',36,'御定全唐詩/json/592.json','["舉世皆問人，唯師獨求己。一馬無四蹄，頃刻行千里。", "應笑北原上，丘墳亂如蟻。"]'),
('yuding-49','入關','曹鄴','唐','御定全唐诗','yuding','','[]','衡門亦無路，何況入西秦。灸病不得穴，徒為采艾人。',24,'御定全唐詩/json/592.json','["衡門亦無路，何況入西秦。灸病不得穴，徒為采艾人。"]'),
('yuding-50','聽劉尊師彈琴','曹鄴','唐','御定全唐诗','yuding','','[]','曾於清海獨聞蟬，又向空庭夜聽泉。',32,'御定全唐詩/json/592.json','["曾於清海獨聞蟬，又向空庭夜聽泉。", "不似齋堂人靜處，秋聲長在七條弦。"]'),
('yuding-51','題山居','曹鄴','唐','御定全唐诗','yuding','','[]','掃葉煎茶摘葉書，心閑無夢夜窗虛。',32,'御定全唐詩/json/592.json','["掃葉煎茶摘葉書，心閑無夢夜窗虛。", "只應光武恩波晚，豈是嚴君戀釣魚。"]'),
('yuding-52','關試前送進士姚潛下第歸南陽','曹鄴','唐','御定全唐诗','yuding','','[]','馬嘶殘日沒殘霞，二月東風便到家。',32,'御定全唐詩/json/592.json','["馬嘶殘日沒殘霞，二月東風便到家。", "莫羨長安占春者，明年始見故園花。"]'),
('yuding-53','滻川寄進士劉駕','曹鄴','唐','御定全唐诗','yuding','','[]','我家不背水，君身不向越。自是相憶苦，忽如經年別。',48,'御定全唐詩/json/592.json','["我家不背水，君身不向越。自是相憶苦，忽如經年別。", "山家草木寒，石上有殘雪。美人望不見，迢迢雲中月。"]'),
('yuding-54','翠孤至渚宮寄座主相公','曹鄴','唐','御定全唐诗','yuding','','[]','萬里一孤舟，春行夏方到。骨肉盡單羸，沉憂滿懷抱。',192,'御定全唐詩/json/592.json','["萬里一孤舟，春行夏方到。骨肉盡單羸，沉憂滿懷抱。", "羈孤相對泣，性命不相保。開戶山鼠驚，蟲聲亂秋草。", "白菌緣屋生，黃蒿擁籬倒。對此起長嗟，芳年亦須老。", "恩門為宰相，出入用天道。忽於摧落間，收得青松操。", "全家到江陵，屋虛風浩浩。中腸自相伐，日夕如寇盜。", "其下有孤侄，其上有孀嫂。黃糧賤於土，一飯常不飽。", "天斜日光薄，地濕蟲叫噪。惟恐道忽消，形容益枯槁。", "古人于黃雀，豈望白環報。奉答恩地恩，何慚以誠告。"]'),
('yuding-55','早秋宿田舍','曹鄴','唐','御定全唐诗','yuding','','[]','澗草疏疏螢火光，山月朗朗楓樹長。',32,'御定全唐詩/json/592.json','["澗草疏疏螢火光，山月朗朗楓樹長。", "南村犢子夜聲急，應是欄邊新有霜。"]'),
('yuding-56','旅次岳陽寄京中親故','曹鄴','唐','御定全唐诗','yuding','','[]','君山南面浪連天，一客愁心兩處懸。身逐片帆歸楚澤，',40,'御定全唐詩/json/592.json','["君山南面浪連天，一客愁心兩處懸。身逐片帆歸楚澤，", "更欲登樓向西望，北風催上洞庭船。"]'),
('yuding-57','題舒鄉','曹鄴','唐','御定全唐诗','yuding','','[]','功名若及鴟夷子，必擬將舟泛洞庭。',32,'御定全唐詩/json/592.json','["功名若及鴟夷子，必擬將舟泛洞庭。", "柳色湖光好相待，我心非醉亦非醒。"]'),
('yuding-58','碧尋宴上有懷知己','曹鄴','唐','御定全唐诗','yuding','','[]','荻花蘆葉滿溪流，一簇笙歌在水樓。金管曲長人盡醉，',40,'御定全唐詩/json/592.json','["荻花蘆葉滿溪流，一簇笙歌在水樓。金管曲長人盡醉，", "莫怪當歡卻惆悵，全家欲上五湖舟。"]'),
('yuding-59','從天平節度使游平流園','曹鄴','唐','御定全唐诗','yuding','','[]','池塘靜於寺，俗事不到眼。下馬如在山，令人忽疏散。',120,'御定全唐詩/json/592.json','["池塘靜於寺，俗事不到眼。下馬如在山，令人忽疏散。", "明公有高思，到此遂長返。乘興挈一壺，折荷以為盞。", "入竹藤似蛇，侵牆水成蘚。幽鳥不識人，時來拂冠冕。", "沿流路若窮，及行路猶遠。洞中已雲夕，洞口天未晚。", "自憐不羈者，寫物心常簡。翻愁此興多，引得嵇康懶。"]'),
('yuding-60','故人寄茶','曹鄴','唐','御定全唐诗','yuding','','[]','劍外九華英，緘題下玉京。開時微月上，碾處亂泉聲。',72,'御定全唐詩/json/592.json','["劍外九華英，緘題下玉京。開時微月上，碾處亂泉聲。", "半夜招僧至，孤吟對月烹。碧沈霞腳碎，香泛乳花輕。", "六腑睡神去，數朝詩思清。月餘不敢費，留伴肘書行。"]'),
('yuding-0','東武吟','曹鄴','唐','御定全唐诗','yuding','','[]','心如山上虎，身若倉中鼠。惆悵倚市門，無人與之語。',60,'御定全唐詩/json/593.json','["心如山上虎，身若倉中鼠。惆悵倚市門，無人與之語。", "夜宴李將軍，欲望心相許。何曾聽我言，貪謔邯鄲女。", "獨上黃金台，淒涼淚如雨。"]'),
('yuding-1','薊北門行','曹鄴','唐','御定全唐诗','yuding','','[]','長河凍如石，征人夜中戍。但恐筋力盡，敢憚將軍遇。',96,'御定全唐詩/json/593.json','["長河凍如石，征人夜中戍。但恐筋力盡，敢憚將軍遇。", "古來死未歇，白骨礙官路。豈無一有功，可以高其墓。", "親戚牽衣泣，悲號自相顧。死者雖無言，那堪生者悟。", "不如無手足，得見齒發暮。乃知七尺軀，卻是速死具。"]'),
('yuding-2','金井怨','曹鄴','唐','御定全唐诗','yuding','','[]','西風吹急景，美人照金井。不見面上花，卻恨井中影。',24,'御定全唐詩/json/593.json','["西風吹急景，美人照金井。不見面上花，卻恨井中影。"]'),
('yuding-3','姑蘇台','曹鄴','唐','御定全唐诗','yuding','','[]','南宮酒未銷，又宴姑蘇台。美人和淚去，半夜閶門開。',72,'御定全唐詩/json/593.json','["南宮酒未銷，又宴姑蘇台。美人和淚去，半夜閶門開。", "相對正歌舞，笑中聞鼓鼙。星散九重門，血流十二街。", "一去成萬古，台盡人不回。時聞野田中，拾得黃金釵。"]'),
('yuding-4','夜坐有懷','曹鄴','唐','御定全唐诗','yuding','','[]','悄悄月出樹，東南若微霜。愁人不成寐，五月夜亦長。',72,'御定全唐詩/json/593.json','["悄悄月出樹，東南若微霜。愁人不成寐，五月夜亦長。", "佳期杳天末，骨肉不在旁。年華且有恨，厥體難久康。", "人言力耕者，歲旱亦有糧。吾道固如此，安得苦倀倀。"]'),
('yuding-5','寄監察從兄','曹鄴','唐','御定全唐诗','yuding','','[]','我祖居鄴地，鄴人識文星。此地星已落，兼無古時城。',168,'御定全唐詩/json/593.json','["我祖居鄴地，鄴人識文星。此地星已落，兼無古時城。", "古風既無根，千載難重生。空留建安書，傳說七子名。", "賤子生桂州，桂州山水清。自覺心貌古，兼合古人情。", "因為二雅詩，出語有性靈。持來向長安，時得長者驚。", "芝草不為瑞，還共木葉零。恨如轍中土，終歲填不平。", "吾宗戴豸冠，忽然入西京。憐其羽翼單，撫若親弟兄。", "松根已堅牢，松葉豈不榮。言罷眼無淚，心中如酒酲。"]'),
('yuding-6','樂府體','曹鄴','唐','御定全唐诗','yuding','','[]','蓮子房房嫩，菖蒲葉葉齊。共結池中根，不厭池中泥。',24,'御定全唐詩/json/593.json','["蓮子房房嫩，菖蒲葉葉齊。共結池中根，不厭池中泥。"]'),
('yuding-7','棄婦','曹鄴','唐','御定全唐诗','yuding','','[]','嫁來未曾出，此去長別離。父母亦有家，羞言何以歸。',72,'御定全唐詩/json/593.json','["嫁來未曾出，此去長別離。父母亦有家，羞言何以歸。", "此日年且少，事姑常有儀。見多自成醜，不待顏色衰。", "何人不識寵，所嗟無自非。將欲告此意，四鄰已相疑。"]'),
('yuding-8','讀李斯傳','曹鄴','唐','御定全唐诗','yuding','','[]','一車致三轂，本圖行地速。不知駕馭難，舉足成顛覆。',60,'御定全唐詩/json/593.json','["一車致三轂，本圖行地速。不知駕馭難，舉足成顛覆。", "欺暗尚不然，欺明當自戮。難將一人手，掩得天下目。", "不見三尺墳，雲陽草空綠。"]'),
('yuding-9','文宗陵','曹鄴','唐','御定全唐诗','yuding','','[]','千年堯舜心，心成身已歿。始隨蒼梧雲，不返蒼龍闕。',60,'御定全唐詩/json/593.json','["千年堯舜心，心成身已歿。始隨蒼梧雲，不返蒼龍闕。", "宮女衣不香，黃金賜白髮。留此奉天下，所以無征伐。", "至今汨羅水，不葬大夫骨。"]'),
('yuding-10','偶懷','曹鄴','唐','御定全唐诗','yuding','','[]','開目不見路，常如夜中行。最賤不自勉，中塗與誰爭。',60,'御定全唐詩/json/593.json','["開目不見路，常如夜中行。最賤不自勉，中塗與誰爭。", "蓬為沙所危，還向沙上生。一年秋不熟，安得便廢耕。", "顏子命未達，亦遇時人輕。"]'),
('yuding-11','代羅敷誚使君','曹鄴','唐','御定全唐诗','yuding','','[]','常言愛嵩山，別妾向東京。朝來見人說，卻知在石城。',72,'御定全唐詩/json/593.json','["常言愛嵩山，別妾向東京。朝來見人說，卻知在石城。", "未必菖蒲花，只向石城生。自是使君眼，見物皆有情。", "麋鹿同上山，蓮藕同在泥。莫學天上日，朝東暮還西。"]'),
('yuding-12','怨歌行','曹鄴','唐','御定全唐诗','yuding','','[]','丈夫好弓劍，行坐說金吾。喜聞有行役，結束不待車。',96,'御定全唐詩/json/593.json','["丈夫好弓劍，行坐說金吾。喜聞有行役，結束不待車。", "官田贈倡婦，留妾侍舅姑。舅姑皆已死，庭花半是蕪。", "中妹尋適人，生女亦嫁夫。何曾寄消息，他處卻有書。", "嚴風厲中野，女子心易孤。貧賤又相負，封侯意何如。"]'),
('yuding-13','南征怨','曹鄴','唐','御定全唐诗','yuding','','[]','萬浪東不回，昭王南征早。龍舟沒何處，獨樹江上老。',36,'御定全唐詩/json/593.json','["萬浪東不回，昭王南征早。龍舟沒何處，獨樹江上老。", "吾欲問水濱，宮殿已生草。"]'),
('yuding-14','和潘安仁金谷集','曹鄴','唐','御定全唐诗','yuding','','[]','太守龍為馬，將軍金作車。香飄十裏風，風下綠珠歌。',48,'御定全唐詩/json/593.json','["太守龍為馬，將軍金作車。香飄十裏風，風下綠珠歌。", "莫怪坐上客，歎君庭前花。明朝此池館，不是石崇家。"]'),
('yuding-15','不可見','曹鄴','唐','御定全唐诗','yuding','','[]','常聞貧賤夫，頭白終相待。自從嫁黔婁，終歲長不在。',48,'御定全唐詩/json/593.json','["常聞貧賤夫，頭白終相待。自從嫁黔婁，終歲長不在。", "君夢有雙影，妾夢空四鄰。常思勁北風，吹折雙車輪。"]'),
('yuding-16','秦後作','曹鄴','唐','御定全唐诗','yuding','','[]','大道不居謙，八荒安苟得。木中不生火，高殿禍頃刻。',144,'御定全唐詩/json/593.json','["大道不居謙，八荒安苟得。木中不生火，高殿禍頃刻。", "誰將白帝子，踐我禮義域。空持拔山志，欲奪天地德。", "軹道人不回，壯士斷消息。父母骨成薪，蟲蛇自相食。", "鼎亂陰陽疑，戰盡鬼神力。東郊龍見血，九土玄黃色。", "鼙鼓裂二景，妖星動中國。圓丘無日月，曠野失南北。", "徒流殺人血，神器終不忒。一馬渡空江，始知賢者賊。"]'),
('yuding-17','薄命妾','曹鄴','唐','御定全唐诗','yuding','','[]','薄命常惻惻，出門見南北。劉郎馬蹄疾，何處去不得。',48,'御定全唐詩/json/593.json','["薄命常惻惻，出門見南北。劉郎馬蹄疾，何處去不得。", "淚珠不可收，蟲絲不可織。知君綠桑下，更有新相識。"]'),
('yuding-18','放歌行','曹鄴','唐','御定全唐诗','yuding','','[]','莫唱放歌行，此歌臨楚水。人皆惡此聲，唱者終不已。',36,'御定全唐詩/json/593.json','["莫唱放歌行，此歌臨楚水。人皆惡此聲，唱者終不已。", "三閭有何罪，不向枕上死。"]'),
('yuding-19','江西送人','曹鄴','唐','御定全唐诗','yuding','','[]','八月江上樓，西風令人愁。攜酒樓上別，盡見四山秋。',84,'御定全唐詩/json/593.json','["八月江上樓，西風令人愁。攜酒樓上別，盡見四山秋。", "但愁今日知，莫作他時疑。郎本不住此，無人泣望歸。", "何水不生波，何木不改柯。遙知明日恨，不如今日多。", "將心速投人，路遠人如何。"]'),
('yuding-20','始皇陵下作','曹鄴','唐','御定全唐诗','yuding','','[]','千金買魚燈，泉下照狐兔。行人上陵過，卻吊扶蘇墓。',60,'御定全唐詩/json/593.json','["千金買魚燈，泉下照狐兔。行人上陵過，卻吊扶蘇墓。", "累累壙中物，多於養生具。若使山可移，應將秦國去。", "舜歿雖在前，今猶未封樹。"]'),
('yuding-21','洛原西望','曹鄴','唐','御定全唐诗','yuding','','[]','築城畏不堅，城堅心自毀。秦樹滿平原，秦人不居此。',36,'御定全唐詩/json/593.json','["築城畏不堅，城堅心自毀。秦樹滿平原，秦人不居此。", "猶為泣路者，無力報天子。"]'),
('yuding-22','趙城懷古','曹鄴','唐','御定全唐诗','yuding','','[]','邯鄲舊公子，騎馬又鳴珂。手揮白玉鞭，不避五侯車。',60,'御定全唐詩/json/593.json','["邯鄲舊公子，騎馬又鳴珂。手揮白玉鞭，不避五侯車。", "閒愁春日短，沽酒入倡家。一笑千萬金，醉中贈秦娥。", "如今高原上，樹樹白楊花。"]'),
('yuding-23','代班姬','曹鄴','唐','御定全唐诗','yuding','','[]','寵極多妒容，乘車上金階。欻然趙飛燕，不語到日西。',84,'御定全唐詩/json/593.json','["寵極多妒容，乘車上金階。欻然趙飛燕，不語到日西。", "手把菖蒲花，君王喚不來。常嫌鬢蟬重，乞人白玉釵。", "君心無定波，咫尺流不回。後宮門不掩，每夜黃鳥啼。", "買得千金賦，花顏已如灰。"]'),
('yuding-24','庭草','曹鄴','唐','御定全唐诗','yuding','','[]','庭草根自淺，造化無遺功。低回一寸心，不敢怨春風。',24,'御定全唐詩/json/593.json','["庭草根自淺，造化無遺功。低回一寸心，不敢怨春風。"]'),
('yuding-25','過白起墓','曹鄴','唐','御定全唐诗','yuding','','[]','夷陵火焰滅，長平生氣低。將軍臨老病，賜劍咸陽西。',24,'御定全唐詩/json/593.json','["夷陵火焰滅，長平生氣低。將軍臨老病，賜劍咸陽西。"]'),
('yuding-26','對酒','曹鄴','唐','御定全唐诗','yuding','','[]','愛酒知是僻，難與性相舍。未必獨醒人，便是不飲者。',36,'御定全唐詩/json/593.json','["愛酒知是僻，難與性相舍。未必獨醒人，便是不飲者。", "晚歲無此物，何由住田野。"]'),
('yuding-27','續幽憤','曹鄴','唐','御定全唐诗','yuding','','[]','繁霜作陰起，朱火乘夕發。清晝冷無光，蘭膏坐銷歇。',108,'御定全唐詩/json/593.json','["繁霜作陰起，朱火乘夕發。清晝冷無光，蘭膏坐銷歇。", "惟公執天憲，身是台中傑。一逐楚大夫，何人為君雪。", "匆匆鬼方路，不許辭雙闕。過門似他鄉，舉趾如遺轍。", "八月黃草生，洪濤入雲熱。危魂沒太行，客吊空骨節。", "千年瘴江水，恨聲流不絕。"]'),
('yuding-28','古詞','曹鄴','唐','御定全唐诗','yuding','','[]','高闕礙飛鳥，人言是君家。經年不歸去，愛妾面上花。',48,'御定全唐詩/json/593.json','["高闕礙飛鳥，人言是君家。經年不歸去，愛妾面上花。", "妾面雖有花，妾心非女蘿。郎妻自不重，於妾欲如何。"]'),
('yuding-29','和謝豫章從宋公戲馬台送孔令謝病','曹鄴','唐','御定全唐诗','yuding','','[]','碧樹杳雲暮，朔風自西來。佳人憶山水，置酒在高臺。',48,'御定全唐詩/json/593.json','["碧樹杳雲暮，朔風自西來。佳人憶山水，置酒在高臺。", "不必問流水，坐來日已西。勸君速歸去，正及鷓鴣啼。"]'),
('yuding-30','送進士李殷下第游汾河','曹鄴','唐','御定全唐诗','yuding','','[]','上國花照地，遣君向西征。旁人亦有恨，況複故人情。',120,'御定全唐詩/json/593.json','["上國花照地，遣君向西征。旁人亦有恨，況複故人情。", "單車欲雲去，別酒忽然醒。如何今夜夢，半作道路程。", "邊士不好禮，全家住軍城。城中鼓角嚴，旅客常夜驚。", "中有左記室，逢人眼光明。西門未歸者，下馬如到京。", "還應一開卷，為子心不平。殷勤說忠抱，壯志勿自輕。"]'),
('yuding-31','相思極','曹鄴','唐','御定全唐诗','yuding','','[]','妾顏與日空，君心與日新。三年得一書，猶在湘之濱。',60,'御定全唐詩/json/593.json','["妾顏與日空，君心與日新。三年得一書，猶在湘之濱。", "料君相輕意，知妾無至親。況當受明禮，不令再嫁人。", "願君從此日，化質為妾身。"]'),
('yuding-32','代謝玄暉新亭送範零陵','曹鄴','唐','御定全唐诗','yuding','','[]','楚水洪無際，滄茫接天涯。相看不能語，獨鳥下江蘺。',60,'御定全唐詩/json/593.json','["楚水洪無際，滄茫接天涯。相看不能語，獨鳥下江蘺。", "蓬子悉有戀，蓬根卻無期。車輪自不住，何必怨路岐。", "孟冬衣食薄，夢寐亦未遺。"]'),
('yuding-33','山中效陶','曹鄴','唐','御定全唐诗','yuding','','[]','落第非有罪，茲山聊歸止。山猿隔雲住，共飲山中水。',84,'御定全唐詩/json/593.json','["落第非有罪，茲山聊歸止。山猿隔雲住，共飲山中水。", "讀書時有興，坐石忘卻起。西山忽然暮，往往遺巾履。", "經時一出門，兼候僮僕喜。常被山翁笑，求名豈如此。", "齒發老未衰，何如且求己。"]'),
('yuding-34','城南野居寄知己','曹鄴','唐','御定全唐诗','yuding','','[]','奔走未到我，在城如在村。出門既無意，豈如常閉門。',72,'御定全唐詩/json/593.json','["奔走未到我，在城如在村。出門既無意，豈如常閉門。", "作詩二十載，闕下名不聞。無人為開口，君子獨有言。", "身為苦寒士，一笑亦感恩。殷勤中途上，勿使車無輪。"]'),
('yuding-35','古莫買妾行','曹鄴','唐','御定全唐诗','yuding','','[]','千扉不當路，未似開一門。若遣綠珠醜，石家應尚存。',24,'御定全唐詩/json/593.json','["千扉不當路，未似開一門。若遣綠珠醜，石家應尚存。"]'),
('yuding-36','霽後作','曹鄴','唐','御定全唐诗','yuding','','[]','新霽辨草木，晚塘明衣衿。乳燕不歸宿，雙雙飛向林。',48,'御定全唐詩/json/593.json','["新霽辨草木，晚塘明衣衿。乳燕不歸宿，雙雙飛向林。", "微照露花影，輕雲浮麥陰。無人可招隱，盡日登山吟。"]'),
('yuding-37','田家效陶','曹鄴','唐','御定全唐诗','yuding','','[]','黑黍舂來釀酒飲，青禾刈了驅牛載。',32,'御定全唐詩/json/593.json','["黑黍舂來釀酒飲，青禾刈了驅牛載。", "大姑小叔常在眼，卻笑長安在天外。"]'),
('yuding-38','寄賈馳先輩','曹鄴','唐','御定全唐诗','yuding','','[]','遊子想萬里，何必登高台。聞君燕女吟，如自薊北來。',96,'御定全唐詩/json/593.json','["遊子想萬里，何必登高台。聞君燕女吟，如自薊北來。", "長安高蓋多，健馬東西街。盡說蒿簪古，將錢買金釵。", "我祖西園事，言之獨傷懷。如今數君子，如鳥無樹棲。", "濟水一入河，便與清流乖。聞君欲自持，勿使吾道低。"]'),
('yuding-39','送友人入塞','曹鄴','唐','御定全唐诗','yuding','','[]','亂蓬無根日，送子入青塞。蒼茫萬里秋，如見原野大。',72,'御定全唐詩/json/593.json','["亂蓬無根日，送子入青塞。蒼茫萬里秋，如見原野大。", "鳥雀寒不下，山川迥相對。一馬沒黃雲，登高望猶在。", "驚風忽然起，白日黯已晦。如何恨路長，出門天涯外。"]'),
('yuding-40','寄陽朔友人','曹鄴','唐','御定全唐诗','yuding','','[]','桂林須產千株桂，未解當天影日開。',32,'御定全唐詩/json/593.json','["桂林須產千株桂，未解當天影日開。", "我到月中收得種，為君移向故園栽。"]'),
('yuding-41','題廣福岩','曹鄴','唐','御定全唐诗','yuding','','[]','未有天地先融結，方廣高深無丈尺。',32,'御定全唐詩/json/593.json','["未有天地先融結，方廣高深無丈尺。", "書言不盡畫難成，留與人間作奇特。"]'),
('yuding-42','送曾德邁歸寧宜春','曹鄴','唐','御定全唐诗','yuding','','[]','湘東山水有清輝，袁水詞人得意歸。幾府爭馳毛義檄，',40,'御定全唐詩/json/593.json','["湘東山水有清輝，袁水詞人得意歸。幾府爭馳毛義檄，", "想到宜陽更無事，並將歡慶奉庭闈。"]'),
('yuding-43','送鄭穀歸宜春','曹鄴','唐','御定全唐诗','yuding','','[]','無成歸故國，上馬亦高歌。況是飛鳴後，殊為喜慶多。',48,'御定全唐詩/json/593.json','["無成歸故國，上馬亦高歌。況是飛鳴後，殊為喜慶多。", "暑銷嵩嶽雨，涼吹洞庭波。莫便閑吟去，須期接盛科。"]'),
('yuding-44','老圃堂','曹鄴','唐','御定全唐诗','yuding','','[]','邵平瓜地接吾廬，穀雨幹時手自鋤。',32,'御定全唐詩/json/593.json','["邵平瓜地接吾廬，穀雨幹時手自鋤。", "昨日春風欺不在，就床吹落讀殘書。"]'),
('yuding-0','登蕪城','儲嗣宗','唐','御定全唐诗','yuding','','[]','昔人登此地，丘壟已前悲。今日又非昔，春風能幾時。',24,'御定全唐詩/json/594.json','["昔人登此地，丘壟已前悲。今日又非昔，春風能幾時。"]'),
('yuding-1','滄浪峽','儲嗣宗','唐','御定全唐诗','yuding','','[]','滄浪臨古道，道上石成塵。自有滄浪峽，誰為無事人。',24,'御定全唐詩/json/594.json','["滄浪臨古道，道上石成塵。自有滄浪峽，誰為無事人。"]'),
('yuding-2','垓城','儲嗣宗','唐','御定全唐诗','yuding','','[]','百戰未言非，孤軍驚夜圍。山河意氣盡，淚濕美人衣。',24,'御定全唐詩/json/594.json','["百戰未言非，孤軍驚夜圍。山河意氣盡，淚濕美人衣。"]'),
('yuding-3','南陂遠望','儲嗣宗','唐','御定全唐诗','yuding','','[]','閑門橫古塘，紅樹已驚霜。獨立望秋草，野人耕夕陽。',48,'御定全唐詩/json/594.json','["閑門橫古塘，紅樹已驚霜。獨立望秋草，野人耕夕陽。", "孤煙起蝸舍，飛鷺下漁梁。唯有田家事，依依似故鄉。"]'),
('yuding-4','宿玉簫宮','儲嗣宗','唐','御定全唐诗','yuding','','[]','塵飛不到空，露濕翠微宮。鶴影石橋月，簫聲松殿風。',48,'御定全唐詩/json/594.json','["塵飛不到空，露濕翠微宮。鶴影石橋月，簫聲松殿風。", "綠毛辭世女，白髮入壺翁。借問燒丹處，桃花幾遍紅。"]'),
('yuding-5','晚眺徐州延福寺','儲嗣宗','唐','御定全唐诗','yuding','','[]','杉風振旅塵，晚景藉芳茵。片水明在野，萬花深見人。',48,'御定全唐詩/json/594.json','["杉風振旅塵，晚景藉芳茵。片水明在野，萬花深見人。", "靜依歸鶴思，遠惜舊山春。今日惜攜手，寄懷吟白蘋。"]'),
('yuding-6','宿甘棠館','儲嗣宗','唐','御定全唐诗','yuding','','[]','塵跡入門盡，悄然江海心。水聲巫峽遠，山色洞庭深。',48,'御定全唐詩/json/594.json','["塵跡入門盡，悄然江海心。水聲巫峽遠，山色洞庭深。", "風桂落寒子，嵐煙凝夕陰。前軒鶴歸處，蘿月思沉沉。"]'),
('yuding-7','和茅山高拾遺憶山中雜題五首：山泉','儲嗣宗','唐','御定全唐诗','yuding','','[]','香味清機仙府回，縈紆亂石便流杯。',32,'御定全唐詩/json/594.json','["香味清機仙府回，縈紆亂石便流杯。", "春風莫泛桃花去，恐引凡人入洞來。"]'),
('yuding-8','和茅山高拾遺憶山中雜題五首：巢鶴','儲嗣宗','唐','御定全唐诗','yuding','','[]','千萬雲間丁令威，殷勤仙骨莫先飛。',32,'御定全唐詩/json/594.json','["千萬雲間丁令威，殷勤仙骨莫先飛。", "若逢茅氏傳消息，貞白先生不久歸。"]'),
('yuding-9','和茅山高拾遺憶山中雜題五首：胡山','儲嗣宗','唐','御定全唐诗','yuding','','[]','犬入五雲音信絕，鳳樓凝碧悄無聲。',32,'御定全唐詩/json/594.json','["犬入五雲音信絕，鳳樓凝碧悄無聲。", "焚香古洞步虛夜，露濕松花空月明。"]'),
('yuding-10','和茅山高拾遺憶山中雜題五首：小樓','儲嗣宗','唐','御定全唐诗','yuding','','[]','松杉風外亂山青，曲幾焚香對石屏。',32,'御定全唐詩/json/594.json','["松杉風外亂山青，曲幾焚香對石屏。", "空憶去年春雨後，燕泥時汙太玄經。"]'),
('yuding-11','和茅山高拾遺憶山中雜題五首：山鄰','儲嗣宗','唐','御定全唐诗','yuding','','[]','石橋春澗已歸遲，夢入仙山山不知。',32,'御定全唐詩/json/594.json','["石橋春澗已歸遲，夢入仙山山不知。", "柱史從來非俗吏，青牛道士莫相疑。"]'),
('yuding-12','送道士','儲嗣宗','唐','御定全唐诗','yuding','','[]','泠然禦風客，與道自浮沉。黃鶴有歸語，白雲無忌心。',48,'御定全唐詩/json/594.json','["泠然禦風客，與道自浮沉。黃鶴有歸語，白雲無忌心。", "藥爐經月淨，天路入壺深。從此分杯後，相思何處尋。"]'),
('yuding-13','宿山館','儲嗣宗','唐','御定全唐诗','yuding','','[]','寂寞對衰草，地涼凝露華。蟬鳴月中樹，風落客前花。',48,'御定全唐詩/json/594.json','["寂寞對衰草，地涼凝露華。蟬鳴月中樹，風落客前花。", "山館無宿伴，秋琴初別家。自憐千萬里，筆硯寄生涯。"]'),
('yuding-14','入浮石山','儲嗣宗','唐','御定全唐诗','yuding','','[]','斜日出門去，殘花已過春。鳥聲穿葉遠，虎跡渡溪新。',48,'御定全唐詩/json/594.json','["斜日出門去，殘花已過春。鳥聲穿葉遠，虎跡渡溪新。", "入洞幾時路，耕田何代人。自慚非避俗，不敢問迷津。"]'),
('yuding-15','送人歸故園','儲嗣宗','唐','御定全唐诗','yuding','','[]','遠節慘言別，況予心久違。從來憶家淚，今日送君歸。',48,'御定全唐詩/json/594.json','["遠節慘言別，況予心久違。從來憶家淚，今日送君歸。", "野路正風雪，還鄉猶布衣。裏中耕稼者，應笑讀書非。"]'),
('yuding-16','得越中書','儲嗣宗','唐','御定全唐诗','yuding','','[]','芳草離離思，悠悠春夢餘。池亭千里月，煙水一封書。',48,'御定全唐詩/json/594.json','["芳草離離思，悠悠春夢餘。池亭千里月，煙水一封書。", "詩想懷康樂，文應吊子胥。扁舟戀南越，豈獨為鱸魚。"]'),
('yuding-17','秋墅','儲嗣宗','唐','御定全唐诗','yuding','','[]','欲暮候樵者，望山空翠微。虹隨餘雨散，鴉帶夕陽歸。',48,'御定全唐詩/json/594.json','["欲暮候樵者，望山空翠微。虹隨餘雨散，鴉帶夕陽歸。", "窮巷長秋草，孤村時擣衣。誰知多病客，寂寞掩柴扉。"]'),
('yuding-18','哭彭先生','儲嗣宗','唐','御定全唐诗','yuding','','[]','穀口溪聲客自傷，那堪嗚咽吊殘陽。空階鶴戀丹青影，',40,'御定全唐詩/json/594.json','["穀口溪聲客自傷，那堪嗚咽吊殘陽。空階鶴戀丹青影，", "門人遠赴心喪夜，月滿千山舊草堂。"]'),
('yuding-19','和顧非熊先生題茅山處士閒居','儲嗣宗','唐','御定全唐诗','yuding','','[]','歸耕地肺絕塵喧，匣裏青萍未報恩。濁酒自憐終日醉，',40,'御定全唐詩/json/594.json','["歸耕地肺絕塵喧，匣裏青萍未報恩。濁酒自憐終日醉，", "唯有階前芳草色，年年惆悵憶王孫。"]'),
('yuding-20','長安懷古','儲嗣宗','唐','御定全唐诗','yuding','','[]','禍稔蕭牆終不知，生人力屈盡邊陲。赤龍已赴東方暗，',40,'御定全唐詩/json/594.json','["禍稔蕭牆終不知，生人力屈盡邊陲。赤龍已赴東方暗，", "秋風解怨扶蘇死，露泣煙愁紅樹枝。"]'),
('yuding-21','過王右丞書堂二首','儲嗣宗','唐','御定全唐诗','yuding','','[]','澄潭昔臥龍，章句世為宗。獨步聲名在，千岩水石空。',96,'御定全唐詩/json/594.json','["澄潭昔臥龍，章句世為宗。獨步聲名在，千岩水石空。", "野禽悲灌木，落日吊清風。後學攀遺址，秋山聞草蟲。", "萬樹影參差，石床藤半垂。螢光雖散草，鳥跡尚臨池。", "風雅傳今日，雲山想昔時。感深蘇屬國，千載五言詩。"]'),
('yuding-22','孤雁','儲嗣宗','唐','御定全唐诗','yuding','','[]','孤雁暮飛急，蕭蕭天地秋。關河正黃葉，消息斷青樓。',48,'御定全唐詩/json/594.json','["孤雁暮飛急，蕭蕭天地秋。關河正黃葉，消息斷青樓。", "湘渚煙波遠，驪山風雨愁。此時萬里道，魂夢繞滄洲。"]'),
('yuding-23','贈隱者','儲嗣宗','唐','御定全唐诗','yuding','','[]','盡室居幽谷，亂山為四鄰。霧深知有術，窗靜似無人。',48,'御定全唐詩/json/594.json','["盡室居幽谷，亂山為四鄰。霧深知有術，窗靜似無人。", "鶴語松上月，花明雲裏春。生涯更何許，尊酒與垂綸。"]'),
('yuding-24','早春懷薛公裕','儲嗣宗','唐','御定全唐诗','yuding','','[]','幽獨自成愚，柴門日漸蕪。陸機初入洛，孫楚又游吳。',48,'御定全唐詩/json/594.json','["幽獨自成愚，柴門日漸蕪。陸機初入洛，孫楚又游吳。", "失意怨楊柳，異鄉聞鷓鴣。相思複相望，春草滿南湖。"]'),
('yuding-25','村月','儲嗣宗','唐','御定全唐诗','yuding','','[]','月午籬南道，前村半隱林。田翁獨歸處，蕎麥露花深。',24,'御定全唐詩/json/594.json','["月午籬南道，前村半隱林。田翁獨歸處，蕎麥露花深。"]'),
('yuding-26','早春','儲嗣宗','唐','御定全唐诗','yuding','','[]','野樹花初發，空山獨見時。踟躕曆陽道，鄉思滿南枝。',24,'御定全唐詩/json/594.json','["野樹花初發，空山獨見時。踟躕曆陽道，鄉思滿南枝。"]'),
('yuding-27','送友人游吳','儲嗣宗','唐','御定全唐诗','yuding','','[]','吳山青楚吟，草色異鄉心。一酌水邊酒，數聲花下琴。',48,'御定全唐詩/json/594.json','["吳山青楚吟，草色異鄉心。一酌水邊酒，數聲花下琴。", "登樓舊國遠，探穴九疑深。更想逢秋節，那堪聞夜砧。"]'),
('yuding-28','贈別','儲嗣宗','唐','御定全唐诗','yuding','','[]','蘭澤傷秋色，臨風遠別期。東城草雖綠，南浦柳無枝。',48,'御定全唐詩/json/594.json','["蘭澤傷秋色，臨風遠別期。東城草雖綠，南浦柳無枝。", "直道豈易枉，暗投誰不疑。因君問行役，有淚濕江蘺。"]'),
('yuding-29','經故人舊居','儲嗣宗','唐','御定全唐诗','yuding','','[]','萬里訪遺塵，鶯聲淚濕巾。古書無主散，廢宅與山鄰。',48,'御定全唐詩/json/594.json','["萬里訪遺塵，鶯聲淚濕巾。古書無主散，廢宅與山鄰。", "宿草風悲夜，荒村月吊人。淒涼問殘柳，今日為誰春。"]'),
('yuding-30','隨邊使過五原','儲嗣宗','唐','御定全唐诗','yuding','','[]','偶逐星車犯虜塵，故鄉常恐到無因。',32,'御定全唐詩/json/594.json','["偶逐星車犯虜塵，故鄉常恐到無因。", "五原西去陽關廢，日漫平沙不見人。"]'),
('yuding-31','春懷寄秣陵知友','儲嗣宗','唐','御定全唐诗','yuding','','[]','廬江城外柳堪攀，萬里行人尚未還。',32,'御定全唐詩/json/594.json','["廬江城外柳堪攀，萬里行人尚未還。", "借問景陽臺下客，謝家誰更臥東山。"]'),
('yuding-32','宋州月夜感懷','儲嗣宗','唐','御定全唐诗','yuding','','[]','雁池衰草露沾衣，河水東流萬事微。',32,'御定全唐詩/json/594.json','["雁池衰草露沾衣，河水東流萬事微。", "寂寞青陵臺上月，秋風滿樹鵲南飛。"]'),
('yuding-33','吳宮','儲嗣宗','唐','御定全唐诗','yuding','','[]','荒台荊棘多，忠諫竟如何。細草迷宮巷，閑花誤綺羅。',48,'御定全唐詩/json/594.json','["荒台荊棘多，忠諫竟如何。細草迷宮巷，閑花誤綺羅。", "前溪徒自綠，子夜不聞歌。悵望清江暮，悠悠東去波。"]'),
('yuding-34','春遊望仙谷','儲嗣宗','唐','御定全唐诗','yuding','','[]','清無車馬塵，深洞百花春。雞犬疑沾藥，耕桑似避秦。',48,'御定全唐詩/json/594.json','["清無車馬塵，深洞百花春。雞犬疑沾藥，耕桑似避秦。", "登山采樵路，臨水浣紗人。若得心無事，移家便卜鄰。"]'),
('yuding-35','聖女祠','儲嗣宗','唐','御定全唐诗','yuding','','[]','石屏苔色涼，流水繞祠堂。巢鵲疑天漢，潭花似鏡妝。',48,'御定全唐詩/json/594.json','["石屏苔色涼，流水繞祠堂。巢鵲疑天漢，潭花似鏡妝。", "神來雲雨合，神去蕙蘭香。不復聞雙佩，山門空夕陽。"]'),
('yuding-36','宿范水','儲嗣宗','唐','御定全唐诗','yuding','','[]','行人倦游宦，秋草宿湖邊。露濕芙蓉渡，月明漁網船。',48,'御定全唐詩/json/594.json','["行人倦游宦，秋草宿湖邊。露濕芙蓉渡，月明漁網船。", "寒機深竹裏，遠浪到門前。何處思鄉甚，歌聲聞採蓮。"]'),
('yuding-37','送顧陶校書歸錢塘','儲嗣宗','唐','御定全唐诗','yuding','','[]','清苦月偏知，南歸瘦馬遲。橐輕緣換酒，發白為吟詩。',48,'御定全唐詩/json/594.json','["清苦月偏知，南歸瘦馬遲。橐輕緣換酒，發白為吟詩。", "水色西陵渡，松聲伍相祠。聖朝思直諫，不是掛冠時。"]'),
('yuding-38','題雲陽高少府衙齋','儲嗣宗','唐','御定全唐诗','yuding','','[]','大隱能兼濟，軒窗逐勝開。遠含雲水思，深得棟樑材。',48,'御定全唐詩/json/594.json','["大隱能兼濟，軒窗逐勝開。遠含雲水思，深得棟樑材。", "吏散山逾靜，庭閑鳥自來。更憐幽砌色，秋雨長莓苔。"]'),
('yuding-0','早春山行','于武陵','唐','御定全唐诗','yuding','','[]','江草暖初綠，雁行皆北飛。異鄉那久客，野鳥尚思歸。',48,'御定全唐詩/json/595.json','["江草暖初綠，雁行皆北飛。異鄉那久客，野鳥尚思歸。", "十載過如夢，素心應已違。行行家漸遠，更苦得書稀。"]'),
('yuding-1','宿友生林居因懷賈區','于武陵','唐','御定全唐诗','yuding','','[]','繞屋樹森森，多棲紫閣禽。暫過當永夜，微得話前心。',48,'御定全唐詩/json/595.json','["繞屋樹森森，多棲紫閣禽。暫過當永夜，微得話前心。", "入楚行應遠，經湘恨必深。那堪對寒燭，更賦別離吟。"]'),
('yuding-2','贈賣松人','于武陵','唐','御定全唐诗','yuding','','[]','入市雖求利，憐君意獨真。劚將寒澗樹，賣與翠樓人。',48,'御定全唐詩/json/595.json','["入市雖求利，憐君意獨真。劚將寒澗樹，賣與翠樓人。", "瘦葉幾經雪，淡花應少春。長安重桃李，徒染六街塵。"]'),
('yuding-3','友人南游不回因而有寄','于武陵','唐','御定全唐诗','yuding','','[]','相思春樹綠，千里亦依依。鄠杜月頻滿，瀟湘人未歸。',48,'御定全唐詩/json/595.json','["相思春樹綠，千里亦依依。鄠杜月頻滿，瀟湘人未歸。", "桂花風半落，煙草蝶雙飛。一別無消息，水南車跡稀。"]'),
('yuding-4','送酂縣董明府之任','于武陵','唐','御定全唐诗','yuding','','[]','南北行已久，憐君知苦辛。萬家同草木，三載得陽春。',48,'御定全唐詩/json/595.json','["南北行已久，憐君知苦辛。萬家同草木，三載得陽春。", "東道聽遊子，夷門歌主人。空持語相送，應怪不沾巾。"]'),
('yuding-5','山上樹','于武陵','唐','御定全唐诗','yuding','','[]','日暖上山路，鳥啼知已春。忽逢幽隱處，如見獨醒人。',48,'御定全唐詩/json/595.json','["日暖上山路，鳥啼知已春。忽逢幽隱處，如見獨醒人。", "石冷開常晚，風多落亦頻。樵夫應不識，歲久伐為薪。"]'),
('yuding-6','長信宮二首','于武陵','唐','御定全唐诗','yuding','','[]','簟涼秋氣初，長信恨何如。拂黛月生指，解鬟雲滿梳。',96,'御定全唐詩/json/595.json','["簟涼秋氣初，長信恨何如。拂黛月生指，解鬟雲滿梳。", "一從悲畫扇，幾度泣前魚。坐聽南宮樂，涼風搖翠裾。", "一失輦前恩，綺羅生暗塵。惟應深夜月，獨伴向隅人。", "長信翠蛾老，昭陽紅粉新。君心似秋節，不使草長春。"]'),
('yuding-7','洛陽道','于武陵','唐','御定全唐诗','yuding','','[]','浮世若浮雲，千回故複新。旋添青草塚，更有白頭人。',48,'御定全唐詩/json/595.json','["浮世若浮雲，千回故複新。旋添青草塚，更有白頭人。", "歲暮容將老，雪晴山欲春。行行車與馬，不盡洛陽塵。"]'),
('yuding-8','東門路','于武陵','唐','御定全唐诗','yuding','','[]','東門車馬路，此路在浮沉。白日若不落，紅塵應更深。',48,'御定全唐詩/json/595.json','["東門車馬路，此路在浮沉。白日若不落，紅塵應更深。", "從來名利地，皆起是非心。所以青青草，年年生漢陰。"]'),
('yuding-9','江樓春望','于武陵','唐','御定全唐诗','yuding','','[]','樓下長江路，舟車晝不閑。鳥聲非故國，春色是他山。',48,'御定全唐詩/json/595.json','["樓下長江路，舟車晝不閑。鳥聲非故國，春色是他山。", "一望雲複水，幾重河與關。愁心隨落日，萬里各西還。"]'),
('yuding-10','洛中晴望','于武陵','唐','御定全唐诗','yuding','','[]','九陌盡風塵，囂囂晝複昏。古今人不斷，南北路長存。',48,'御定全唐詩/json/595.json','["九陌盡風塵，囂囂晝複昏。古今人不斷，南北路長存。", "葉落上陽樹，草衰金穀園。亂鴉歸未已，殘日半前軒。"]'),
('yuding-11','西歸','于武陵','唐','御定全唐诗','yuding','','[]','不系與舟閑，悠悠吳楚間。羞將新白髮，卻到舊青山。',48,'御定全唐詩/json/595.json','["不系與舟閑，悠悠吳楚間。羞將新白髮，卻到舊青山。", "一葉忽離樹，幾人同入關。長安家尚在，秋至又西還。"]'),
('yuding-12','南游','于武陵','唐','御定全唐诗','yuding','','[]','窮秋幾日雨，處處生蒼苔。舊國寄書後，涼天方雁來。',48,'御定全唐詩/json/595.json','["窮秋幾日雨，處處生蒼苔。舊國寄書後，涼天方雁來。", "露繁山草濕，洲暖水花開。去盡同行客，一帆猶未回。"]'),
('yuding-13','南遊有感','于武陵','唐','御定全唐诗','yuding','','[]','杜陵無厚業，不得駐車輪。重到曾遊處，多非舊主人。',48,'御定全唐詩/json/595.json','["杜陵無厚業，不得駐車輪。重到曾遊處，多非舊主人。", "東風千嶺樹，西日一洲蘋。又渡湘江去，湘江水複春。"]'),
('yuding-14','夜泊湘江','于武陵','唐','御定全唐诗','yuding','','[]','北風吹楚樹，此地獨先秋。何事屈原恨，不隨湘水流。',48,'御定全唐詩/json/595.json','["北風吹楚樹，此地獨先秋。何事屈原恨，不隨湘水流。", "涼天生片月，竟夕伴孤舟。一作南行客，無成空白頭。"]'),
('yuding-15','客中','于武陵','唐','御定全唐诗','yuding','','[]','楚人歌竹枝，遊子淚沾衣。異國久為客，寒宵頻夢歸。',48,'御定全唐詩/json/595.json','["楚人歌竹枝，遊子淚沾衣。異國久為客，寒宵頻夢歸。", "一封書未返，千樹葉皆飛。南過洞庭水，更應消息稀。"]'),
('yuding-16','夜尋僧不遇','于武陵','唐','御定全唐诗','yuding','','[]','數歇度煙水，漸非塵俗間。泉聲入秋寺，月色遍寒山。',48,'御定全唐詩/json/595.json','["數歇度煙水，漸非塵俗間。泉聲入秋寺，月色遍寒山。", "石路幾回雪，竹房猶閉關。不知雙樹客，何處與雲閑。"]'),
('yuding-17','訪道者不遇','于武陵','唐','御定全唐诗','yuding','','[]','人間惟此路，長得綠苔衣。及戶無行跡，游方應未歸。',48,'御定全唐詩/json/595.json','["人間惟此路，長得綠苔衣。及戶無行跡，游方應未歸。", "平生無限事，到此盡知非。獨倚松門久，陰雲昏翠微。"]'),
('yuding-18','贈王隱者山居','于武陵','唐','御定全唐诗','yuding','','[]','石室掃無塵，人寰與此分。飛來南浦樹，半是華山雲。',48,'御定全唐詩/json/595.json','["石室掃無塵，人寰與此分。飛來南浦樹，半是華山雲。", "浮世幾多事，先生應不聞。寒山滿西日，空照雁成群。"]'),
('yuding-19','寄北客','于武陵','唐','御定全唐诗','yuding','','[]','窮邊足風慘，何處醉樓臺。家去幾千里，月圓十二回。',48,'御定全唐詩/json/595.json','["窮邊足風慘，何處醉樓臺。家去幾千里，月圓十二回。", "寒阡隨日遠，雪路向城開。遊子久無信，年年空雁來。"]'),
('yuding-20','寄友人','于武陵','唐','御定全唐诗','yuding','','[]','長安清渭東，遊子跡重重。此去紅塵路，難尋君馬蹤。',48,'御定全唐詩/json/595.json','["長安清渭東，遊子跡重重。此去紅塵路，難尋君馬蹤。", "昔時輕一別，漸老貴相逢。應戀嵩陽住，嵩陽饒古松。"]'),
('yuding-21','夜與故人別','于武陵','唐','御定全唐诗','yuding','','[]','白日去難駐，故人非舊容。今宵一別後，何處更相逢。',48,'御定全唐詩/json/595.json','["白日去難駐，故人非舊容。今宵一別後，何處更相逢。", "過楚水千里，到秦山幾重。語來天又曉，月落滿城鐘。"]'),
('yuding-22','別故人','于武陵','唐','御定全唐诗','yuding','','[]','行子與秋葉，各隨南北風。雖非千里別，還阻一宵同。',48,'御定全唐詩/json/595.json','["行子與秋葉，各隨南北風。雖非千里別，還阻一宵同。", "過盡少年日，尚如長轉蓬。猶為布衣客，羞入故關中。"]'),
('yuding-23','送客東歸','于武陵','唐','御定全唐诗','yuding','','[]','一聽遊子歌，秋計覺蹉跎。四海少平地，百川無定波。',48,'御定全唐詩/json/595.json','["一聽遊子歌，秋計覺蹉跎。四海少平地，百川無定波。", "共驚年已暮，俱向客中多。又駕征輪去，東歸事若何。"]'),
('yuding-24','過侯王故第','于武陵','唐','御定全唐诗','yuding','','[]','過此一酸辛，行人淚有痕。獨殘新碧樹，猶擁舊朱門。',48,'御定全唐詩/json/595.json','["過此一酸辛，行人淚有痕。獨殘新碧樹，猶擁舊朱門。", "歌歇雲初散，簷空燕尚存。不知彈鋏客，何處感新恩。"]'),
('yuding-25','孤雲','于武陵','唐','御定全唐诗','yuding','','[]','南北各萬里，有雲心更閑。因風離海上，伴月到人間。',48,'御定全唐詩/json/595.json','["南北各萬里，有雲心更閑。因風離海上，伴月到人間。", "洛浦少高樹，長安無舊山。裴回不可駐，漠漠又空還。"]'),
('yuding-26','遠水','于武陵','唐','御定全唐诗','yuding','','[]','悔作望南浦，望中生遠愁。因知人易老，為有水東流。',48,'御定全唐詩/json/595.json','["悔作望南浦，望中生遠愁。因知人易老，為有水東流。", "欲附故鄉信，不逢歸客舟。萋萋兩岸草，又度一年秋。"]'),
('yuding-27','詠蟬','于武陵','唐','御定全唐诗','yuding','','[]','江頭一聲起，芳歲已難留。聽此高林上，遙知故國秋。',48,'御定全唐詩/json/595.json','["江頭一聲起，芳歲已難留。聽此高林上，遙知故國秋。", "應催風落葉，似勸客回舟。不是新蟬苦，年年自有愁。"]'),
('yuding-28','感情','于武陵','唐','御定全唐诗','yuding','','[]','青山長寂寞，南望獨高歌。四海故人盡，九原新壟多。',48,'御定全唐詩/json/595.json','["青山長寂寞，南望獨高歌。四海故人盡，九原新壟多。", "西沉浮世日，東注逝川波。不使年華駐，此生能幾何。"]'),
('yuding-29','早春日山居寄城郭知己','于武陵','唐','御定全唐诗','yuding','','[]','陽和潛發蕩寒陰，便使川原景象新。入戶風泉聲瀝瀝，',40,'御定全唐詩/json/595.json','["陽和潛發蕩寒陰，便使川原景象新。入戶風泉聲瀝瀝，", "雖有眼前詩酒興，遨遊爭得稱閒心。"]'),
('yuding-30','勸酒','于武陵','唐','御定全唐诗','yuding','','[]','勸君金屈卮，滿酌不須辭。花發多風雨，人生足別離。',24,'御定全唐詩/json/595.json','["勸君金屈卮，滿酌不須辭。花發多風雨，人生足別離。"]'),
('yuding-31','感懷','于武陵','唐','御定全唐诗','yuding','','[]','東風吹草色，空使客蹉跎。不設太平險，更應遊子多。',48,'御定全唐詩/json/595.json','["東風吹草色，空使客蹉跎。不設太平險，更應遊子多。", "幾傷行處淚，一曲醉中歌。盡向青門外，東隨渭水波。"]'),
('yuding-32','友人亭松','于武陵','唐','御定全唐诗','yuding','','[]','俯仰不能去，如逢舊友同。曾因春雪散，見在華山中。',48,'御定全唐詩/json/595.json','["俯仰不能去，如逢舊友同。曾因春雪散，見在華山中。", "何處有明月，訪君聽遠風。相將歸未得，各占石岩東。"]'),
('yuding-33','遊中梁山','于武陵','唐','御定全唐诗','yuding','','[]','僻地好泉石，何人曾陸沈。不知青嶂外，更有白雲深。',48,'御定全唐詩/json/595.json','["僻地好泉石，何人曾陸沈。不知青嶂外，更有白雲深。", "因此見喬木，幾回思舊林。殷勤猿與鳥，惟我獨何心。"]'),
('yuding-34','尋山','于武陵','唐','御定全唐诗','yuding','','[]','到此絕車輪，萋萋草樹春。青山如有利，白石亦成塵。',48,'御定全唐詩/json/595.json','["到此絕車輪，萋萋草樹春。青山如有利，白石亦成塵。", "水闊應無路，松深不見人。如知巢與許，千載跡猶新。"]'),
('yuding-35','宿江口','于武陵','唐','御定全唐诗','yuding','','[]','南渡人來絕，喧喧雁滿沙。自生江上月，長有客思家。',48,'御定全唐詩/json/595.json','["南渡人來絕，喧喧雁滿沙。自生江上月，長有客思家。", "半夜下霜岸，北風吹荻花。自驚歸夢斷，不得到天涯。"]'),
('yuding-36','秋夜達蕭關','于武陵','唐','御定全唐诗','yuding','','[]','擾擾浮梁路，人忙月自閑。去年為塞客，今夜宿蕭關。',48,'御定全唐詩/json/595.json','["擾擾浮梁路，人忙月自閑。去年為塞客，今夜宿蕭關。", "辭國幾經歲，望鄉空見山。不知江葉下，又作布衣還。"]'),
('yuding-37','斜谷道','于武陵','唐','御定全唐诗','yuding','','[]','亂峰連疊嶂，千里綠峨峨。蜀國路如此，遊人車亦過。',48,'御定全唐詩/json/595.json','["亂峰連疊嶂，千里綠峨峨。蜀國路如此，遊人車亦過。", "遠煙當葉斂，驟雨逐風多。獨憶紫芝叟，臨風歌舊歌。"]'),
('yuding-38','過百牢關貽舟中者','于武陵','唐','御定全唐诗','yuding','','[]','蜀國少平地，方思京洛間。遠為千里客，來度百牢關。',48,'御定全唐詩/json/595.json','["蜀國少平地，方思京洛間。遠為千里客，來度百牢關。", "帆影清江水，鈴聲碧草山。不因名與利，爾我各應閑。"]'),
('yuding-39','客中覽鏡','于武陵','唐','御定全唐诗','yuding','','[]','何當開此鏡，即見發如絲。白日急於水，一年能幾時。',48,'御定全唐詩/json/595.json','["何當開此鏡，即見發如絲。白日急於水，一年能幾時。", "每逢芳草處，長返故園遲。所以多為客，蹉跎欲怨誰。"]'),
('yuding-40','長安逢隱者','于武陵','唐','御定全唐诗','yuding','','[]','征車千里至，碾遍六街塵。向此有營地，忽逢無事人。',48,'御定全唐詩/json/595.json','["征車千里至，碾遍六街塵。向此有營地，忽逢無事人。", "昔時顏未改，浮世路多新。且脫衣沽酒，終南山欲春。"]'),
('yuding-41','與僧話舊','于武陵','唐','御定全唐诗','yuding','','[]','草堂前有山，一見一相寬。處世貴僧靜，青松因歲寒。',48,'御定全唐詩/json/595.json','["草堂前有山，一見一相寬。處世貴僧靜，青松因歲寒。", "他山逢舊侶，盡日話長安。所以閑行跡，千回繞藥欄。"]'),
('yuding-42','贈王道士','于武陵','唐','御定全唐诗','yuding','','[]','日日市朝路，何時無苦辛。不隨丹灶客，終作白頭人。',48,'御定全唐詩/json/595.json','["日日市朝路，何時無苦辛。不隨丹灶客，終作白頭人。", "浮世度千載，桃源方一春。歸來華表上，應笑北邙塵。"]'),
('yuding-43','匣中琴','于武陵','唐','御定全唐诗','yuding','','[]','世人無正心，蟲網匣中琴。何以經時廢，非為娛耳音。',48,'御定全唐詩/json/595.json','["世人無正心，蟲網匣中琴。何以經時廢，非為娛耳音。", "獨令高韻在，誰感隙塵深。應是南風曲，聲聲不合今。"]'),
('yuding-44','過洛陽城','于武陵','唐','御定全唐诗','yuding','','[]','古來利與名，俱在洛陽城。九陌鼓初起，萬車輪已行。',48,'御定全唐詩/json/595.json','["古來利與名，俱在洛陽城。九陌鼓初起，萬車輪已行。", "周秦時幾變，伊洛水猶清。二月中橋路，鳥啼春草生。"]'),
('yuding-45','望月','于武陵','唐','御定全唐诗','yuding','','[]','離家凡幾宵，一望一寥寥。新魄又將滿，故鄉應漸遙。',48,'御定全唐詩/json/595.json','["離家凡幾宵，一望一寥寥。新魄又將滿，故鄉應漸遙。", "獨臨彭蠡水，遠憶洛陽橋。更有乘舟客，淒然亦駐橈。"]'),
('yuding-46','王將軍宅夜聽歌','于武陵','唐','御定全唐诗','yuding','','[]','朱檻滿明月，美人歌落梅。忽驚塵起處，疑有鳳飛來。',48,'御定全唐詩/json/595.json','["朱檻滿明月，美人歌落梅。忽驚塵起處，疑有鳳飛來。", "一曲聽初徹，幾年愁暫開。東南正雲雨，不得見陽臺。"]'),
('yuding-47','長信宮','于武陵','唐','御定全唐诗','yuding','','[]','莫問古宮名，古宮空有城。惟應東去水，不改舊時聲。',24,'御定全唐詩/json/595.json','["莫問古宮名，古宮空有城。惟應東去水，不改舊時聲。"]'),
('yuding-48','高樓','于武陵','唐','御定全唐诗','yuding','','[]','遠天明月出，照此誰家樓。上有羅衣裳，涼風吹不休。',24,'御定全唐詩/json/595.json','["遠天明月出，照此誰家樓。上有羅衣裳，涼風吹不休。"]'),
('yuding-0','感古','司馬紮','唐','御定全唐诗','yuding','','[]','九折無停波，三光如轉燭。玄珠人不識，徒愛燕趙玉。',48,'御定全唐詩/json/596.json','["九折無停波，三光如轉燭。玄珠人不識，徒愛燕趙玉。", "祖龍已深惑，漢氏遠徇欲。驪山與茂陵，相對秋草綠。"]'),
('yuding-1','贈王道士','司馬紮','唐','御定全唐诗','yuding','','[]','玉洞秋有花，蓬山夜無鬼。豈知浮雲世，生死逐流水。',72,'御定全唐詩/json/596.json','["玉洞秋有花，蓬山夜無鬼。豈知浮雲世，生死逐流水。", "瑤台歌一曲，曲盡五煙起。悠然望虛路，玉京在海裏。", "青籙秘不聞，黃鶴去不止。願隨執輕策，往結周太子。"]'),
('yuding-2','古思','司馬紮','唐','御定全唐诗','yuding','','[]','春華惜妾態，秋草念妾心。始知井邊桐，不如堂上琴。',48,'御定全唐詩/json/596.json','["春華惜妾態，秋草念妾心。始知井邊桐，不如堂上琴。", "月落卻羨鏡，花飛猶委苔。門前長江水，一去終不回。"]'),
('yuding-3','獵客','司馬紮','唐','御定全唐诗','yuding','','[]','五陵射雕客，走馬占春光。下馬青樓前，華裾獨煌煌。',120,'御定全唐詩/json/596.json','["五陵射雕客，走馬占春光。下馬青樓前，華裾獨煌煌。", "自言家咸京，世族如金張。擊鐘傳鼎食，爾來八十強。", "朱門爭先開，車輪滿路傍。娥娥燕趙人，珠箔閉高堂。", "清歌雜妙舞，臨歡度曲長。朝遊園花新，夜宴池月涼。", "更以馳驟多，意氣事強梁。君王正年少，終日在長楊。"]'),
('yuding-4','送進士苗縱歸紫邏山居','司馬紮','唐','御定全唐诗','yuding','','[]','汝上多奇山，高懷愜清境。強來幹名地，冠帶不能整。',72,'御定全唐詩/json/596.json','["汝上多奇山，高懷愜清境。強來幹名地，冠帶不能整。", "常言夢歸處，泉石寒更靜。鶴聲夜無人，空月隨松影。", "今朝拋我去，春物傷明景。悵望相送還，微陽在東嶺。"]'),
('yuding-5','賣花者','司馬紮','唐','御定全唐诗','yuding','','[]','少壯彼何人，種花荒苑外。不知力田苦，卻笑耕耘輩。',120,'御定全唐詩/json/596.json','["少壯彼何人，種花荒苑外。不知力田苦，卻笑耕耘輩。", "當春賣春色，來往經幾代。長安甲第多，處處花堪愛。", "良金不惜費，競取園中最。一蕊才占煙，歌聲已高會。", "自言種花地，終日擁軒蓋。農夫官役時，獨與花相對。", "那令賣花者，久為生人害。貴粟不貴花，生人自應泰。"]'),
('yuding-6','彈琴','司馬紮','唐','御定全唐诗','yuding','','[]','涼室無外響，空桑七弦分。所彈非新聲，俗耳安肯聞。',48,'御定全唐詩/json/596.json','["涼室無外響，空桑七弦分。所彈非新聲，俗耳安肯聞。", "月落未終曲，暗中泣湘君。如傳我心苦，千里蒼梧雲。"]'),
('yuding-7','古邊卒思歸','司馬紮','唐','御定全唐诗','yuding','','[]','有田不得耕，身臥遼陽城。夢中稻花香，覺後戰血腥。',72,'御定全唐詩/json/596.json','["有田不得耕，身臥遼陽城。夢中稻花香，覺後戰血腥。", "漢武在深殿，唯思廓寰瀛。中原半烽火，比屋皆點行。", "邊土無膏腴，閑地何必爭。徒令執耒者，刀下死縱橫。"]'),
('yuding-8','美劉太保','司馬紮','唐','御定全唐诗','yuding','','[]','常愛魯仲連，退身得其趣。不知鴟夷子，更入五湖去。',96,'御定全唐詩/json/596.json','["常愛魯仲連，退身得其趣。不知鴟夷子，更入五湖去。", "雲霞恣搖曳，鴻鵠無低翥。萬里天地空，清飆在平楚。", "藏名向寵節，辭疾去公務。夜盡醉弦歌，日高臥煙樹。", "豈嗤生前樂，千載自垂裕。論道複論功，皆可黃金鑄。"]'),
('yuding-9','蠶女','司馬紮','唐','御定全唐诗','yuding','','[]','養蠶先養桑，蠶老人亦衰。苟無園中葉，安得機上絲。',72,'御定全唐詩/json/596.json','["養蠶先養桑，蠶老人亦衰。苟無園中葉，安得機上絲。", "妾家非豪門，官賦日相追。鳴梭夜達曉，猶恐不及時。", "但憂蠶與桑，敢問結髮期。東鄰女新嫁，照鏡弄蛾眉。"]'),
('yuding-10','效陶彭澤','司馬紮','唐','御定全唐诗','yuding','','[]','一夢倏已盡，百年如露草。獨有南山高，不與人共老。',72,'御定全唐詩/json/596.json','["一夢倏已盡，百年如露草。獨有南山高，不與人共老。", "尊中貯靈味，無事即醉倒。何必鳴鼓鐘，然後樂懷抱。", "輕波向海疾，浮雲歸穀早。形役良可嗟，唯能徇天道。"]'),
('yuding-11','鋤草怨','司馬紮','唐','御定全唐诗','yuding','','[]','種田望雨多，雨多長蓬蒿。亦念官賦急，寧知荷鋤勞。',96,'御定全唐詩/json/596.json','["種田望雨多，雨多長蓬蒿。亦念官賦急，寧知荷鋤勞。", "亭午霽日明，鄰翁醉陶陶。鄉吏不到門，禾黍苗自高。", "獨有辛苦者，屢為州縣徭。罷鋤田又廢，戀鄉不忍逃。", "出門吏相促，鄰家滿倉穀。鄰翁不可告，盡日向田哭。"]'),
('yuding-12','山中晚興寄裴侍禦','司馬紮','唐','御定全唐诗','yuding','','[]','雷息疏雨散，空山夏雲晴。南軒對林晚，籬落新蛩鳴。',72,'御定全唐詩/json/596.json','["雷息疏雨散，空山夏雲晴。南軒對林晚，籬落新蛩鳴。", "白酒一樽滿，坐歌天地清。十年身未閑，心在人間名。", "永懷君親恩，久賤難退情。安得蓬丘侶，提攜采瑤英。"]'),
('yuding-13','築台','司馬紮','唐','御定全唐诗','yuding','','[]','魏國昔強盛，宮中金玉多。征丁築層台，唯恐不巍峨。',108,'御定全唐詩/json/596.json','["魏國昔強盛，宮中金玉多。征丁築層台，唯恐不巍峨。", "結構切星漢，躋攀橫綺羅。朝觀細腰舞，夜聽皓齒歌。", "詎念人力勞，安問黍與禾。一朝國既傾，千仞堂亦平。", "舞模衰柳影，歌留草蟲聲。月照白露寒，蒼蒼故鄴城。", "漢文有遺美，對此清飆生。"]'),
('yuding-14','道中早發','司馬紮','唐','御定全唐诗','yuding','','[]','野店雞一聲，蕭蕭客車動。西峰帶曉月，十裏猶相送。',72,'御定全唐詩/json/596.json','["野店雞一聲，蕭蕭客車動。西峰帶曉月，十裏猶相送。", "繁弦滿長道，羸馬四蹄重。遙羨青樓人，錦衾方遠夢。", "功名不我與，孤劍何所用。行役難自休，家山憶秋洞。"]'),
('yuding-15','滄浪峽','司馬紮','唐','御定全唐诗','yuding','','[]','山下水聲深，水邊山色聚。月照秋自清，花名春不去。',72,'御定全唐詩/json/596.json','["山下水聲深，水邊山色聚。月照秋自清，花名春不去。", "似非人間境，又近紅塵路。乍入洞中天，更移雲外步。", "我殊惺惺者，猶得滄浪趣。可以濯吾纓，斯言誠所慕。"]'),
('yuding-16','感螢','司馬紮','唐','御定全唐诗','yuding','','[]','愛爾持照書，臨書歎吾道。青熒一點光，曾誤幾人老。',36,'御定全唐詩/json/596.json','["愛爾持照書，臨書歎吾道。青熒一點光，曾誤幾人老。", "夜久獨此心，環垣閉秋草。"]'),
('yuding-17','自渭南晚次華州','司馬紮','唐','御定全唐诗','yuding','','[]','前樓仙鼎原，西經赤水渡。火雲入村巷，餘雨依驛樹。',96,'御定全唐詩/json/596.json','["前樓仙鼎原，西經赤水渡。火雲入村巷，餘雨依驛樹。", "我行傷去國，疲馬屢回顧。有如無窠鳥，觸熱不得住。", "峨峨華峰近，城郭生夕霧。逆旅何人尋，行客暗中住。", "卻思林丘臥，自愜平生素。勞役今若茲，羞吟招隱句。"]'),
('yuding-18','近別','司馬紮','唐','御定全唐诗','yuding','','[]','咫尺不相見，便同天一涯。何必隔關山，乃言傷別離。',48,'御定全唐詩/json/596.json','["咫尺不相見，便同天一涯。何必隔關山，乃言傷別離。", "君心與我心，脈脈無由知。誰堪近別苦，遠別猶有期。"]'),
('yuding-19','江上秋夕','司馬紮','唐','御定全唐诗','yuding','','[]','茂陵歸路絕，誰念此淹留。極目月沈浦，苦吟霜滿舟。',48,'御定全唐詩/json/596.json','["茂陵歸路絕，誰念此淹留。極目月沈浦，苦吟霜滿舟。", "孤猿啼後夜，久客病高秋。欲寄鄉關恨，寒江無北流。"]'),
('yuding-20','送歸客','司馬紮','唐','御定全唐诗','yuding','','[]','多才與命違，末路隱柴扉。白髮何人問，青山一劍歸。',48,'御定全唐詩/json/596.json','["多才與命違，末路隱柴扉。白髮何人問，青山一劍歸。", "晴煙獨鳥沒，野渡亂花飛。寂寞長亭外，依然空落暉。"]'),
('yuding-21','東門晚望','司馬紮','唐','御定全唐诗','yuding','','[]','青門聊極望，何事久離群。芳草失歸路，故鄉空暮雲。',48,'御定全唐詩/json/596.json','["青門聊極望，何事久離群。芳草失歸路，故鄉空暮雲。", "信回陵樹老，夢斷灞流分。兄弟正南北，鴻聲堪獨聞。"]'),
('yuding-22','上巳日曲江有感','司馬紮','唐','御定全唐诗','yuding','','[]','萬花明曲水，車馬動秦川。此日不得意，青春徒少年。',48,'御定全唐詩/json/596.json','["萬花明曲水，車馬動秦川。此日不得意，青春徒少年。", "晴沙下鷗鷺，幽沚生蘭荃。向晚積歸念，江湖心渺然。"]'),
('yuding-23','宿壽安甘棠館','司馬紮','唐','御定全唐诗','yuding','','[]','行人方倦役，到此似還鄉。流水來關外，青山近洛陽。',48,'御定全唐詩/json/596.json','["行人方倦役，到此似還鄉。流水來關外，青山近洛陽。", "溪雲歸洞鶴，松月半軒霜。坐恐晨鐘動，天涯道路長。"]'),
('yuding-24','送友人下第東游','司馬紮','唐','御定全唐诗','yuding','','[]','出門皆有托，君去獨何親。闕下新交少，天涯舊業貧。',48,'御定全唐詩/json/596.json','["出門皆有托，君去獨何親。闕下新交少，天涯舊業貧。", "煙寒嶽樹暝，雪後嶺梅春。聖代留昆玉，那令愧郤詵。"]'),
('yuding-25','山齋會別','司馬紮','唐','御定全唐诗','yuding','','[]','春草平陵路，荷衣醉別離。將尋洛陽友，共結洞庭期。',48,'御定全唐詩/json/596.json','["春草平陵路，荷衣醉別離。將尋洛陽友，共結洞庭期。", "星月半山盡，天雞出海遲。無輕此分手，他日重相思。"]'),
('yuding-26','曉過伊水寄龍門僧','司馬紮','唐','御定全唐诗','yuding','','[]','龍門樹色暗蒼蒼，伊水東流客恨長。病馬獨嘶殘夜月，',40,'御定全唐詩/json/596.json','["龍門樹色暗蒼蒼，伊水東流客恨長。病馬獨嘶殘夜月，", "山下禪庵老師在，願將形役問空王。"]'),
('yuding-27','送孔恂入洛','司馬紮','唐','御定全唐诗','yuding','','[]','洛陽古城秋色多，送君此去心如何。青山欲暮惜別酒，',40,'御定全唐詩/json/596.json','["洛陽古城秋色多，送君此去心如何。青山欲暮惜別酒，", "行人正苦奈分手，日落遠水生微波。"]'),
('yuding-28','觀郊禮','司馬紮','唐','御定全唐诗','yuding','','[]','鐘鼓旌旗引六飛，玉皇初著畫龍衣。',32,'御定全唐詩/json/596.json','["鐘鼓旌旗引六飛，玉皇初著畫龍衣。", "泰壇煙盡星河曉，萬國心隨彩仗歸。"]'),
('yuding-29','宮怨','司馬紮','唐','御定全唐诗','yuding','','[]','柳色參差掩畫樓，曉鶯啼送滿宮愁。',32,'御定全唐詩/json/596.json','["柳色參差掩畫樓，曉鶯啼送滿宮愁。", "年年花落無人見，空逐春泉出禦溝。"]'),
('yuding-30','南徐夕眺','司馬紮','唐','御定全唐诗','yuding','','[]','行吟向暮天，何處不淒然。岸影幾家柳，笛聲何處船。',48,'御定全唐詩/json/596.json','["行吟向暮天，何處不淒然。岸影幾家柳，笛聲何處船。", "樓分瓜步月，鳥入秣陵煙。故里無人到，鄉書誰為傳。"]'),
('yuding-31','題清上人','司馬紮','唐','御定全唐诗','yuding','','[]','古院閉松色，入門人自閑。罷經來宿鳥，支策對秋山。',48,'御定全唐詩/json/596.json','["古院閉松色，入門人自閑。罷經來宿鳥，支策對秋山。", "客念蓬梗外，禪心煙霧間。空憐濯纓處，階下水潺潺。"]'),
('yuding-32','塗中寄薛中裕','司馬紮','唐','御定全唐诗','yuding','','[]','貧交千裏外，失路更傷離。曉淚芳草盡，夜魂明月知。',48,'御定全唐詩/json/596.json','["貧交千裏外，失路更傷離。曉淚芳草盡，夜魂明月知。", "空山連野外，寒鳥下霜枝。此景正寥落，為君玄發衰。"]'),
('yuding-33','白馬津阻雨','司馬紮','唐','御定全唐诗','yuding','','[]','津樹蕭蕭旅館空，坐看疏葉繞階紅。故鄉千里楚雲外，',40,'御定全唐詩/json/596.json','["津樹蕭蕭旅館空，坐看疏葉繞階紅。故鄉千里楚雲外，", "功名倘遂身無事，終向溪頭伴釣翁。"]'),
('yuding-34','秋日懷儲嗣宗','司馬紮','唐','御定全唐诗','yuding','','[]','故人北游久不回，塞雁南渡聲何哀。',32,'御定全唐詩/json/596.json','["故人北游久不回，塞雁南渡聲何哀。", "相思聞雁更惆悵，卻向單于台下來。"]'),
('yuding-35','夜聽李山人彈琴','司馬紮','唐','御定全唐诗','yuding','','[]','瑤琴夜久弦秋清，楚客一奏湘煙生。',32,'御定全唐詩/json/596.json','["瑤琴夜久弦秋清，楚客一奏湘煙生。", "曲中聲盡意不盡，月照竹軒紅葉明。"]'),
('yuding-36','隱者','司馬紮','唐','御定全唐诗','yuding','','[]','松間開一徑，秋草自相依。終日不冠帶，空山無是非。',48,'御定全唐詩/json/596.json','["松間開一徑，秋草自相依。終日不冠帶，空山無是非。", "投綸溪鳥伴，曝藥穀雲飛。時向鄰家去，狂歌夜醉歸。"]'),
('yuding-37','登河中鸛雀樓','司馬紮','唐','御定全唐诗','yuding','','[]','樓中見千里，樓影入通津。煙樹遙分陝，山河曲向秦。',48,'御定全唐詩/json/596.json','["樓中見千里，樓影入通津。煙樹遙分陝，山河曲向秦。", "興亡留白日，今古共紅塵。鸛雀飛何處，城隅草自春。"]'),
('yuding-38','漾陂晚望','司馬紮','唐','御定全唐诗','yuding','','[]','遠客家水國，此來如到鄉。何人垂白髮，一葉釣殘陽。',48,'御定全唐詩/json/596.json','["遠客家水國，此來如到鄉。何人垂白髮，一葉釣殘陽。", "柳暗鳥乍起，渚深蘭自芳。因知帝城下，有路向滄浪。"]'),
('yuding-0','賀襄陽副使節判同加章綬','徐商','唐','御定全唐诗','yuding','','[]','朱紫花前賀故人，兼榮此會頗關身。同年坐上聯賓榻，',40,'御定全唐詩/json/597.json','["朱紫花前賀故人，兼榮此會頗關身。同年坐上聯賓榻，", "芳菲解助今朝喜，嫩蕊青條滿眼新。"]'),
('yuding-1','句','徐商','唐','御定全唐诗','yuding','','[]','萍聚只因今日浪，荻斜都為夜來風。',16,'御定全唐詩/json/597.json','["萍聚只因今日浪，荻斜都為夜來風。"]'),
('yuding-2','和薛逢贈別','高璩','唐','御定全唐诗','yuding','','[]','劍外綿州第一州，尊前偏喜接君留。歌聲婉轉添長恨，',40,'御定全唐詩/json/597.json','["劍外綿州第一州，尊前偏喜接君留。歌聲婉轉添長恨，", "莫言此去難相見，怨別征黃是順流。"]'),
('yuding-3','句','高璩','唐','御定全唐诗','yuding','','[]','公齋一到人非舊，詩板重尋墨尚新。',16,'御定全唐詩/json/597.json','["公齋一到人非舊，詩板重尋墨尚新。"]'),
('yuding-4','和李尚書命妓餞崔侍禦','高湘','唐','御定全唐诗','yuding','','[]','謝安春渚餞袁宏，千里仁風一扇清。',32,'御定全唐詩/json/597.json','["謝安春渚餞袁宏，千里仁風一扇清。", "歌黛慘時方酩酊，不知公子重飛觥。"]'),
('yuding-5','句','高湘','唐','御定全唐诗','yuding','','[]','惟有高州是當家。（《玉泉子》雲：湘從兄中書舍人湜',70,'御定全唐詩/json/597.json','["惟有高州是當家。（《玉泉子》雲：湘從兄中書舍人湜", "與路相岩親善，而湘厚劉相瞻，岩既逐瞻，除不附己者", "十司戶。湘得高州，到日，憤湜不佑己，賦詩雲）"]'),
('yuding-6','報何澤','崔安潛','唐','御定全唐诗','yuding','','[]','四十九年前及第，同年唯有老夫存。',32,'御定全唐詩/json/597.json','["四十九年前及第，同年唯有老夫存。", "今日殷勤訪吾子，穩將鬐鬣上龍門。"]'),
('yuding-7','題文翁石室','裴鉶','唐','御定全唐诗','yuding','','[]','文翁石室有儀形，庠序千秋播德馨。古柏尚留今日翠，',40,'御定全唐詩/json/597.json','["文翁石室有儀形，庠序千秋播德馨。古柏尚留今日翠，", "更歎沱江無限水，爭流只願到滄溟。"]'),
('yuding-8','憤惋詩三首','劉損','唐','御定全唐诗','yuding','','[]','寶釵分股合無緣，魚在深淵日在天。得意紫鸞休舞鏡，',120,'御定全唐詩/json/597.json','["寶釵分股合無緣，魚在深淵日在天。得意紫鸞休舞鏡，", "從此蘼蕪山下過，只應將淚比黃泉。", "鸞辭舊伴知何止，鳳得新梧想稱心。紅粉尚存香幕幕，", "願作山頭似人石，丈夫衣上淚痕深。", "舊嘗遊處遍尋看，睹物傷情死一般。買笑樓前花已謝，", "莫道詩成無淚下，淚如泉滴亦須幹。"]'),
('yuding-9','幼作','鄭愚','唐','御定全唐诗','yuding','','[]','臺山初罷霧，岐海正分流。漁浦颺來笛，鴻逵翼去舟。',24,'御定全唐詩/json/597.json','["臺山初罷霧，岐海正分流。漁浦颺來笛，鴻逵翼去舟。"]'),
('yuding-10','茶詩','鄭愚','唐','御定全唐诗','yuding','','[]','嫩芽香且靈，吾謂草中英。夜臼和煙搗，寒爐對雪烹。',36,'御定全唐詩/json/597.json','["嫩芽香且靈，吾謂草中英。夜臼和煙搗，寒爐對雪烹。", "惟憂碧粉散，嘗見綠花生。"]'),
('yuding-11','郡樓望九華歌','霍總','唐','御定全唐诗','yuding','','[]','樓上坐見九子峰，翠雲赤日光溶溶。有時朝昏變疏密，',64,'御定全唐詩/json/597.json','["樓上坐見九子峰，翠雲赤日光溶溶。有時朝昏變疏密，", "陽烏生子偶成數，丹鳳養雛同此名。日日遙看機已靜，", "玉漿瑤草不可見，自有神仙風馬來。"]'),
('yuding-12','塞下曲','霍總','唐','御定全唐诗','yuding','','[]','曾當一面戰，頻出九重圍。但見爭鋒處，長須得勝歸。',48,'御定全唐詩/json/597.json','["曾當一面戰，頻出九重圍。但見爭鋒處，長須得勝歸。", "雪沾旗尾落，風斷節毛稀。豈要銘燕石，平生重武威。"]'),
('yuding-13','關山月','霍總','唐','御定全唐诗','yuding','','[]','珠瓏翡翠床，白皙侍中郎。五日來花下，雙童問道傍。',48,'御定全唐詩/json/597.json','["珠瓏翡翠床，白皙侍中郎。五日來花下，雙童問道傍。", "到門車馬狹，連夜管弦長。每笑東家子，窺他宋玉牆。"]'),
('yuding-14','驄馬','霍總','唐','御定全唐诗','yuding','','[]','青驪八尺高，俠客倚雄豪。踏雪生珠汗，障泥護錦袍。',48,'御定全唐詩/json/597.json','["青驪八尺高，俠客倚雄豪。踏雪生珠汗，障泥護錦袍。", "路傍看驟影，鞍底卷旋毛。豈獨連錢貴，酬恩更代勞。"]'),
('yuding-15','雉朝飛','霍總','唐','御定全唐诗','yuding','','[]','五色有名翬，清晨挾兩雌。群群飛自樂，步步飲相隨。',48,'御定全唐詩/json/597.json','["五色有名翬，清晨挾兩雌。群群飛自樂，步步飲相隨。", "覘葉逢人處，驚媒妒寵時。綠毛春鬥盡，強敵願君知。"]'),
('yuding-16','木芙蓉','霍總','唐','御定全唐诗','yuding','','[]','本自江湖遠，常開霜露餘。爭春候穠李，得水異紅蕖。',48,'御定全唐詩/json/597.json','["本自江湖遠，常開霜露餘。爭春候穠李，得水異紅蕖。", "孤秀曾無偶，當門幸不鋤。誰能政搖落，繁彩照階除。"]'),
('yuding-17','採蓮女','霍總','唐','御定全唐诗','yuding','','[]','舟中採蓮女，兩兩催妝梳。聞早渡江去，日高來起居。',24,'御定全唐詩/json/597.json','["舟中採蓮女，兩兩催妝梳。聞早渡江去，日高來起居。"]'),
('yuding-18','別僧','陳琡','唐','御定全唐诗','yuding','','[]','行若獨輪車，常畏大道覆。止若員底器，常恐他物觸。',36,'御定全唐詩/json/597.json','["行若獨輪車，常畏大道覆。止若員底器，常恐他物觸。", "行止既如此，安得不離俗。"]'),
('yuding-19','早春殘雪','裴虔餘','唐','御定全唐诗','yuding','','[]','霽日雕瓊彩，幽庭減夜寒。梅飄餘片積，日墮晚光殘。',72,'御定全唐詩/json/597.json','["霽日雕瓊彩，幽庭減夜寒。梅飄餘片積，日墮晚光殘。", "零落偏依桂，霏微不掩蘭。陰林披霧縠，小沼破冰盤。", "曲檻霜凝砌，疏篁玉碎竿。已聞三徑好，猶可訪袁安。"]'),
('yuding-20','柳枝詞詠篙水濺妓衣','裴虔餘','唐','御定全唐诗','yuding','','[]','半額微黃金縷衣，玉搔頭嫋鳳雙飛。',32,'御定全唐詩/json/597.json','["半額微黃金縷衣，玉搔頭嫋鳳雙飛。", "從教水濺羅裙濕，還道朝來行雨歸。"]'),
('yuding-21','獻淮南師','李嶸','唐','御定全唐诗','yuding','','[]','雞樹煙含瑞氣凝，鳳池波待玉山澄。',32,'御定全唐詩/json/597.json','["雞樹煙含瑞氣凝，鳳池波待玉山澄。", "國人久倚東關望，擬築沙堤到廣陵。"]'),
('yuding-22','月','袁郊','唐','御定全唐诗','yuding','','[]','嫦娥竊藥出人間，藏在蟾宮不放還。',32,'御定全唐詩/json/597.json','["嫦娥竊藥出人間，藏在蟾宮不放還。", "後羿遍尋無覓處，誰知天上卻容奸。"]'),
('yuding-23','霜','袁郊','唐','御定全唐诗','yuding','','[]','古今何事不思量，盡信鄒生感彼蒼。',32,'御定全唐詩/json/597.json','["古今何事不思量，盡信鄒生感彼蒼。", "但想燕山吹暖律，炎天豈不解飛霜。"]'),
('yuding-24','露','袁郊','唐','御定全唐诗','yuding','','[]','湛湛騰空下碧霄，地卑濕處更偏饒。',32,'御定全唐詩/json/597.json','["湛湛騰空下碧霄，地卑濕處更偏饒。", "菅茅豐草皆沾潤，不道良田有旱苗。"]'),
('yuding-25','雲','袁郊','唐','御定全唐诗','yuding','','[]','楚甸嘗聞旱魃侵，從龍應合解為霖。',32,'御定全唐詩/json/597.json','["楚甸嘗聞旱魃侵，從龍應合解為霖。", "荒淫卻入陽臺夢，惑亂懷襄父子心。"]'),
('yuding-26','遊東觀山','張叢','唐','御定全唐诗','yuding','','[]','岩岫碧孱顏，靈蹤若可攀。樓臺煙靄外，松竹翠微間。',48,'御定全唐詩/json/597.json','["岩岫碧孱顏，靈蹤若可攀。樓臺煙靄外，松竹翠微間。", "玉液寒深洞，秋光秀遠山。憑君指歸路，何處是人寰。"]'),
('yuding-27','擲盧作','馮袞','唐','御定全唐诗','yuding','','[]','八尺台盤照面新，千金一擲鬥精神。',32,'御定全唐詩/json/597.json','["八尺台盤照面新，千金一擲鬥精神。", "合是賭時須賭取，不妨回首乞閒人。"]'),
('yuding-28','戲酒妓','馮袞','唐','御定全唐诗','yuding','','[]','醉眼從伊百度斜，是他家屬是他家。',32,'御定全唐詩/json/597.json','["醉眼從伊百度斜，是他家屬是他家。", "低聲向道人知也，隔坐剛拋豆蔻花。"]'),
('yuding-29','老僧','鄭綮','唐','御定全唐诗','yuding','','[]','日照四山雪，老僧門未開。凍瓶黏柱礎，宿火陷爐灰。',48,'御定全唐詩/json/597.json','["日照四山雪，老僧門未開。凍瓶黏柱礎，宿火陷爐灰。", "童子病歸去，鹿麑寒入來。齋鐘知漸近，枝鳥下生台。"]'),
('yuding-30','題盧州郡齋','鄭綮','唐','御定全唐诗','yuding','','[]','九衢塵裏一書生，多達逢時擁旆旌。',32,'御定全唐詩/json/597.json','["九衢塵裏一書生，多達逢時擁旆旌。", "醉裏眼開金使字，紫旗風動耀天明。"]'),
('yuding-31','別郡後寄席中三蘭','鄭綮','唐','御定全唐诗','yuding','','[]','淮淝兩水不相通，隔岸臨流望向東。',32,'御定全唐詩/json/597.json','["淮淝兩水不相通，隔岸臨流望向東。", "千顆淚珠無寄處，一時彈與渡前風。"]'),
('yuding-32','觀山燈獻徐尚書','溫庭皓','唐','御定全唐诗','yuding','','[]','一峰當勝地，萬點照嚴城。勢異昆岡發，光疑玄圃生。',144,'御定全唐詩/json/597.json','["一峰當勝地，萬點照嚴城。勢異昆岡發，光疑玄圃生。", "焚書翻見字，舉燧不招兵。況遇新春夜，何勞秉燭行。", "九枝應並耀，午夜忽潛然。景集青山外，螢分碧草前。", "輝華侵月影，曆亂寫星躔。望極高樓上，搖光滿綺筵。", "春山收暝色，爝火集餘輝。麗景饒紅焰，祥光出翠微。", "白榆行自比，青桂影相依。唯有偷光客，追遊欲忘歸。"]'),
('yuding-33','梅','溫庭皓','唐','御定全唐诗','yuding','','[]','一樹寒林外，何人此地栽。春光先自暖，陽豔暗相催。',96,'御定全唐詩/json/597.json','["一樹寒林外，何人此地栽。春光先自暖，陽豔暗相催。", "曉覺霜添白，寒迷月借開。餘香低惹袖，墮蕊逐流杯。", "零落移新暖，飄颺上故台。雪繁鶯不識，風嫋蝶空回。", "羌吹應愁起，征徒異渴來。莫貪題詠興，商鼎待鹽梅。"]'),
('yuding-0','言懷','高駢','唐','御定全唐诗','yuding','','[]','恨乏平戎策，慚登拜將壇。手持金鉞冷，身掛鐵衣寒。',48,'御定全唐詩/json/598.json','["恨乏平戎策，慚登拜將壇。手持金鉞冷，身掛鐵衣寒。", "主聖扶持易，恩深報效難。三邊猶未靜，何敢便休官。"]'),
('yuding-1','寄鄠杜李遂良處士','高駢','唐','御定全唐诗','yuding','','[]','小隱堪忘世上情，可能休夢入重城。池邊寫字師前輩，',40,'御定全唐詩/json/598.json','["小隱堪忘世上情，可能休夢入重城。池邊寫字師前輩，", "春來不得山中信，盡日無人傍水行。"]'),
('yuding-2','和王昭符進士贈洞庭趙先生','高駢','唐','御定全唐诗','yuding','','[]','為愛君山景最靈，角冠秋禮一壇星。藥將雞犬雲間試，',40,'御定全唐詩/json/598.json','["為愛君山景最靈，角冠秋禮一壇星。藥將雞犬雲間試，", "煙霞淡泊無人到，唯有漁翁過洞庭。"]'),
('yuding-3','依韻奉酬李迪','高駢','唐','御定全唐诗','yuding','','[]','柳下官資顏子居，閒情入骨若為除。詩成斬將奇難敵，',40,'御定全唐詩/json/598.json','["柳下官資顏子居，閒情入骨若為除。詩成斬將奇難敵，", "而今共飲醇滋味，消得揶揄勢利疏。"]'),
('yuding-4','留別彰德軍從事範校書','高駢','唐','御定全唐诗','yuding','','[]','無金寄與白頭親，節概猶誇似古人。未出塵埃真落魄，',40,'御定全唐詩/json/598.json','["無金寄與白頭親，節概猶誇似古人。未出塵埃真落魄，", "匹馬東歸羨知己，燕王臺上結交新。"]'),
('yuding-5','途次內黃馬病，寄僧舍呈諸友人','高駢','唐','御定全唐诗','yuding','','[]','官閑馬病客深秋，肯學張衡詠四愁。紅葉寺多詩景致，',40,'御定全唐詩/json/598.json','["官閑馬病客深秋，肯學張衡詠四愁。紅葉寺多詩景致，", "好與高陽結吟社，況無名跡達珠旒。"]'),
('yuding-6','遣興','高駢','唐','御定全唐诗','yuding','','[]','浮世忙忙蟻子群，莫嗔頭上雪紛紛。沈憂萬種與千種，',40,'御定全唐詩/json/598.json','["浮世忙忙蟻子群，莫嗔頭上雪紛紛。沈憂萬種與千種，", "醉鄉日月終須覓，去作先生號白雲。"]'),
('yuding-7','南海神祠','高駢','唐','御定全唐诗','yuding','','[]','滄溟八千里，今古畏波濤。此日征南將，安然渡萬艘。',24,'御定全唐詩/json/598.json','["滄溟八千里，今古畏波濤。此日征南將，安然渡萬艘。"]'),
('yuding-8','送春','高駢','唐','御定全唐诗','yuding','','[]','水淺魚爭躍，花深鳥競啼。春光看欲盡，判卻醉如泥。',24,'御定全唐詩/json/598.json','["水淺魚爭躍，花深鳥競啼。春光看欲盡，判卻醉如泥。"]'),
('yuding-9','海翻','高駢','唐','御定全唐诗','yuding','','[]','幾經人事變，又見海濤翻。徒起如山浪，何曾洗至冤。',24,'御定全唐詩/json/598.json','["幾經人事變，又見海濤翻。徒起如山浪，何曾洗至冤。"]'),
('yuding-10','筇竹杖寄僧','高駢','唐','御定全唐诗','yuding','','[]','堅輕筇竹杖，一枝有九節。寄與沃洲人，閒步青山月。',24,'御定全唐詩/json/598.json','["堅輕筇竹杖，一枝有九節。寄與沃洲人，閒步青山月。"]'),
('yuding-11','遣興','高駢','唐','御定全唐诗','yuding','','[]','把盞非憐酒，持竿不為魚。唯應嵇叔夜，似我性慵疏。',24,'御定全唐詩/json/598.json','["把盞非憐酒，持竿不為魚。唯應嵇叔夜，似我性慵疏。"]'),
('yuding-12','歎征人','高駢','唐','御定全唐诗','yuding','','[]','心堅膽壯箭頭親，十載沙場受苦辛。',32,'御定全唐詩/json/598.json','["心堅膽壯箭頭親，十載沙場受苦辛。", "力盡路傍行不得，廣張紅旆是何人。"]'),
('yuding-13','湘妃廟','高駢','唐','御定全唐诗','yuding','','[]','帝舜南巡去不還，二妃幽怨水雲間。',32,'御定全唐詩/json/598.json','["帝舜南巡去不還，二妃幽怨水雲間。", "當時珠淚垂多少，直到如今竹尚斑。"]'),
('yuding-14','赴安南卻寄台司','高駢','唐','御定全唐诗','yuding','','[]','曾驅萬馬上天山，風去雲回頃刻間。',32,'御定全唐詩/json/598.json','["曾驅萬馬上天山，風去雲回頃刻間。", "今日海門南面事，莫教還似鳳林關。"]'),
('yuding-15','閨怨','高駢','唐','御定全唐诗','yuding','','[]','人世悲歡不可知，夫君初破黑山歸。',32,'御定全唐詩/json/598.json','["人世悲歡不可知，夫君初破黑山歸。", "如今又獻征南策，早晚催縫帶號衣。"]'),
('yuding-16','馬嵬驛','高駢','唐','御定全唐诗','yuding','','[]','玉顏雖掩馬嵬塵，冤氣和煙鎖渭津。',32,'御定全唐詩/json/598.json','["玉顏雖掩馬嵬塵，冤氣和煙鎖渭津。", "蟬鬢不隨鑾駕去，至今空感往來人。"]'),
('yuding-17','宴犒蕃軍有感','高駢','唐','御定全唐诗','yuding','','[]','蜀地恩留馬嵬哭，煙雨濛濛春草綠。',32,'御定全唐詩/json/598.json','["蜀地恩留馬嵬哭，煙雨濛濛春草綠。", "滿眼由來是舊人，那堪更奏梁州曲。"]'),
('yuding-18','寓懷','高駢','唐','御定全唐诗','yuding','','[]','關山萬里恨難銷，鐵馬金鞭出塞遙。',32,'御定全唐詩/json/598.json','["關山萬里恨難銷，鐵馬金鞭出塞遙。", "為問昔時青海畔，幾人歸到鳳林橋。"]'),
('yuding-19','步虛詞','高駢','唐','御定全唐诗','yuding','','[]','青溪道士人不識，上天下天鶴一隻。',32,'御定全唐詩/json/598.json','["青溪道士人不識，上天下天鶴一隻。", "洞門深鎖碧窗寒，滴露研朱點周易。"]'),
('yuding-20','贈歌者二首','高駢','唐','御定全唐诗','yuding','','[]','酒滿金船花滿枝，佳人立唱慘愁眉。',64,'御定全唐詩/json/598.json','["酒滿金船花滿枝，佳人立唱慘愁眉。", "一聲直入青雲去，多少悲歡起此時。", "公子邀歡月滿樓，雙成揭調唱伊州。", "便從席上風沙起，直到陽關水盡頭。"]'),
('yuding-21','入蜀','高駢','唐','御定全唐诗','yuding','','[]','萬水千山音信希，空勞魂夢到京畿。',32,'御定全唐詩/json/598.json','["萬水千山音信希，空勞魂夢到京畿。", "漫天嶺上頻回首，不見虞封淚滿衣。"]'),
('yuding-22','邊城聽角','高駢','唐','御定全唐诗','yuding','','[]','席箕風起雁聲秋，隴水邊沙滿目愁。',32,'御定全唐詩/json/598.json','["席箕風起雁聲秋，隴水邊沙滿目愁。", "三會五更欲吹盡，不知凡白幾人頭。"]'),
('yuding-23','渭川秋望寄右軍王特進','高駢','唐','御定全唐诗','yuding','','[]','長川終日碧潺湲，知道天河與地連。',32,'御定全唐詩/json/598.json','["長川終日碧潺湲，知道天河與地連。", "憑寄兩行朝闕淚，願隨流入禦溝泉。"]'),
('yuding-24','山亭夏日','高駢','唐','御定全唐诗','yuding','','[]','綠樹陰濃夏日長，樓臺倒影入池塘。',32,'御定全唐詩/json/598.json','["綠樹陰濃夏日長，樓臺倒影入池塘。", "水精簾動微風起，滿架薔薇一院香。"]'),
('yuding-25','蜀路感懷','高駢','唐','御定全唐诗','yuding','','[]','蜀山蒼翠隴雲愁，鑾駕西巡陷幾州。',32,'御定全唐詩/json/598.json','["蜀山蒼翠隴雲愁，鑾駕西巡陷幾州。", "唯有縈回深澗水，潺湲不改舊時流。"]'),
('yuding-26','殘春遣興','高駢','唐','御定全唐诗','yuding','','[]','畫舸輕橈柳色新，摩訶池上醉青春。',32,'御定全唐詩/json/598.json','["畫舸輕橈柳色新，摩訶池上醉青春。", "不辭不為青春醉，只恐鶯花也怪人。"]'),
('yuding-27','春日招賓','高駢','唐','御定全唐诗','yuding','','[]','花枝如火酒如餳，正好狂歌醉複醒。',32,'御定全唐詩/json/598.json','["花枝如火酒如餳，正好狂歌醉複醒。", "對酒看花何處好，延和閣下碧筠亭。"]'),
('yuding-28','過天威徑','高駢','唐','御定全唐诗','yuding','','[]','豺狼坑盡卻朝天，戰馬休嘶瘴嶺煙。',32,'御定全唐詩/json/598.json','["豺狼坑盡卻朝天，戰馬休嘶瘴嶺煙。", "歸路嶮巇今坦蕩，一條千里直如弦。"]'),
('yuding-29','對花呈幕中','高駢','唐','御定全唐诗','yuding','','[]','海棠初發去春枝，首唱曾題七字詩。',32,'御定全唐詩/json/598.json','["海棠初發去春枝，首唱曾題七字詩。", "今日能來花下飲，不辭頻把使頭旗。"]'),
('yuding-30','寄題羅浮別業','高駢','唐','御定全唐诗','yuding','','[]','不將真性染埃塵，為有煙霞伴此身。',32,'御定全唐詩/json/598.json','["不將真性染埃塵，為有煙霞伴此身。", "帶日長江好歸信，博羅山下碧桃春。"]'),
('yuding-31','塞上曲二首','高駢','唐','御定全唐诗','yuding','','[]','二年邊戍絕煙塵，一曲河灣萬恨新。',64,'御定全唐詩/json/598.json','["二年邊戍絕煙塵，一曲河灣萬恨新。", "從此鳳林關外事，不知誰是苦心人。", "隴上征夫隴下魂，死生同恨漢將軍。", "不知萬里沙場苦，空舉平安火入雲。"]'),
('yuding-32','廣陵宴次戲簡幕賓','高駢','唐','御定全唐诗','yuding','','[]','一曲狂歌酒百分，蛾眉畫出月爭新。',32,'御定全唐詩/json/598.json','["一曲狂歌酒百分，蛾眉畫出月爭新。", "將軍醉罷無餘事，亂把花枝折贈人。"]'),
('yuding-33','安南送曹別敕歸朝','高駢','唐','御定全唐诗','yuding','','[]','雲水蒼茫日欲收，野煙深處鷓鴣愁。',32,'御定全唐詩/json/598.json','["雲水蒼茫日欲收，野煙深處鷓鴣愁。", "知君萬里朝天去，為說征南已五秋。"]'),
('yuding-34','對雪','高駢','唐','御定全唐诗','yuding','','[]','六出飛花入戶時，坐看青竹變瓊枝。',32,'御定全唐詩/json/598.json','["六出飛花入戶時，坐看青竹變瓊枝。", "如今好上高樓望，蓋盡人間惡路岐。"]'),
('yuding-35','訪隱者不遇','高駢','唐','御定全唐诗','yuding','','[]','落花流水認天臺，半醉閑吟獨自來。',32,'御定全唐詩/json/598.json','["落花流水認天臺，半醉閑吟獨自來。", "惆悵仙翁何處去，滿庭紅杏碧桃開。"]'),
('yuding-36','赴西川途經虢縣作','高駢','唐','御定全唐诗','yuding','','[]','亞夫重過柳營門，路指岷峨隔暮雲。',32,'御定全唐詩/json/598.json','["亞夫重過柳營門，路指岷峨隔暮雲。", "紅額少年遮道拜，殷勤認得舊將軍。"]'),
('yuding-37','錦城寫望','高駢','唐','御定全唐诗','yuding','','[]','蜀江波影碧悠悠，四望煙花匝郡樓。',32,'御定全唐詩/json/598.json','["蜀江波影碧悠悠，四望煙花匝郡樓。", "不會人家多少錦，春來盡掛樹梢頭。"]'),
('yuding-38','太公廟','高駢','唐','御定全唐诗','yuding','','[]','青山長在境長新，寂寞持竿一水濱。',32,'御定全唐詩/json/598.json','["青山長在境長新，寂寞持竿一水濱。", "及得王師身已老，不知辛苦為何人。"]'),
('yuding-39','邊方春興','高駢','唐','御定全唐诗','yuding','','[]','草色青青柳色濃，玉壺傾酒滿金鐘。',32,'御定全唐詩/json/598.json','["草色青青柳色濃，玉壺傾酒滿金鐘。", "笙歌嘹亮隨風去，知盡關山第幾重。"]'),
('yuding-40','塞上寄家兄','高駢','唐','御定全唐诗','yuding','','[]','棣萼分張信使希，幾多鄉淚濕征衣。',32,'御定全唐詩/json/598.json','["棣萼分張信使希，幾多鄉淚濕征衣。", "笳聲未斷腸先斷，萬里胡天鳥不飛。"]'),
('yuding-41','寫懷二首','高駢','唐','御定全唐诗','yuding','','[]','漁竿消日酒消愁，一醉忘情萬事休。',64,'御定全唐詩/json/598.json','["漁竿消日酒消愁，一醉忘情萬事休。", "卻恨韓彭興漢室，功成不向五湖遊。", "花滿西園月滿池，笙歌搖曳畫船移。", "如今暗與心相約，不動征旗動酒旗。"]'),
('yuding-42','池上送春','高駢','唐','御定全唐诗','yuding','','[]','持竿閑坐思沉吟，釣得江鱗出碧潯。',32,'御定全唐詩/json/598.json','["持竿閑坐思沉吟，釣得江鱗出碧潯。", "回首看花花欲盡，可憐寥落送春心。"]'),
('yuding-43','南征敘懷','高駢','唐','御定全唐诗','yuding','','[]','萬里驅兵過海門，此生今日報君恩。',32,'御定全唐詩/json/598.json','["萬里驅兵過海門，此生今日報君恩。", "回期直待烽煙靜，不遣征衣有淚痕。"]'),
('yuding-44','風箏','高駢','唐','御定全唐诗','yuding','','[]','夜靜弦聲響碧空，宮商信任往來風。',32,'御定全唐詩/json/598.json','["夜靜弦聲響碧空，宮商信任往來風。", "依稀似曲才堪聽，又被移將別調中。"]'),
('yuding-45','平流園席上','高駢','唐','御定全唐诗','yuding','','[]','畫舸搖煙水滿塘，柳絲輕軟小桃香。',32,'御定全唐詩/json/598.json','["畫舸搖煙水滿塘，柳絲輕軟小桃香。", "卻緣龍節為縈絆，好是狂時不得狂。"]'),
('yuding-46','聞河中王鐸加都統','高駢','唐','御定全唐诗','yuding','','[]','煉汞燒鉛四十年，至今猶在藥爐前。',32,'御定全唐詩/json/598.json','["煉汞燒鉛四十年，至今猶在藥爐前。", "不知子晉緣何事，只學吹簫便得仙。"]'),
('yuding-47','句','高駢','唐','御定全唐诗','yuding','','[]','人間無限傷心事，不得尊前折一枝。',64,'御定全唐詩/json/598.json','["人間無限傷心事，不得尊前折一枝。", "滿宮多少承恩者，似有容華妾也無。", "滿身珠翠將何用，唯與豪家拂象床。", "何人種得西施花，千古春風開不盡。"]'),
('yuding-0','青樓曲','於濆','唐','御定全唐诗','yuding','','[]','青樓臨大道，一上一回老。所思終不來，極目傷春草。',24,'御定全唐詩/json/599.json','["青樓臨大道，一上一回老。所思終不來，極目傷春草。"]'),
('yuding-1','塞下曲','於濆','唐','御定全唐诗','yuding','','[]','紫塞曉屯兵，黃沙披甲臥。戰鼓聲未齊，烏鳶已相賀。',48,'御定全唐詩/json/599.json','["紫塞曉屯兵，黃沙披甲臥。戰鼓聲未齊，烏鳶已相賀。", "燕然山上雲，半是離鄉魂。衛霍待富貴，豈能無乾坤。"]'),
('yuding-2','山村曉思','於濆','唐','御定全唐诗','yuding','','[]','開門省禾黍，鄰翁水頭住。今朝南澗波，昨夜西川雨。',48,'御定全唐詩/json/599.json','["開門省禾黍，鄰翁水頭住。今朝南澗波，昨夜西川雨。", "牧童披短蓑，腰笛期煙渚。不問水邊人，騎牛傍山去。"]'),
('yuding-3','馬嵬驛','于濆','唐','御定全唐诗','yuding','','[]','常經馬嵬驛，見說坡前客。一從屠貴妃，生女愁傾國。',48,'御定全唐詩/json/599.json','["常經馬嵬驛，見說坡前客。一從屠貴妃，生女愁傾國。", "是日芙蓉花，不如秋草色。當時嫁匹夫，不妨得頭白。"]'),
('yuding-4','苦辛吟','於濆','唐','御定全唐诗','yuding','','[]','壟上扶犁兒，手種腹長饑。窗下拋梭女，手織身無衣。',48,'御定全唐詩/json/599.json','["壟上扶犁兒，手種腹長饑。窗下拋梭女，手織身無衣。", "我願燕趙姝，化為嫫母姿。一笑不值錢，自然家國肥。"]'),
('yuding-5','野蠶','於濆','唐','御定全唐诗','yuding','','[]','野蠶食青桑，吐絲亦成繭。無功及生人，何異偷飽暖。',36,'御定全唐詩/json/599.json','["野蠶食青桑，吐絲亦成繭。無功及生人，何異偷飽暖。", "我願均爾絲，化為寒者衣。"]'),
('yuding-6','秦原覽古','於濆','唐','御定全唐诗','yuding','','[]','耕者戮力地，龍虎曾角逐。火德道將亨，夜逢蛇母哭。',72,'御定全唐詩/json/599.json','["耕者戮力地，龍虎曾角逐。火德道將亨，夜逢蛇母哭。", "昔日望夷宮，是處尋桑穀。漢祖竟為龍，趙高徒指鹿。", "當時行路人，已合傷心目。漢祚又千年，秦原草還綠。"]'),
('yuding-7','古宴曲','於濆','唐','御定全唐诗','yuding','','[]','雉扇合蓬萊，朝車回紫陌。重門集嘶馬，言宴金張宅。',72,'御定全唐詩/json/599.json','["雉扇合蓬萊，朝車回紫陌。重門集嘶馬，言宴金張宅。", "燕娥奉卮酒，低鬟若無力。十戶手胼胝，鳳凰釵一隻。", "高樓齊下視，日照羅衣色。笑指負薪人，不信生中國。"]'),
('yuding-8','南越謠','於濆','唐','御定全唐诗','yuding','','[]','迢迢東南天，巨浸無津壖。雄風卷昏霧，干戈滿樓船。',72,'御定全唐詩/json/599.json','["迢迢東南天，巨浸無津壖。雄風卷昏霧，干戈滿樓船。", "此時尉佗心，兒童待幽燕。三寸陸賈舌，萬里漢山川。", "若令交趾貨，盡生虞芮田。天意苟如此，遐人誰肯憐。"]'),
('yuding-9','述己歎','於濆','唐','御定全唐诗','yuding','','[]','不長不成人，及長老逼身。履善本求樂，及善尤苦辛。',36,'御定全唐詩/json/599.json','["不長不成人，及長老逼身。履善本求樂，及善尤苦辛。", "如何幽並兒，一箭取功勳。"]'),
('yuding-10','遼陽行','於濆','唐','御定全唐诗','yuding','','[]','遼陽在何處，妾欲隨君去。義合齊死生，本不誇機杼。',36,'御定全唐詩/json/599.json','["遼陽在何處，妾欲隨君去。義合齊死生，本不誇機杼。", "誰能守空閨，虛問遼陽路。"]'),
('yuding-11','旅館秋思','於濆','唐','御定全唐诗','yuding','','[]','旅館坐孤寂，出門成苦吟。何事覺歸晚，黃花秋意深。',48,'御定全唐詩/json/599.json','["旅館坐孤寂，出門成苦吟。何事覺歸晚，黃花秋意深。", "寒蝶戀衰草，軫我離鄉心。更見庭前樹，南枝巢宿禽。"]'),
('yuding-12','長城','于濆','唐','御定全唐诗','yuding','','[]','秦皇豈無德，蒙氏非不武。豈將版築功，萬里遮胡虜。',72,'御定全唐詩/json/599.json','["秦皇豈無德，蒙氏非不武。豈將版築功，萬里遮胡虜。", "團沙世所難，作壘明知苦。死者倍堪傷，僵屍猶抱杵。", "十年居上郡，四海誰為主。縱使骨為塵，冤名不入土。"]'),
('yuding-13','田翁歎','於濆','唐','御定全唐诗','yuding','','[]','手植千樹桑，文杏作中梁。頻年徭役重，盡屬富家郎。',72,'御定全唐詩/json/599.json','["手植千樹桑，文杏作中梁。頻年徭役重，盡屬富家郎。", "富家田業廣，用此買金章。昨日門前過，軒車滿垂楊。", "歸來說向家，兒孫竟咨嗟。不見千樹桑，一浦芙蓉花。"]'),
('yuding-14','沙場夜','於濆','唐','御定全唐诗','yuding','','[]','城上更聲發，城下杵聲歇。征人燒斷蓬，對泣沙中月。',72,'御定全唐詩/json/599.json','["城上更聲發，城下杵聲歇。征人燒斷蓬，對泣沙中月。", "耕牛朝挽甲，戰馬夜銜鐵。士卒浣戎衣，交河水為血。", "輕裘兩都客，洞房愁宿別。何況遠辭家，生死猶未決。"]'),
('yuding-15','裏中女','於濆','唐','御定全唐诗','yuding','','[]','吾聞池中魚，不識海水深。吾聞桑下女，不識華堂陰。',84,'御定全唐詩/json/599.json','["吾聞池中魚，不識海水深。吾聞桑下女，不識華堂陰。", "貧窗苦機杼，富家鳴杵砧。天與雙明眸，只教識蒿簪。", "徒惜越娃貌，亦蘊韓娥音。珠玉不到眼，遂無奢侈心。", "豈知趙飛燕，滿髻釵黃金。"]'),
('yuding-16','寒食','於濆','唐','御定全唐诗','yuding','','[]','二月野中芳，凡花亦能香。素娥哭新塚，樵柯鳴柔桑。',48,'御定全唐詩/json/599.json','["二月野中芳，凡花亦能香。素娥哭新塚，樵柯鳴柔桑。", "田父引黃犬，尋狐上高岡。墳前呼犬歸，不知頭似霜。"]'),
('yuding-17','邊遊錄戍卒言','於濆','唐','御定全唐诗','yuding','','[]','二十屬盧龍，三十防沙漠。平生愛功業，不覺從軍惡。',60,'御定全唐詩/json/599.json','["二十屬盧龍，三十防沙漠。平生愛功業，不覺從軍惡。", "今來客鬢改，知學彎弓錯。赤肉痛金瘡，他人成衛霍。", "目斷望君門，君門苦寥廓。"]'),
('yuding-18','古征戰','于濆','唐','御定全唐诗','yuding','','[]','高峰淩青冥，深穴萬丈坑。皇天自山谷，焉得人心平。',60,'御定全唐詩/json/599.json','["高峰淩青冥，深穴萬丈坑。皇天自山谷，焉得人心平。", "齊魯足兵甲，燕趙多娉婷。仍聞麗水中，日日黃金生。", "苟非夷齊心，豈得無戰爭。"]'),
('yuding-19','山村叟','于濆','唐','御定全唐诗','yuding','','[]','古鑿岩居人，一廛稱有產。雖沾巾覆形，不及貴門犬。',48,'御定全唐詩/json/599.json','["古鑿岩居人，一廛稱有產。雖沾巾覆形，不及貴門犬。", "驅牛耕白石，課女經黃繭。歲暮霜霰濃，畫樓人飽暖。"]'),
('yuding-20','戍客南歸','於濆','唐','御定全唐诗','yuding','','[]','北別黃榆塞，南歸白雲鄉。孤舟下彭蠡，楚月沈滄浪。',48,'御定全唐詩/json/599.json','["北別黃榆塞，南歸白雲鄉。孤舟下彭蠡，楚月沈滄浪。", "為子惜功業，滿身刀箭瘡。莫渡汨羅水，回君忠孝腸。"]'),
('yuding-21','經館娃宮','於濆','唐','御定全唐诗','yuding','','[]','館娃宮畔顧，國變生嬌妒。勾踐膽未嘗，夫差心已誤。',48,'御定全唐詩/json/599.json','["館娃宮畔顧，國變生嬌妒。勾踐膽未嘗，夫差心已誤。", "吳亡甘已矣，越勝今何處。當時二國君，一種江邊墓。"]'),
('yuding-22','村居晏起','於濆','唐','御定全唐诗','yuding','','[]','村舍少聞事，日高猶閉關。起來花滿地，戴勝鳴桑間。',48,'御定全唐詩/json/599.json','["村舍少聞事，日高猶閉關。起來花滿地，戴勝鳴桑間。", "居安即永業，何者為故山。朱門與蓬戶，六十頭盡斑。"]'),
('yuding-23','感懷','於濆','唐','御定全唐诗','yuding','','[]','采薇易為山，何必登首陽。濯纓易為水，何必泛滄浪。',48,'御定全唐詩/json/599.json','["采薇易為山，何必登首陽。濯纓易為水，何必泛滄浪。", "貴崇已難慕，諂笑何所長。東堂桂欲空，猶有收螢光。"]'),
('yuding-24','金穀感懷','于濆','唐','御定全唐诗','yuding','','[]','黃金驕石崇，與晉爭國力。更欲住人間，一日買不得。',48,'御定全唐詩/json/599.json','["黃金驕石崇，與晉爭國力。更欲住人間，一日買不得。", "行為忠信主，身是文章宅。四者俱不聞，空傳墮樓客。"]'),
('yuding-25','恨從軍','於濆','唐','御定全唐诗','yuding','','[]','不嫁白衫兒，愛君新紫衣。早知遽相別，何用假光輝。',48,'御定全唐詩/json/599.json','["不嫁白衫兒，愛君新紫衣。早知遽相別，何用假光輝。", "已聞都萬騎，又道出重圍。一軸金裝字，致君終不歸。"]'),
('yuding-26','燒金曲','於濆','唐','御定全唐诗','yuding','','[]','天壽畏不永，燒金希長年。積土培枯根，自謂松柏堅。',48,'御定全唐詩/json/599.json','["天壽畏不永，燒金希長年。積土培枯根，自謂松柏堅。", "南陌試腰褭，西樓歌嬋娟。豈知蔓草中，日日開夜泉。"]'),
('yuding-27','子從軍','於濆','唐','御定全唐诗','yuding','','[]','男作鄉中丁，女作鄉男婦。南村與北裏，日日見父母。',48,'御定全唐詩/json/599.json','["男作鄉中丁，女作鄉男婦。南村與北裏，日日見父母。", "豈似從軍兒，一去便白首。何當鑄劍戟，盡得丁男力。"]'),
('yuding-28','越溪女','於濆','唐','御定全唐诗','yuding','','[]','會稽山上雲，化作越溪人。枉破吳王國，徒為西子身。',72,'御定全唐詩/json/599.json','["會稽山上雲，化作越溪人。枉破吳王國，徒為西子身。", "江邊浣紗伴，黃金扼雙腕。倏忽不相期，思傾趙飛燕。", "妾家基業薄，空有如花面。嫁盡綠窗人，獨自盤金線。"]'),
('yuding-29','巫山高','于濆','唐','御定全唐诗','yuding','','[]','何山無朝雲，彼雲亦悠揚。何山無暮雨，彼雨亦蒼茫。',60,'御定全唐詩/json/599.json','["何山無朝雲，彼雲亦悠揚。何山無暮雨，彼雨亦蒼茫。", "宋玉恃才者，恁虛構高唐。自垂文賦名，荒淫歸楚襄。", "峨峨十二峰，永作妖鬼鄉。"]'),
('yuding-30','織素謠','於濆','唐','御定全唐诗','yuding','','[]','貧女苦筋力，繰絲夜夜織。萬梭為一素，世重韓娥色。',60,'御定全唐詩/json/599.json','["貧女苦筋力，繰絲夜夜織。萬梭為一素，世重韓娥色。", "五侯初買笑，建章方落籍。一曲古涼州，六親長血食。", "勸爾畫長眉，學歌飽親戚。"]'),
('yuding-31','擬古諷','於濆','唐','御定全唐诗','yuding','','[]','洛陽大道傍，甲第何深邃。南畝無一廛，東園有餘地。',72,'御定全唐詩/json/599.json','["洛陽大道傍，甲第何深邃。南畝無一廛，東園有餘地。", "春溪化桃李，秋沼生荷芰。草木本無情，此時如有為。", "旱苗當壟死，流水資嘉致。余心甘至愚，不會皇天意。"]'),
('yuding-32','贈太行開路者','於濆','唐','御定全唐诗','yuding','','[]','手劚太行山，心齊太行巔。劚盡太行險，君心更摩天。',36,'御定全唐詩/json/599.json','["手劚太行山，心齊太行巔。劚盡太行險，君心更摩天。", "何如回苦辛，自鑿東皋田。"]'),
('yuding-33','戍卒傷春','于濆','唐','御定全唐诗','yuding','','[]','連年戍邊塞，過卻芳菲節。東風氣力盡，不減陰山雪。',72,'御定全唐詩/json/599.json','["連年戍邊塞，過卻芳菲節。東風氣力盡，不減陰山雪。", "蕭條柳一株，南枝葉微發。為帶故鄉情，依依藉攀折。", "晚風吹磧沙，夜淚啼鄉月。淩煙閣上人，未必皆忠烈。"]'),
('yuding-34','富農詩','于濆','唐','御定全唐诗','yuding','','[]','長聞鄉人語，此家勝良賈。骨肉化饑魂，倉中有飽鼠。',96,'御定全唐詩/json/599.json','["長聞鄉人語，此家勝良賈。骨肉化饑魂，倉中有飽鼠。", "青春滿桑柘，旦夕鳴機杼。秋風一夜來，累累聞砧杵。", "西鄰有原憲，蓬蒿繞環堵。自樂固窮心，天意在何處。", "當門見堆子，已作桑田主。安得四海中，盡為虞芮土。"]'),
('yuding-35','早發','於濆','唐','御定全唐诗','yuding','','[]','綠野含曙光，東北雲如茜。棲鴉林際起，落月水中見。',48,'御定全唐詩/json/599.json','["綠野含曙光，東北雲如茜。棲鴉林際起，落月水中見。", "此身何自苦，日日淩霜霰。流蘇帳裏人，猶在陽臺畔。"]'),
('yuding-36','季夏逢朝客','於濆','唐','御定全唐诗','yuding','','[]','滻水桃李熟，杜曲芙蓉老。九天休沐歸，腰玉垂楊道。',48,'御定全唐詩/json/599.json','["滻水桃李熟，杜曲芙蓉老。九天休沐歸，腰玉垂楊道。", "避路回綺羅，迎風嘶騕褭。豈知山谷中，日日吹瑤草。"]'),
('yuding-37','隴頭水','于濆','唐','御定全唐诗','yuding','','[]','行人何彷徨，隴頭水嗚咽。寒沙戰鬼愁，白骨風霜切。',48,'御定全唐詩/json/599.json','["行人何彷徨，隴頭水嗚咽。寒沙戰鬼愁，白骨風霜切。", "薄日朦朧秋，怨氣陰雲結。殺成邊將名，名著生靈滅。"]'),
('yuding-38','古別離','於濆','唐','御定全唐诗','yuding','','[]','入室少情意，出門多路岐。黃鶴有歸日，蕩子無還時。',132,'御定全唐詩/json/599.json','["入室少情意，出門多路岐。黃鶴有歸日，蕩子無還時。", "人誰無分命，妾身何太奇。君為東南風，妾作西北枝。", "青樓鄰里婦，終年畫長眉。自倚對良匹，笑妾空羅幃。", "郎本東家兒，妾本西家女。對門中道間，終謂無離阻。", "豈知中道間，遣作空閨主。自是愛封侯，非關備胡虜。", "知子去從軍，何處無良人。"]'),
('yuding-39','擬古意','于濆','唐','御定全唐诗','yuding','','[]','白玉若無玷，花顏須及時。國色久在室，良媒亦生疑。',48,'御定全唐詩/json/599.json','["白玉若無玷，花顏須及時。國色久在室，良媒亦生疑。", "鴉鬟未成髻，鸞鏡徒相知。翻慚效顰者，卻笑從人遲。"]'),
('yuding-40','隴頭吟','於濆','唐','御定全唐诗','yuding','','[]','借問隴頭水，終年恨何事。深疑嗚咽聲，中有征人淚。',48,'御定全唐詩/json/599.json','["借問隴頭水，終年恨何事。深疑嗚咽聲，中有征人淚。", "自古蘊長策，況我非才智。無計謝潺湲，一宵空不寐。"]'),
('yuding-41','思歸引','於濆','唐','御定全唐诗','yuding','','[]','不耕南畝田，為愛東堂桂。身同樹上花，一落又經歲。',48,'御定全唐詩/json/599.json','["不耕南畝田，為愛東堂桂。身同樹上花，一落又經歲。", "交親日相薄，知己恩潛替。日開十二門，自是無歸計。"]'),
('yuding-42','秦富人','於濆','唐','御定全唐诗','yuding','','[]','高高起華堂，遠遠引流水。糞土視金珍，猶嫌未奢侈。',36,'御定全唐詩/json/599.json','["高高起華堂，遠遠引流水。糞土視金珍，猶嫌未奢侈。", "陋巷滿蓬蒿，誰憐有顏子。"]'),
('yuding-43','對花','於濆','唐','御定全唐诗','yuding','','[]','花開蝶滿枝，花落蝶還稀。惟有舊巢燕，主人貧亦歸。',24,'御定全唐詩/json/599.json','["花開蝶滿枝，花落蝶還稀。惟有舊巢燕，主人貧亦歸。"]'),
('yuding-44','宮怨','於濆','唐','御定全唐诗','yuding','','[]','妾家望江口，少年家財厚。臨江起珠樓，不賣文君酒。',120,'御定全唐詩/json/599.json','["妾家望江口，少年家財厚。臨江起珠樓，不賣文君酒。", "當年樂貞獨，巢燕時為友。父兄未許人，畏妾事姑舅。", "西牆鄰宋玉，窺見妾眉宇。一旦及天聰，恩光生戶牖。", "謂言入漢宮，富貴可長久。君王縱有情，不奈陳皇后。", "誰憐頰似桃，孰知腰勝柳。今日在長門，從來不如醜。"]'),
('yuding-0','登越王樓即事','牛征','唐','御定全唐诗','yuding','','[]','危樓送遠目，信美奈鄉情。轉岸孤舟疾，銜山落照明。',48,'御定全唐詩/json/600.json','["危樓送遠目，信美奈鄉情。轉岸孤舟疾，銜山落照明。", "蕭條看草色，惆悵認江聲。誰會登臨恨，從軍白髮生。"]'),
('yuding-1','及第後寄梁燭處士','伊璠','唐','御定全唐诗','yuding','','[]','繡轂尋芳許史家，獨將羈事達江沙。十年辛苦一枝桂，',40,'御定全唐詩/json/600.json','["繡轂尋芳許史家，獨將羈事達江沙。十年辛苦一枝桂，", "同袍不得同遊玩，今對春風日又斜。"]'),
('yuding-2','春詩','蕭遘','唐','御定全唐诗','yuding','','[]','南國韶光早，春風送臘來。水堤煙報柳，山寺雪驚梅。',48,'御定全唐詩/json/600.json','["南國韶光早，春風送臘來。水堤煙報柳，山寺雪驚梅。", "練色鋪江晚，潮聲逐渚回。青旗問沽酒，何處撥寒醅。"]'),
('yuding-3','和王侍中謁張惡子廟','蕭遘','唐','御定全唐诗','yuding','','[]','青骨祀吳誰讓德，紫華居越亦知名。未聞一劍傳唐主，',40,'御定全唐詩/json/600.json','["青骨祀吳誰讓德，紫華居越亦知名。未聞一劍傳唐主，", "酂侯為國親簫鼓，堂上神籌更布兵。"]'),
('yuding-4','成都','蕭遘','唐','御定全唐诗','yuding','','[]','月曉已開花市合，江平偏見竹簰多。',32,'御定全唐詩/json/600.json','["月曉已開花市合，江平偏見竹簰多。", "好教載取芳菲樹，剩照岷天瑟瑟波。"]'),
('yuding-5','句','蕭遘','唐','御定全唐诗','yuding','','[]','吾家九葉相，盡繼明時出。',12,'御定全唐詩/json/600.json','["吾家九葉相，盡繼明時出。"]'),
('yuding-6','策試夜潛紀長句於都堂西南隅','韋承貽','唐','御定全唐诗','yuding','','[]','褒衣博帶滿塵埃，獨自都堂納卷回。蓬巷幾時聞吉語，',72,'御定全唐詩/json/600.json','["褒衣博帶滿塵埃，獨自都堂納卷回。蓬巷幾時聞吉語，", "殘月漸低人擾擾，不知誰是謫仙才。", "白蓮千朵照廊明，一片升平雅頌聲。", "才唱第三條燭盡，南宮風月畫難成。"]'),
('yuding-7','詔放雲南子弟還國','鄭洪業','唐','御定全唐诗','yuding','','[]','德被陪臣子，仁垂聖主恩。雕題辭鳳闕，丹服出金門。',73,'御定全唐詩/json/600.json','["德被陪臣子，仁垂聖主恩。雕題辭鳳闕，丹服出金門。", "有澤沾殊俗，無征及獷ce。銅梁分漢土，玉壘駕鸞軒。", "瘴嶺蠶叢盛，巴江越巂垠。萬方同感化，豈獨自南蕃。"]'),
('yuding-8','中秋夜思鄭延美有作','孫緯','唐','御定全唐诗','yuding','','[]','中秋中夜月，世說懾妖精。顧兔雲初蔽，長蛇誰與勍。',48,'御定全唐詩/json/600.json','["中秋中夜月，世說懾妖精。顧兔雲初蔽，長蛇誰與勍。", "未追良友玩，安用玉輪盈。此意人誰喻，裁詩穿禁城。"]'),
('yuding-9','清曉捲簾','歐陽玭','唐','御定全唐诗','yuding','','[]','清曉意未愜，捲簾時一吟。檻虛花氣密，地暖竹聲深。',48,'御定全唐詩/json/600.json','["清曉意未愜，捲簾時一吟。檻虛花氣密，地暖竹聲深。", "秀色還朝暮，浮雲自古今。石泉驚已躍，會可洗幽心。"]'),
('yuding-10','巴陵','歐陽玭','唐','御定全唐诗','yuding','','[]','孤城向夕原，春入景初暄。綠樹低官舍，青山在縣門。',48,'御定全唐詩/json/600.json','["孤城向夕原，春入景初暄。綠樹低官舍，青山在縣門。", "樓臺疑結蜃，枕席更聞猿。客路何曾定，棲遲欲斷魂。"]'),
('yuding-11','榆溪道上','歐陽玭','唐','御定全唐诗','yuding','','[]','初日在斜溪，山雲片片低。鄉愁夢裏失，馬色望中迷。',48,'御定全唐詩/json/600.json','["初日在斜溪，山雲片片低。鄉愁夢裏失，馬色望中迷。", "澗底淒泉氣，岩前遍綠荑。非關秦塞去，無事候晨雞。"]'),
('yuding-12','新嶺臨眺寄連總進士','歐陽玭','唐','御定全唐诗','yuding','','[]','關勢遙臨海，峰巒半入雲。煙中獨鳥下，潭上雜花熏。',48,'御定全唐詩/json/600.json','["關勢遙臨海，峰巒半入雲。煙中獨鳥下，潭上雜花熏。", "寄遠悲春草，登臨憶使君。此時還極目，離思更紛紛。"]'),
('yuding-13','幽軒','歐陽玭','唐','御定全唐诗','yuding','','[]','幽軒斜映山，空澗複潺潺。重疊岩巒趣，遙來窗戶間。',72,'御定全唐詩/json/600.json','["幽軒斜映山，空澗複潺潺。重疊岩巒趣，遙來窗戶間。", "桃花飄岫幌，燕子語松關。衣桁侵池翠，階痕露蘚斑。", "臨風清瑟奏，對客白雲閑。眷戀青春色，含毫俯碧灣。"]'),
('yuding-14','社日村居','張演','唐','御定全唐诗','yuding','','[]','鵝湖山下稻粱肥，豚阱雞棲對掩扉。',32,'御定全唐詩/json/600.json','["鵝湖山下稻粱肥，豚阱雞棲對掩扉。", "桑柘影斜春社散，家家扶得醉人歸。"]'),
('yuding-15','吊孟昌圖','裴澈','唐','御定全唐诗','yuding','','[]','一章何罪死何名，投水惟君與屈平。',32,'御定全唐詩/json/600.json','["一章何罪死何名，投水惟君與屈平。", "從此蜀江煙月夜，杜鵑應作兩般聲。"]'),
('yuding-16','婕妤怨','翁綬','唐','御定全唐诗','yuding','','[]','讒謗潛來起百憂，朝承恩寵暮仇讎。火燒白玉非因玷，',40,'御定全唐詩/json/600.json','["讒謗潛來起百憂，朝承恩寵暮仇讎。火燒白玉非因玷，", "繁華事逐東流水，團扇悲歌萬古愁。"]'),
('yuding-17','隴頭吟','翁綬','唐','御定全唐诗','yuding','','[]','隴水潺湲隴樹黃，征人隴上盡思鄉。馬嘶斜日朔風急，',40,'御定全唐詩/json/600.json','["隴水潺湲隴樹黃，征人隴上盡思鄉。馬嘶斜日朔風急，", "橫行俱是封侯者，誰斬樓蘭獻未央。"]'),
('yuding-18','關山月','翁綬','唐','御定全唐诗','yuding','','[]','裴回漢月滿邊州，照盡天涯到隴頭。影轉銀河寰海靜，',40,'御定全唐詩/json/600.json','["裴回漢月滿邊州，照盡天涯到隴頭。影轉銀河寰海靜，", "況是故園搖落夜，那堪少婦獨登樓。"]'),
('yuding-19','雨雪曲','翁綬','唐','御定全唐诗','yuding','','[]','邊聲四合殷河流，雨雪飛來遍隴頭。鐵嶺探人迷鳥道，',40,'御定全唐詩/json/600.json','["邊聲四合殷河流，雨雪飛來遍隴頭。鐵嶺探人迷鳥道，", "一自塞垣無李蔡，何人為解北門憂。"]'),
('yuding-20','行路難','翁綬','唐','御定全唐诗','yuding','','[]','行路艱難不復歌，故人榮達我蹉跎。雙輪晚上銅台雪，',40,'御定全唐詩/json/600.json','["行路艱難不復歌，故人榮達我蹉跎。雙輪晚上銅台雪，", "君看西漢翟丞相，鳳沼朝辭暮雀羅。"]'),
('yuding-21','折楊柳','翁綬','唐','御定全唐诗','yuding','','[]','紫陌金堤映綺羅，遊人處處動離歌。陰移古戍迷芳草，',40,'御定全唐詩/json/600.json','["紫陌金堤映綺羅，遊人處處動離歌。陰移古戍迷芳草，", "殷勤攀折贈行客，此去關山雨雪多。"]'),
('yuding-22','詠酒','翁綬','唐','御定全唐诗','yuding','','[]','逃暑迎春複送秋，無非綠蟻滿杯浮。百年莫惜千回醉，',40,'御定全唐詩/json/600.json','["逃暑迎春複送秋，無非綠蟻滿杯浮。百年莫惜千回醉，", "平生名利關身者，不識狂歌到白頭。"]'),
('yuding-23','白馬','翁綬','唐','御定全唐诗','yuding','','[]','渥窪龍種雪霜同，毛骨天生膽氣雄。金埒乍調光照地，',40,'御定全唐詩/json/600.json','["渥窪龍種雪霜同，毛骨天生膽氣雄。金埒乍調光照地，", "一夜羽書催轉戰，紫髯騎出佩騂弓。"]'),
('yuding-24','句','翁綬','唐','御定全唐诗','yuding','','[]','海國歐鄉浙水東，暫煩良守此憑熊。',16,'御定全唐詩/json/600.json','["海國歐鄉浙水東，暫煩良守此憑熊。"]'),
('yuding-25','中秋月','潘緯','唐','御定全唐诗','yuding','','[]','古今逢此夜，共冀泬明。豈是月華別，只應秋氣清。',48,'御定全唐詩/json/600.json','["古今逢此夜，共冀泬明。豈是月華別，只應秋氣清。", "影當中土正，輪對八荒平。尋客徒留望，璿璣自有程。"]'),
('yuding-26','琴','潘緯','唐','御定全唐诗','yuding','','[]','客來鳴素琴，惆悵對遺音。一曲起于古，幾人聽到今。',48,'御定全唐詩/json/600.json','["客來鳴素琴，惆悵對遺音。一曲起于古，幾人聽到今。", "盡含風靄遠，自泛月煙深。風續水山操，坐生方外心。"]'),
('yuding-27','句','潘緯','唐','御定全唐诗','yuding','','[]','篆經千古澀，影瀉一堂寒。',12,'御定全唐詩/json/600.json','["篆經千古澀，影瀉一堂寒。"]'),
('yuding-28','九日衛使君筵上作','武瓘','唐','御定全唐诗','yuding','','[]','佳晨登賞喜還鄉，謝宇開筵晚興長。滿眼黃花初泛酒，',40,'御定全唐詩/json/600.json','["佳晨登賞喜還鄉，謝宇開筵晚興長。滿眼黃花初泛酒，", "共賀安人豐樂歲，幸陪珠履侍銀章。"]'),
('yuding-29','勸酒','武瓘','唐','御定全唐诗','yuding','','[]','勸君金屈卮，滿酌不須辭。花發多風雨，人生足別離。',24,'御定全唐詩/json/600.json','["勸君金屈卮，滿酌不須辭。花發多風雨，人生足別離。"]'),
('yuding-30','感事','武瓘','唐','御定全唐诗','yuding','','[]','花開蝶滿枝，花謝蝶還稀。惟有舊巢燕，主人貧亦歸。',24,'御定全唐詩/json/600.json','["花開蝶滿枝，花謝蝶還稀。惟有舊巢燕，主人貧亦歸。"]'),
('yuding-31','重歸宜春偶成十六韻寄朝中知己','袁皓','唐','御定全唐诗','yuding','','[]','水香甘似醴，知是入袁溪。黃竹成叢密，青蘿夾岸低。',192,'御定全唐詩/json/600.json','["水香甘似醴，知是入袁溪。黃竹成叢密，青蘿夾岸低。", "暖流鸂鶒戲，深樹鷓鴣啼。黃犬驚迎客，青牛困臥泥。", "有村皆績紡，無地不耕犁。鄉曲多耆舊，逢迎盡杖藜。", "殷勤傾白酒，相勸有黃雞。歸老官知忝，還鄉路不迷。", "直言幹忌諱，權路恥依棲。拙學趨時態，閑思與牧齊。", "稻糧饒燕雀，江海溢鳧鷖。昔共逢離亂，今來息鼓鼙。", "恩仁沾品物，教化及雕題。上貢貞元祿，曾叨寵記批。", "何須歸紫禁，便是到丹梯。珍重長安道，從今息馬嘶。"]'),
('yuding-32','及第後作','袁皓','唐','御定全唐诗','yuding','','[]','金榜高懸姓字真，分明折得一枝春。蓬瀛乍接神仙侶，',40,'御定全唐詩/json/600.json','["金榜高懸姓字真，分明折得一枝春。蓬瀛乍接神仙侶，", "升平時節逢公道，不覺龍門是嶮津。"]'),
('yuding-33','重歸宜春經過萍川題梵林寺','袁皓','唐','御定全唐诗','yuding','','[]','梵林遺址在松蘿，四十年來兩度過。瀘水東奔彭蠡浪，',40,'御定全唐詩/json/600.json','["梵林遺址在松蘿，四十年來兩度過。瀘水東奔彭蠡浪，", "拖紫腰金成底事，憑闌惆悵欲如何。"]'),
('yuding-34','寄岳陽嚴使君','袁皓','唐','御定全唐诗','yuding','','[]','得意東歸過岳陽，桂枝香惹蕊珠香。也知暮雨生巫峽，',40,'御定全唐詩/json/600.json','["得意東歸過岳陽，桂枝香惹蕊珠香。也知暮雨生巫峽，", "南亭宴罷笙歌散，回首煙波路渺茫。"]'),
('yuding-35','賦得郎官上應列宿','公乘億','唐','御定全唐诗','yuding','','[]','北極佇文昌，南宮曉拜郎。紫泥乘帝澤，銀印佩天光。',72,'御定全唐詩/json/600.json','["北極佇文昌，南宮曉拜郎。紫泥乘帝澤，銀印佩天光。", "緯結三台側，鉤連四輔旁。佐商依傅說，仕漢笑馮唐。", "委佩搖秋色，峨冠帶晚霜。自然符列象，千古耀岩廊。"]'),
('yuding-36','春風扇微和','公乘億','唐','御定全唐诗','yuding','','[]','麗日催遲景，和風扇早春。暖浮丹鳳闕，韶媚黑龍津。',72,'御定全唐詩/json/600.json','["麗日催遲景，和風扇早春。暖浮丹鳳闕，韶媚黑龍津。", "澹蕩迎仙杖，霏微送畫輪。綠搖宮柳散，紅待禁花新。", "舞席潛回雪，歌筵暗起塵。幸當陽候律，一顧及佳晨。"]'),
('yuding-37','賦得秋菊有佳色','公乘億','唐','御定全唐诗','yuding','','[]','陶令籬邊菊，秋來色轉佳。翠攢千片葉，金剪一枝花。',72,'御定全唐詩/json/600.json','["陶令籬邊菊，秋來色轉佳。翠攢千片葉，金剪一枝花。", "蕊逐蜂須亂，英隨蝶翅斜。帶香飄綠綺，和酒上烏紗。", "散漫搖霜彩，嬌妍漏日華。芳菲彭澤見，更稱在誰家。"]'),
('yuding-38','賦得臨江遲來客','公乘億','唐','御定全唐诗','yuding','','[]','江上晚沉沉，煙波一望深。向來殊未至，何處擬相尋。',72,'御定全唐詩/json/600.json','["江上晚沉沉，煙波一望深。向來殊未至，何處擬相尋。", "柳結重重眼，萍翻寸寸心。暮山期共眺，寒渚待同臨。", "北去魚無信，南飛雁絕音。思君不可見，使我獨愁吟。"]'),
('yuding-39','句','公乘億','唐','御定全唐诗','yuding','','[]','十上十年皆落第，一家一半已成塵。',16,'御定全唐詩/json/600.json','["十上十年皆落第，一家一半已成塵。"]'),
('yuding-40','九華山謠','王季文','唐','御定全唐诗','yuding','','[]','九華崢嶸占南陸，蓮花擢本山半腹。翠屏橫截萬里天，',96,'御定全唐詩/json/600.json','["九華崢嶸占南陸，蓮花擢本山半腹。翠屏橫截萬里天，", "丹崖壓下廬霍勢，白日隱出牛鬥星。杉松一歲抽數尺，", "雷霆往往從地發，龍臥豹藏安可別。峻極遙看戛昊蒼，", "陽烏不見峰頂樹，大火尚結岩中冰。靈光爽氣曛複旭，"]'),
('yuding-41','青出藍','王季文','唐','御定全唐诗','yuding','','[]','芳藍滋匹帛，人力半天經。浸潤加新氣，光輝勝本青。',48,'御定全唐詩/json/600.json','["芳藍滋匹帛，人力半天經。浸潤加新氣，光輝勝本青。", "還同冰出水，不共草為螢。翻覆依襟上，偏知造化靈。"]'),
('yuding-42','題青龍精舍','盧駢','唐','御定全唐诗','yuding','','[]','壽夭雖雲命，榮枯亦大偏。不知雷氏劍，何處更沖天。',24,'御定全唐詩/json/600.json','["壽夭雖雲命，榮枯亦大偏。不知雷氏劍，何處更沖天。"]'),
('yuding-43','感事','王鐐','唐','御定全唐诗','yuding','','[]','擊石易得火，扣人難動心。今日朱門者，曾恨朱門深。',24,'御定全唐詩/json/600.json','["擊石易得火，扣人難動心。今日朱門者，曾恨朱門深。"]'),
('yuding-44','退朝望終南山','李拯','唐','御定全唐诗','yuding','','[]','紫宸朝罷綴鴛鸞，丹鳳樓前駐馬看。',32,'御定全唐詩/json/600.json','["紫宸朝罷綴鴛鸞，丹鳳樓前駐馬看。", "惟有終南山色在，晴明依舊滿長安。"]'),
('yuding-45','月中桂樹','顧封人','唐','御定全唐诗','yuding','','[]','芬馥天邊桂，扶疏在月中。能齊大椿長，不與小山同。',72,'御定全唐詩/json/600.json','["芬馥天邊桂，扶疏在月中。能齊大椿長，不與小山同。", "皎皎舒華色，亭亭麗碧空。虧盈寧委露，搖落不關風。", "歲晚花應發，春餘質詎豐。無因遂攀賞，徒欲望青蔥。"]'),
('yuding-46','和陸魯望白菊','司馬都','唐','御定全唐诗','yuding','','[]','恥共金英一例開，素芳須待早霜催。繞籬看見成瑤圃，',40,'御定全唐詩/json/600.json','["恥共金英一例開，素芳須待早霜催。繞籬看見成瑤圃，", "夫君每尚風流事，應為徐妃致此栽。"]'),
('yuding-47','送羊振文先輩往桂陽歸覲','司馬都','唐','御定全唐诗','yuding','','[]','此去歡榮冠士林，離筵休恨酒杯深。雲梯萬仞初高步，',40,'御定全唐詩/json/600.json','["此去歡榮冠士林，離筵休恨酒杯深。雲梯萬仞初高步，", "君家祖德惟清苦，卻笑當時問絹心。"]'),
('yuding-0','書邊事','李昌符','唐','御定全唐诗','yuding','','[]','朔野煙塵起，天軍又舉戈。陰風向晚急，殺氣入秋多。',48,'御定全唐詩/json/601.json','["朔野煙塵起，天軍又舉戈。陰風向晚急，殺氣入秋多。", "樹盡禽棲草，冰堅路在河。汾陽無繼者，羌虜肯先和。"]'),
('yuding-1','遠歸別墅','李昌符','唐','御定全唐诗','yuding','','[]','馬省曾行處，連嘶渡晚河。忽驚鄉樹出，漸識路人多。',48,'御定全唐詩/json/601.json','["馬省曾行處，連嘶渡晚河。忽驚鄉樹出，漸識路人多。", "細徑穿禾黍，頹垣壓薜蘿。乍歸猶似客，鄰叟亦相過。"]'),
('yuding-2','題友人屋','李昌符','唐','御定全唐诗','yuding','','[]','松底詩人宅，閑門遠岫孤。數家分小徑，一水截平蕪。',48,'御定全唐詩/json/601.json','["松底詩人宅，閑門遠岫孤。數家分小徑，一水截平蕪。", "竹節偶相對，鳥名多自呼。愛君真靜者，欲去又踟躕。"]'),
('yuding-3','贈同游','李昌符','唐','御定全唐诗','yuding','','[]','此來風雨後，已覺減年華。若待皆無事，應難更有花。',48,'御定全唐詩/json/601.json','["此來風雨後，已覺減年華。若待皆無事，應難更有花。", "管弦臨夜急，榆柳向江斜。且莫看歸路，同須醉酒家。"]'),
('yuding-4','送人出塞','李昌符','唐','御定全唐诗','yuding','','[]','北風吹雨雪，舉目已淒淒。戰鬼秋頻哭，征鴻夜不棲。',48,'御定全唐詩/json/601.json','["北風吹雨雪，舉目已淒淒。戰鬼秋頻哭，征鴻夜不棲。", "沙平關路直，磧廣郡樓低。此去非東魯，人多事鼓鼙。"]'),
('yuding-5','尋僧元皎因贈','李昌符','唐','御定全唐诗','yuding','','[]','此生迷有著，因病得尋師。話盡山中事，歸當月上時。',48,'御定全唐詩/json/601.json','["此生迷有著，因病得尋師。話盡山中事，歸當月上時。", "高松連寺影，亞竹入窗枝。閑憶草堂路，相逢非素期。"]'),
('yuding-6','下第後蒙侍郎示意指于新先輩宣恩感謝','李昌符','唐','御定全唐诗','yuding','','[]','才薄命如此，自嗟兼自疑。遭逢好文日，黜落至公時。',48,'御定全唐詩/json/601.json','["才薄命如此，自嗟兼自疑。遭逢好文日，黜落至公時。", "倚玉甘無路，穿楊卻未期。更慚君侍坐，問許可言詩。"]'),
('yuding-7','夜泊渭津','李昌符','唐','御定全唐诗','yuding','','[]','漂漂東去客，一宿渭城邊。遠處星垂岸，中流月滿船。',48,'御定全唐詩/json/601.json','["漂漂東去客，一宿渭城邊。遠處星垂岸，中流月滿船。", "涼歸夜深簟，秋入雨餘天。漸覺家山小，殘程尚幾年。"]'),
('yuding-8','晚夏逢友人','李昌符','唐','御定全唐诗','yuding','','[]','一別同袍友，相思已十年。長安多在客，久病忽聞蟬。',48,'御定全唐詩/json/601.json','["一別同袍友，相思已十年。長安多在客，久病忽聞蟬。", "驟雨才沾地，陰雲不遍天。微涼堪話舊，移榻晚風前。"]'),
('yuding-9','秋中夜坐','李昌符','唐','御定全唐诗','yuding','','[]','空庭吟坐久，爽氣入荷衣。病葉先秋落，驚禽背月飛。',48,'御定全唐詩/json/601.json','["空庭吟坐久，爽氣入荷衣。病葉先秋落，驚禽背月飛。", "瘴雲晴未散，戍客老將依。為應金門策，多應說戰機。"]'),
('yuding-10','旅遊傷春','李昌符','唐','御定全唐诗','yuding','','[]','酒醒鄉關遠，迢迢聽漏終。曙分林影外，春盡雨聲中。',48,'御定全唐詩/json/601.json','["酒醒鄉關遠，迢迢聽漏終。曙分林影外，春盡雨聲中。", "鳥思江村路，花殘野岸風。十年成底事，羸馬倦西東。"]'),
('yuding-11','得遠書','李昌符','唐','御定全唐诗','yuding','','[]','故人居謫宦，今日一書來。良久驚兼喜，殷勤卷更開。',48,'御定全唐詩/json/601.json','["故人居謫宦，今日一書來。良久驚兼喜，殷勤卷更開。", "瘴雲沉去雁，江雨促新梅。滿紙殊鄉淚，非冤不可哀。"]'),
('yuding-12','贈同席','李昌符','唐','御定全唐诗','yuding','','[]','四座列吾友，滿園花照衣。一生知幾度，後到擬先歸。',48,'御定全唐詩/json/601.json','["四座列吾友，滿園花照衣。一生知幾度，後到擬先歸。", "急管侵諸樂，嚴城送落暉。當歡莫離席，離席卻歡稀。"]'),
('yuding-13','贈供奉僧玄觀','李昌符','唐','御定全唐诗','yuding','','[]','自得曹溪法，諸經更不看。已降禪侶久，兼作帝師難。',48,'御定全唐詩/json/601.json','["自得曹溪法，諸經更不看。已降禪侶久，兼作帝師難。", "夜木侵簷黑，秋燈照雨寒。如何嫌有著，一念在林巒。"]'),
('yuding-14','送琴客','李昌符','唐','御定全唐诗','yuding','','[]','楚客抱離思，蜀琴留恨聲。坐來新月上，聽久覺秋生。',48,'御定全唐詩/json/601.json','["楚客抱離思，蜀琴留恨聲。坐來新月上，聽久覺秋生。", "夜靜騷人語，天高別鶴鳴。因君興一歎，竟夕意難平。"]'),
('yuding-15','別謫者','李昌符','唐','御定全唐诗','yuding','','[]','此地聞猶惡，人言是所之。一家書絕久，孤驛夢成遲。',48,'御定全唐詩/json/601.json','["此地聞猶惡，人言是所之。一家書絕久，孤驛夢成遲。", "八月三湘道，聞猿冒雨時。不須祠楚相，臣節轉堪疑。"]'),
('yuding-16','行思','李昌符','唐','御定全唐诗','yuding','','[]','千里豈雲去，欲歸如路窮。人間無暇日，馬上又秋風。',48,'御定全唐詩/json/601.json','["千里豈雲去，欲歸如路窮。人間無暇日，馬上又秋風。", "破月銜高嶽，流星拂曉空。此時皆在夢，行色獨匆匆。"]'),
('yuding-17','感懷題從舅宅','李昌符','唐','御定全唐诗','yuding','','[]','郗家庭樹下，幾度醉春風。今日花還發，當時事不同。',48,'御定全唐詩/json/601.json','["郗家庭樹下，幾度醉春風。今日花還發，當時事不同。", "流言應未息，直道竟難通。徒遣相思者，悲歌向暮空。"]'),
('yuding-18','與友人會','李昌符','唐','御定全唐诗','yuding','','[]','蟬吟槐蕊落，的的是愁端。病覺離家遠，貧知處事難。',48,'御定全唐詩/json/601.json','["蟬吟槐蕊落，的的是愁端。病覺離家遠，貧知處事難。", "真交無所隱，深語有餘歡。未必聞歌吹，羈心得暫寬。"]'),
('yuding-19','贈春遊侶','李昌符','唐','御定全唐诗','yuding','','[]','密林多暗香，輕吹送餘芳。啼鳥愁春盡，遊人喜日長。',48,'御定全唐詩/json/601.json','["密林多暗香，輕吹送餘芳。啼鳥愁春盡，遊人喜日長。", "浮雲橫暮色，新雨洗韶光。欲散垂□恨，應須入醉鄉。"]'),
('yuding-20','送人游邊','李昌符','唐','御定全唐诗','yuding','','[]','愁指蕭關外，風沙入遠程。馬行初有跡，雨落竟無聲。',48,'御定全唐詩/json/601.json','["愁指蕭關外，風沙入遠程。馬行初有跡，雨落竟無聲。", "地理全歸漢，天威不在兵。西京逢故老，暗喜複時平。"]'),
('yuding-21','寄棲白上人','李昌符','唐','御定全唐诗','yuding','','[]','剪發兼成隱，將心更屬文。無憀對豪客，不拜謁吾君。',72,'御定全唐詩/json/601.json','["剪發兼成隱，將心更屬文。無憀對豪客，不拜謁吾君。", "畫壁惟泉石，經窗半典墳。歸林幽鳥狎，乞食病僧分。", "默坐終清夜，凝思念碧雲。相逢應未卜，餘正走囂氛。"]'),
('yuding-22','送人入新羅使','李昌符','唐','御定全唐诗','yuding','','[]','雞林君欲去，立冊付星軺。越海程難計，征帆影自飄。',72,'御定全唐詩/json/601.json','["雞林君欲去，立冊付星軺。越海程難計，征帆影自飄。", "望鄉當落日，懷闕羨回潮。宿霧蒙青嶂，驚波蕩碧霄。", "春生陽氣早，天接祖州遙。愁約三年外，相迎上石橋。"]'),
('yuding-23','詠鐵馬鞭','李昌符','唐','御定全唐诗','yuding','','[]','漢將臨流得鐵鞭，鄂侯名字舊雕鐫。須為聖代無雙物，',40,'御定全唐詩/json/601.json','["漢將臨流得鐵鞭，鄂侯名字舊雕鐫。須為聖代無雙物，", "時來終薦明君用，莫歎沉埋二百年。"]'),
('yuding-24','送友人','李昌符','唐','御定全唐诗','yuding','','[]','舉世誰能與事期，解攜多是正歡時。人間不遣有名利，',40,'御定全唐詩/json/601.json','["舉世誰能與事期，解攜多是正歡時。人間不遣有名利，", "我今漂泊還如此，江劍相逢亦未知。"]'),
('yuding-25','南潭','李昌符','唐','御定全唐诗','yuding','','[]','匝岸青蕪掩古苔，面山亭樹枕潭開。有時弦管收筵促，',40,'御定全唐詩/json/601.json','["匝岸青蕪掩古苔，面山亭樹枕潭開。有時弦管收筵促，", "人傳郭惲多遊此，誰見當初泛玉杯。"]'),
('yuding-26','秋夜作','李昌符','唐','御定全唐诗','yuding','','[]','數畝池塘近杜陵，秋天寂寞夜雲凝。芙蓉葉上三更雨，',40,'御定全唐詩/json/601.json','["數畝池塘近杜陵，秋天寂寞夜雲凝。芙蓉葉上三更雨，", "既逢上國陳詩日，長守林泉亦未能。"]'),
('yuding-27','客恨','李昌符','唐','御定全唐诗','yuding','','[]','古原南北舊蕭疏，高木風多小雪餘。半夜病吟人寢後，',40,'御定全唐詩/json/601.json','["古原南北舊蕭疏，高木風多小雪餘。半夜病吟人寢後，", "肥馬王孫定相笑，不知岐路厭樵漁。"]'),
('yuding-28','三月盡日','李昌符','唐','御定全唐诗','yuding','','[]','江頭從此管弦稀，散盡遊人獨未歸。',32,'御定全唐詩/json/601.json','["江頭從此管弦稀，散盡遊人獨未歸。", "落日已將春色去，殘花應逐夜風飛。"]'),
('yuding-29','綠珠詠','李昌符','唐','御定全唐诗','yuding','','[]','洛陽佳麗與芳華，金穀園中見百花。',32,'御定全唐詩/json/601.json','["洛陽佳麗與芳華，金穀園中見百花。", "誰遣當年墜樓死，無人巧笑破孫家。"]'),
('yuding-30','贈別','李昌符','唐','御定全唐诗','yuding','','[]','又將書劍出孤舟，盡日停橈結遠愁。',32,'御定全唐詩/json/601.json','["又將書劍出孤舟，盡日停橈結遠愁。", "莫道江波話離別，江波一去不回流。"]'),
('yuding-31','悶書','李昌符','唐','御定全唐诗','yuding','','[]','病來難處早秋天，一徑無人樹有蟬。',32,'御定全唐詩/json/601.json','["病來難處早秋天，一徑無人樹有蟬。", "歸計未成書半卷，中宵多夢晝多眠。"]'),
('yuding-32','傷春','李昌符','唐','御定全唐诗','yuding','','[]','即是春風盡，仍沾夜雨歸。明朝更來此，兼恐落花稀。',24,'御定全唐詩/json/601.json','["即是春風盡，仍沾夜雨歸。明朝更來此，兼恐落花稀。"]'),
('yuding-33','登臨洮望蕭關','李昌符','唐','御定全唐诗','yuding','','[]','漸覺風沙暗，蕭關欲到時。兒童能探火，婦女解縫旗。',48,'御定全唐詩/json/601.json','["漸覺風沙暗，蕭關欲到時。兒童能探火，婦女解縫旗。", "川少銜魚鷺，林多帶箭麋。暫來戎馬地，不敢苦吟詩。"]'),
('yuding-0','彭澤','汪遵','唐','御定全唐诗','yuding','','[]','鶴愛孤松雲愛山，宦情微祿免相關。',32,'御定全唐詩/json/602.json','["鶴愛孤松雲愛山，宦情微祿免相關。", "栽成五柳吟歸去，漉酒巾邊伴菊閑。"]'),
('yuding-1','杜郵館','汪遵','唐','御定全唐诗','yuding','','[]','殺盡降兵熱血流，一心猶自逞戈矛。',32,'御定全唐詩/json/602.json','["殺盡降兵熱血流，一心猶自逞戈矛。", "功成若解求身退，豈得將軍死杜郵。"]'),
('yuding-2','細腰宮','汪遵','唐','御定全唐诗','yuding','','[]','鼓聲連日燭連宵，貪向春風舞細腰。',32,'御定全唐詩/json/602.json','["鼓聲連日燭連宵，貪向春風舞細腰。", "爭奈君王正沈醉，秦兵江上促征橈。"]'),
('yuding-3','瑤台','汪遵','唐','御定全唐诗','yuding','','[]','仙夢香魂不久留，滿川雲雨滿宮愁。',32,'御定全唐詩/json/602.json','["仙夢香魂不久留，滿川雲雨滿宮愁。", "直須待得荊王死，始向瑤台一處遊。"]'),
('yuding-4','吳阪','汪遵','唐','御定全唐诗','yuding','','[]','蜷局鹽車萬里蹄，忽逢良鑒始能嘶。',32,'御定全唐詩/json/602.json','["蜷局鹽車萬里蹄，忽逢良鑒始能嘶。", "不緣伯樂稱奇骨，幾與駑駘價一齊。"]'),
('yuding-5','箕山','汪遵','唐','御定全唐诗','yuding','','[]','薄世臨流洗耳塵，便歸雲洞任天真。',32,'御定全唐詩/json/602.json','["薄世臨流洗耳塵，便歸雲洞任天真。", "一瓢風入猶嫌鬧，何況人間萬種人。"]'),
('yuding-6','息國','汪遵','唐','御定全唐诗','yuding','','[]','家國興亡身獨存，玉容還受楚王恩。',32,'御定全唐詩/json/602.json','["家國興亡身獨存，玉容還受楚王恩。", "銜冤只合甘先死，何待花間不肯言。"]'),
('yuding-7','梁寺','汪遵','唐','御定全唐诗','yuding','','[]','立國從來為戰功，一朝何事卻談空。',32,'御定全唐詩/json/602.json','["立國從來為戰功，一朝何事卻談空。", "台城兵匝無人敵，閑臥高僧滿梵宮。"]'),
('yuding-8','南陽','汪遵','唐','御定全唐诗','yuding','','[]','陸困泥蟠未適從，豈妨耕稼隱高蹤。',32,'御定全唐詩/json/602.json','["陸困泥蟠未適從，豈妨耕稼隱高蹤。", "若非先主垂三顧，誰識茅廬一臥龍。"]'),
('yuding-9','杞梁墓','汪遵','唐','御定全唐诗','yuding','','[]','一叫長城萬仞摧，杞梁遺骨逐妻回。',32,'御定全唐詩/json/602.json','["一叫長城萬仞摧，杞梁遺骨逐妻回。", "南鄰北裏皆孀婦，誰解堅心繼此來。"]'),
('yuding-10','夷門','汪遵','唐','御定全唐诗','yuding','','[]','晉鄙兵回為重難，秦師收旆亦西還。',32,'御定全唐詩/json/602.json','["晉鄙兵回為重難，秦師收旆亦西還。", "今來不是無朱亥，誰降軒車問抱關。"]'),
('yuding-11','汴河','汪遵','唐','御定全唐诗','yuding','','[]','隋皇意欲泛龍舟，千里昆侖水別流。',32,'御定全唐詩/json/602.json','["隋皇意欲泛龍舟，千里昆侖水別流。", "還待春風錦帆暖，柳陰相送到迷樓。"]'),
('yuding-12','燕台','汪遵','唐','御定全唐诗','yuding','','[]','禮士招賢萬古名，高臺依舊對燕城。',32,'御定全唐詩/json/602.json','["禮士招賢萬古名，高臺依舊對燕城。", "如今寂寞無人上，春去秋來草自生。"]'),
('yuding-13','聊城','汪遵','唐','御定全唐诗','yuding','','[]','刃血攻聊已越年，竟憑儒術罷戈鋋。田單漫逞燒牛計，一箭終輸魯仲連。',32,'御定全唐詩/json/602.json','["刃血攻聊已越年，竟憑儒術罷戈鋋。田單漫逞燒牛計，一箭終輸魯仲連。"]'),
('yuding-14','西河','汪遵','唐','御定全唐诗','yuding','','[]','花貌年年溺水濱，俗傳河伯娶生人。',32,'御定全唐詩/json/602.json','["花貌年年溺水濱，俗傳河伯娶生人。", "自從明宰投巫後，直至如今鬼不神。"]'),
('yuding-15','密縣','汪遵','唐','御定全唐诗','yuding','','[]','百里能將濟猛寬，飛蝗不到邑人安。',32,'御定全唐詩/json/602.json','["百里能將濟猛寬，飛蝗不到邑人安。", "至今閭裏逢災沴，猶祝當時卓長官。"]'),
('yuding-16','升仙橋','汪遵','唐','御定全唐诗','yuding','','[]','題橋貴欲露先誠，此日人皆笑率情。',32,'御定全唐詩/json/602.json','["題橋貴欲露先誠，此日人皆笑率情。", "應訝臨邛沽酒客，逢時還作漢公卿。"]'),
('yuding-17','破陳','汪遵','唐','御定全唐诗','yuding','','[]','獵獵朱旗映彩霞，紛紛白刃入陳家。',32,'御定全唐詩/json/602.json','["獵獵朱旗映彩霞，紛紛白刃入陳家。", "看看打破東平苑，猶舞庭前玉樹花。"]'),
('yuding-18','白頭吟','汪遵','唐','御定全唐诗','yuding','','[]','失卻青絲素發生，合歡羅帶意全輕。',32,'御定全唐詩/json/602.json','["失卻青絲素發生，合歡羅帶意全輕。", "古今人事皆如此，不獨文君與馬卿。"]'),
('yuding-19','短歌吟','汪遵','唐','御定全唐诗','yuding','','[]','箭飛烏兔競東西，貴賤賢愚不夢齊。',32,'御定全唐詩/json/602.json','["箭飛烏兔競東西，貴賤賢愚不夢齊。", "匣裏有琴樽有酒，人間便是武陵溪。"]'),
('yuding-20','晉河','汪遵','唐','御定全唐诗','yuding','','[]','風引征帆管吹高，晉君張宴俟雄豪。',32,'御定全唐詩/json/602.json','["風引征帆管吹高，晉君張宴俟雄豪。", "舟人笑指千餘客，誰是煙霄六翮毛。"]'),
('yuding-21','幹將墓','汪遵','唐','御定全唐诗','yuding','','[]','橐鑰冰霜萬古聞，拍灰松地見餘墳。',32,'御定全唐詩/json/602.json','["橐鑰冰霜萬古聞，拍灰松地見餘墳。", "應緣神劍飛揚久，水水山山儘是雲。"]'),
('yuding-22','金谷','汪遵','唐','御定全唐诗','yuding','','[]','晉臣榮盛更誰過，常向階前舞翠娥。',32,'御定全唐詩/json/602.json','["晉臣榮盛更誰過，常向階前舞翠娥。", "香散豔消如一夢，但留風月伴煙蘿。"]'),
('yuding-23','三閭廟','汪遵','唐','御定全唐诗','yuding','','[]','為嫌朝野盡陶陶，不覺官高怨亦高。',32,'御定全唐詩/json/602.json','["為嫌朝野盡陶陶，不覺官高怨亦高。", "憔悴莫酬漁父笑，浪交千載詠離騷。"]'),
('yuding-24','易水','汪遵','唐','御定全唐诗','yuding','','[]','匕首空磨事不成，誤留龍袂待琴聲。',32,'御定全唐詩/json/602.json','["匕首空磨事不成，誤留龍袂待琴聲。", "斯須卻作秦中鬼，青史徒標烈士名。"]'),
('yuding-25','嚴陵台','汪遵','唐','御定全唐诗','yuding','','[]','一釣淒涼在杳冥，故人飛詔入山扃。',32,'御定全唐詩/json/602.json','["一釣淒涼在杳冥，故人飛詔入山扃。", "終將寵辱輕軒冕，高臥五雲為客星。"]'),
('yuding-26','淮陰','汪遵','唐','御定全唐诗','yuding','','[]','秦季賢愚混不分，只應漂母識王孫。',32,'御定全唐詩/json/602.json','["秦季賢愚混不分，只應漂母識王孫。", "歸榮便累千金贈，為報當時一飯恩。"]'),
('yuding-27','雞鳴曲','汪遵','唐','御定全唐诗','yuding','','[]','金距花冠傍舍棲，清晨相叫一聲齊。',32,'御定全唐詩/json/602.json','["金距花冠傍舍棲，清晨相叫一聲齊。", "開關自有馮生計，不必天明待汝啼。"]'),
('yuding-28','采桑婦','汪遵','唐','御定全唐诗','yuding','','[]','為報躊躇陌上郎，蠶饑日晚妾心忙。',32,'御定全唐詩/json/602.json','["為報躊躇陌上郎，蠶饑日晚妾心忙。", "本來若愛黃金好，不肯攜籠更采桑。"]'),
('yuding-29','漁父','汪遵','唐','御定全唐诗','yuding','','[]','棹月眠流處處通，綠蓑葦帶混元風。',32,'御定全唐詩/json/602.json','["棹月眠流處處通，綠蓑葦帶混元風。", "靈均說盡孤高事，全與逍遙意不同。"]'),
('yuding-30','越女','汪遵','唐','御定全唐诗','yuding','','[]','玉貌何曾為浣沙，只圖勾踐獻夫差。',32,'御定全唐詩/json/602.json','["玉貌何曾為浣沙，只圖勾踐獻夫差。", "蘇台日夜唯歌舞，不覺干戈犯翠華。"]'),
('yuding-31','望思台','汪遵','唐','御定全唐诗','yuding','','[]','不憂家國任奸臣，骨肉翻為驀路人。',32,'御定全唐詩/json/602.json','["不憂家國任奸臣，骨肉翻為驀路人。", "巫蠱事行冤莫雪，九層徒築見無因。"]'),
('yuding-32','比干墓','汪遵','唐','御定全唐诗','yuding','','[]','國亂時危道不行，忠賢諫死勝謀生。',32,'御定全唐詩/json/602.json','["國亂時危道不行，忠賢諫死勝謀生。", "一沉冤骨千年後，壟水雖平恨未平。"]'),
('yuding-33','郢中','汪遵','唐','御定全唐诗','yuding','','[]','莫言白雪少人聽，高調都難稱俗情。',32,'御定全唐詩/json/602.json','["莫言白雪少人聽，高調都難稱俗情。", "不是楚詞詢宋玉，巴歌猶掩繞梁聲。"]'),
('yuding-34','北海','汪遵','唐','御定全唐诗','yuding','','[]','漢臣曾此作縲囚，茹血衣毛十九秋。',32,'御定全唐詩/json/602.json','["漢臣曾此作縲囚，茹血衣毛十九秋。", "鶴發半垂龍節在，不聞青史說封侯。"]'),
('yuding-35','招屈亭','汪遵','唐','御定全唐诗','yuding','','[]','三閭溺處殺懷王，感得荊人盡縞裳。',32,'御定全唐詩/json/602.json','["三閭溺處殺懷王，感得荊人盡縞裳。", "招屈亭邊兩重恨，遠天秋色暮蒼蒼。"]'),
('yuding-36','屈祠','汪遵','唐','御定全唐诗','yuding','','[]','不肯迂回入醉鄉，乍吞忠梗沒滄浪。',32,'御定全唐詩/json/602.json','["不肯迂回入醉鄉，乍吞忠梗沒滄浪。", "至今祠畔猿啼月，了了猶疑恨楚王。"]'),
('yuding-37','銅雀台','汪遵','唐','御定全唐诗','yuding','','[]','銅雀台成玉座空，短歌長袖盡悲風。',32,'御定全唐詩/json/602.json','["銅雀台成玉座空，短歌長袖盡悲風。", "不知仙駕歸何處，徒遣顰眉望漢宮。"]'),
('yuding-38','斑竹祠','汪遵','唐','御定全唐诗','yuding','','[]','九處煙霞九處昏，一回延首一銷魂。',32,'御定全唐詩/json/602.json','["九處煙霞九處昏，一回延首一銷魂。", "因憑直節流紅淚，圖得千秋見血痕。"]'),
('yuding-39','題李太尉平泉莊','汪遵','唐','御定全唐诗','yuding','','[]','水泉花木好高眠，嵩少縱橫滿目前。',32,'御定全唐詩/json/602.json','["水泉花木好高眠，嵩少縱橫滿目前。", "惆悵人間不平事，今朝身在海南邊。"]'),
('yuding-40','戰城南','汪遵','唐','御定全唐诗','yuding','','[]','風沙刮地塞雲愁，平旦交鋒晚未休。',32,'御定全唐詩/json/602.json','["風沙刮地塞雲愁，平旦交鋒晚未休。", "白骨又沾新戰血，青天猶列舊旄頭。"]'),
('yuding-41','延平津','汪遵','唐','御定全唐诗','yuding','','[]','三尺晶熒射鬥牛，豈隨凡手報冤讎。',32,'御定全唐詩/json/602.json','["三尺晶熒射鬥牛，豈隨凡手報冤讎。", "延平一旦為龍處，看取風雲布九州。"]'),
('yuding-42','項亭','汪遵','唐','御定全唐诗','yuding','','[]','不修仁德合文明，天道如何擬力爭。',32,'御定全唐詩/json/602.json','["不修仁德合文明，天道如何擬力爭。", "隔岸故鄉歸不得，十年空負拔山名。"]'),
('yuding-43','烏江','汪遵','唐','御定全唐诗','yuding','','[]','兵散弓殘挫虎威，單槍匹馬突重圍。',32,'御定全唐詩/json/602.json','["兵散弓殘挫虎威，單槍匹馬突重圍。", "英雄去盡羞容在，看卻江東不得歸。"]'),
('yuding-44','綠珠','汪遵','唐','御定全唐诗','yuding','','[]','大抵花顏最怕秋，南家歌歇北家愁。',32,'御定全唐詩/json/602.json','["大抵花顏最怕秋，南家歌歇北家愁。", "從來幾許如君貌，不肯如君墜玉樓。"]'),
('yuding-45','升仙橋','汪遵','唐','御定全唐诗','yuding','','[]','漢朝卿相盡風雲，司馬題橋眾又聞。',32,'御定全唐詩/json/602.json','["漢朝卿相盡風雲，司馬題橋眾又聞。", "何事不如楊得意，解搜賢哲薦明君。"]'),
('yuding-46','隋柳','汪遵','唐','御定全唐诗','yuding','','[]','夾浪分堤萬樹餘，為迎龍舸到江都。',32,'御定全唐詩/json/602.json','["夾浪分堤萬樹餘，為迎龍舸到江都。", "君看靖節高眠處，只向衡門種五株。"]'),
('yuding-47','楊柳','汪遵','唐','御定全唐诗','yuding','','[]','亞夫營畔柳濛濛，隋主堤邊四路通。',32,'御定全唐詩/json/602.json','["亞夫營畔柳濛濛，隋主堤邊四路通。", "攀折贈君還有意，翠眉輕嫩怕春風。"]'),
('yuding-48','桐江','汪遵','唐','御定全唐诗','yuding','','[]','光武重興四海寧，漢臣無不受浮榮。',32,'御定全唐詩/json/602.json','["光武重興四海寧，漢臣無不受浮榮。", "嚴陵何事輕軒冕，獨向桐江釣月明。"]'),
('yuding-49','招隱','汪遵','唐','御定全唐诗','yuding','','[]','罷聽泉聲看鹿群，丈夫才策合匡君。',32,'御定全唐詩/json/602.json','["罷聽泉聲看鹿群，丈夫才策合匡君。", "早攜書劍離岩谷，莫待蒲輪輾白雲。"]'),
('yuding-50','陳宮','汪遵','唐','御定全唐诗','yuding','','[]','椒宮荒宴竟無疑，倏忽山河盡入隋。',32,'御定全唐詩/json/602.json','["椒宮荒宴竟無疑，倏忽山河盡入隋。", "留得後庭亡國曲，至今猶與酒家吹。"]'),
('yuding-51','樊將軍廟','汪遵','唐','御定全唐诗','yuding','','[]','玉輦曾經陷楚營，漢皇心怯擬休兵。',32,'御定全唐詩/json/602.json','["玉輦曾經陷楚營，漢皇心怯擬休兵。", "當時不得將軍力，日月須分一半明。"]'),
('yuding-52','東海','汪遵','唐','御定全唐诗','yuding','','[]','漾舟雪浪映花顏，徐福攜將竟不還。',32,'御定全唐詩/json/602.json','["漾舟雪浪映花顏，徐福攜將竟不還。", "同作危時避秦客，此行何似武陵灘。"]'),
('yuding-53','昭君','汪遵','唐','御定全唐诗','yuding','','[]','漢家天子鎮寰瀛，塞北羌胡未罷兵。',32,'御定全唐詩/json/602.json','["漢家天子鎮寰瀛，塞北羌胡未罷兵。", "猛將謀臣徒自貴，蛾眉一笑塞塵清。"]'),
('yuding-54','五湖','汪遵','唐','御定全唐诗','yuding','','[]','已立平吳霸越功，片帆高揚五湖風。',32,'御定全唐詩/json/602.json','["已立平吳霸越功，片帆高揚五湖風。", "不知戰國官榮者，誰似陶朱得始終。"]'),
('yuding-55','澠池','汪遵','唐','御定全唐诗','yuding','','[]','西秦北趙各稱高，池上張筵列我曹。',32,'御定全唐詩/json/602.json','["西秦北趙各稱高，池上張筵列我曹。", "何事君王親擊缶，相如有劍可吹毛。"]'),
('yuding-56','函谷關','汪遵','唐','御定全唐诗','yuding','','[]','脫禍東奔壯氣摧，馬如飛電轂如雷。',32,'御定全唐詩/json/602.json','["脫禍東奔壯氣摧，馬如飛電轂如雷。", "當時若不聽彈鋏，那得關門半夜開。"]'),
('yuding-57','詠酒二首','汪遵','唐','御定全唐诗','yuding','','[]','九醞松醪一曲歌，本圖閑放養天和。',64,'御定全唐詩/json/602.json','["九醞松醪一曲歌，本圖閑放養天和。", "後人不識前賢意，破國亡家事甚多。", "萬事銷沈向一杯，竹門啞軋為風開。", "秋宵睡足芭蕉雨，又是江湖入夢來。"]'),
('yuding-58','蒼頡台','汪遵','唐','御定全唐诗','yuding','','[]','觀跡成文代結繩，皇風儒教浩然興。',32,'御定全唐詩/json/602.json','["觀跡成文代結繩，皇風儒教浩然興。", "幾人從此休耕釣，吟對長安雪夜燈。"]'),
('yuding-59','長城','汪遵','唐','御定全唐诗','yuding','','[]','秦築長城比鐵牢，蕃戎不敢過臨洮。',32,'御定全唐詩/json/602.json','["秦築長城比鐵牢，蕃戎不敢過臨洮。", "雖然萬里連雲際，爭及堯階三尺高。"]'),
('yuding-0','過洞庭湖','許棠','唐','御定全唐诗','yuding','','[]','驚波常不定，半日鬢堪斑。四顧疑無地，中流忽有山。',48,'御定全唐詩/json/603.json','["驚波常不定，半日鬢堪斑。四顧疑無地，中流忽有山。", "鳥高恒畏墜，帆遠卻如閑。漁父閑相引，時歌浩渺間。"]'),
('yuding-1','登渭南縣樓','許棠','唐','御定全唐诗','yuding','','[]','近甸名偏著，登城景又寬。半空分太華，極目是長安。',48,'御定全唐詩/json/603.json','["近甸名偏著，登城景又寬。半空分太華，極目是長安。", "雪助河流漲，人耕燒色殘。閑來時甚少，欲下重憑欄。"]'),
('yuding-2','送李頻之南陵主簿','許棠','唐','御定全唐诗','yuding','','[]','赴縣是還鄉，途程豈覺長。聽鶯離灞岸，蕩槳入陵陽。',48,'御定全唐詩/json/603.json','["赴縣是還鄉，途程豈覺長。聽鶯離灞岸，蕩槳入陵陽。", "野蕨生公署，閑雲拂印床。晴天調膳外，垂釣有池塘。"]'),
('yuding-3','寫懷','許棠','唐','御定全唐诗','yuding','','[]','汩沒與辛勤，全鐘在此身。半生為下客，終老托何人。',48,'御定全唐詩/json/603.json','["汩沒與辛勤，全鐘在此身。半生為下客，終老托何人。", "兩鬢關中改，千岩海上春。青雲知有路，自是致無因。"]'),
('yuding-4','過中條山','許棠','唐','御定全唐诗','yuding','','[]','徒為經異嶽，不得訪靈蹤。日盡行難盡，千重複萬重。',48,'御定全唐詩/json/603.json','["徒為經異嶽，不得訪靈蹤。日盡行難盡，千重複萬重。", "雲垂多作雨，雷動半和鐘。孤竹人藏處，無因認本峰。"]'),
('yuding-5','早發洛中','許棠','唐','御定全唐诗','yuding','','[]','半夜發清洛，不知過石橋。雲增中嶽大，樹隱上陽遙。',48,'御定全唐詩/json/603.json','["半夜發清洛，不知過石橋。雲增中嶽大，樹隱上陽遙。", "塹黑初沉月，河明欲認潮。孤村人尚夢，無處暫停橈。"]'),
('yuding-6','汝州郡樓望嵩山','許棠','唐','御定全唐诗','yuding','','[]','不共眾山同，岧嶢出迥空。幾層高鳥外，萬仞一樓中。',48,'御定全唐詩/json/603.json','["不共眾山同，岧嶢出迥空。幾層高鳥外，萬仞一樓中。", "水落難歸地，雲籬便逐風。唯應霄漢客，絕頂路方通。"]'),
('yuding-7','將歸江南留別友人','許棠','唐','御定全唐诗','yuding','','[]','連春不得意，所業已疑非。舊國亂離後，新年惆悵歸。',48,'御定全唐詩/json/603.json','["連春不得意，所業已疑非。舊國亂離後，新年惆悵歸。", "雪開還楚地，花惹別秦衣。江徼多留滯，高秋會恐違。"]'),
('yuding-8','塞外書事','許棠','唐','御定全唐诗','yuding','','[]','征路出窮邊，孤吟傍戍煙。河光深蕩塞，磧色迥連天。',48,'御定全唐詩/json/603.json','["征路出窮邊，孤吟傍戍煙。河光深蕩塞，磧色迥連天。", "殘日沉雕外，驚蓬到馬前。空懷釣魚所，未定蔔歸年。"]'),
('yuding-9','日暮江上','許棠','唐','御定全唐诗','yuding','','[]','孤帆收廣岸，落照在遙峰。南北渡人少，高低歸鳥重。',48,'御定全唐詩/json/603.json','["孤帆收廣岸，落照在遙峰。南北渡人少，高低歸鳥重。", "潮回沙出樹，雨過浦沉鐘。漁父雖相問，那能話所從。"]'),
('yuding-10','客行','許棠','唐','御定全唐诗','yuding','','[]','旅食唯草草，此生誰我同。故園魂夢外，長路別離中。',48,'御定全唐詩/json/603.json','["旅食唯草草，此生誰我同。故園魂夢外，長路別離中。", "人事萍隨水，年光鳥過空。欲吟先落淚，多是怨途窮。"]'),
('yuding-11','送李員外知揚子州留務','許棠','唐','御定全唐诗','yuding','','[]','帝命分留務，東南向楚天。幾程回送騎，中路見迎船。',48,'御定全唐詩/json/603.json','["帝命分留務，東南向楚天。幾程回送騎，中路見迎船。", "冶例開山鑄，民多酌海煎。青雲名素重，此去豈經年。"]'),
('yuding-12','春暮途次華山下','許棠','唐','御定全唐诗','yuding','','[]','他皆宴牡丹，獨又出長安。遠道行非易，無圖住自難。',48,'御定全唐詩/json/603.json','["他皆宴牡丹，獨又出長安。遠道行非易，無圖住自難。", "離城風已暖，近嶽雨翻寒。此去知誰顧，閑吟只自寬。"]'),
('yuding-13','旅次滑台投獻陸侍禦','許棠','唐','御定全唐诗','yuding','','[]','已是鴻來日，堪驚卻背秦。天遙三楚樹，路遠兩河人。',48,'御定全唐詩/json/603.json','["已是鴻來日，堪驚卻背秦。天遙三楚樹，路遠兩河人。", "旅夢難歸隱，吟魂不在身。霜台欹冠豸，賴許往來頻。"]'),
('yuding-14','重歸江南','許棠','唐','御定全唐诗','yuding','','[]','無成歸故里，不似在他鄉。歲月逐流水，山川空夕陽。',48,'御定全唐詩/json/603.json','["無成歸故里，不似在他鄉。歲月逐流水，山川空夕陽。", "回潮迷古渡，迸竹過鄰牆。耆舊休存省，胡為止淚行。"]'),
('yuding-15','寄黔南李校書','許棠','唐','御定全唐诗','yuding','','[]','從戎巫峽外，吟興更應多。郡響蠻江漲，山昏蜀雨過。',48,'御定全唐詩/json/603.json','["從戎巫峽外，吟興更應多。郡響蠻江漲，山昏蜀雨過。", "公筵饒越味，俗土尚巴歌。中夜懷吳夢，知經灩澦波。"]'),
('yuding-16','東歸留辭沈侍郎','許棠','唐','御定全唐诗','yuding','','[]','一第久乖期，深心已自疑。滄江歸恨遠，紫閣別愁遲。',48,'御定全唐詩/json/603.json','["一第久乖期，深心已自疑。滄江歸恨遠，紫閣別愁遲。", "稽古成何事，龍鍾負已知。依門非近日，不慮舊恩移。"]'),
('yuding-17','題開明裏友人居','許棠','唐','御定全唐诗','yuding','','[]','城中塵外住，入望是田家。井出深山水，闌藏異國花。',48,'御定全唐詩/json/603.json','["城中塵外住，入望是田家。井出深山水，闌藏異國花。", "風巢和鳥動，雪竹向人斜。來往唯君熟，鄉園共海涯。"]'),
('yuding-18','遣懷','許棠','唐','御定全唐诗','yuding','','[]','此生何處遂，屑屑複悠悠。舊國歸無計，他鄉夢亦愁。',48,'御定全唐詩/json/603.json','["此生何處遂，屑屑複悠悠。舊國歸無計，他鄉夢亦愁。", "飛塵長滿眼，衰發暗添頭。章句非經濟，終難動五侯。"]'),
('yuding-19','送龍州樊使君','許棠','唐','御定全唐诗','yuding','','[]','曾見邛人說，龍州地未深。碧溪飛白鳥，紅旆映青林。',48,'御定全唐詩/json/603.json','["曾見邛人說，龍州地未深。碧溪飛白鳥，紅旆映青林。", "土產唯宜藥，王租只貢金。政成開宴日，誰伴使君吟。"]'),
('yuding-20','寄盩厔薛能少府','許棠','唐','御定全唐诗','yuding','','[]','滿縣唯雲水，何曾似近畿。曉庭猿集慣，寒署吏衙稀。',48,'御定全唐詩/json/603.json','["滿縣唯雲水，何曾似近畿。曉庭猿集慣，寒署吏衙稀。", "冰色封深澗，樵聲出紫微。時聞迎隱者，依舊著山衣。"]'),
('yuding-21','送李左丞巡邊','許棠','唐','御定全唐诗','yuding','','[]','狂戎侵內地，左轄去蕭關。走馬沖邊雪，鳴鞞動塞山。',48,'御定全唐詩/json/603.json','["狂戎侵內地，左轄去蕭關。走馬沖邊雪，鳴鞞動塞山。", "風收枯草定，月滿廣沙閑。西繞河蘭匝，應多隔歲還。"]'),
('yuding-22','題青山館','許棠','唐','御定全唐诗','yuding','','[]','境概殊諸處，依然是謝家。遺文齊日月，舊井照煙霞。',48,'御定全唐詩/json/603.json','["境概殊諸處，依然是謝家。遺文齊日月，舊井照煙霞。", "水隔平蕪遠，山橫度鳥斜。無人能此隱，來往謾興嗟。"]'),
('yuding-23','雁門關野望','許棠','唐','御定全唐诗','yuding','','[]','高關閑獨望，望久轉愁人。紫塞唯多雪，胡山不盡春。',48,'御定全唐詩/json/603.json','["高關閑獨望，望久轉愁人。紫塞唯多雪，胡山不盡春。", "河遙分斷野，樹亂起飛塵。時見東來騎，心知近別秦。"]'),
('yuding-24','五原書事','許棠','唐','御定全唐诗','yuding','','[]','西出黃雲外，東懷白浪遙。星河愁立夜，雷電獨行朝。',48,'御定全唐詩/json/603.json','["西出黃雲外，東懷白浪遙。星河愁立夜，雷電獨行朝。", "磧迥人防寇，天空雁避雕。如何非戰卒，弓劍不離腰。"]'),
('yuding-25','送從弟歸泉州','許棠','唐','御定全唐诗','yuding','','[]','問省歸南服，懸帆任北風。何山猶見雪，半路已無鴻。',48,'御定全唐詩/json/603.json','["問省歸南服，懸帆任北風。何山猶見雪，半路已無鴻。", "瘴雜春雲重，星垂夜海空。往來如不住，亦是一年中。"]'),
('yuding-26','留別故人','許棠','唐','御定全唐诗','yuding','','[]','殊立本不偶，非唯今所難。無門閑共老，盡日泣相看。',48,'御定全唐詩/json/603.json','["殊立本不偶，非唯今所難。無門閑共老，盡日泣相看。", "鳥畏聞鶗鴂，花慚背牡丹。何人知此計，復議出長安。"]'),
('yuding-27','塞下二首','許棠','唐','御定全唐诗','yuding','','[]','胡虜偏狂悍，邊兵不敢閑。防秋朝伏弩，縱火夜搜山。',96,'御定全唐詩/json/603.json','["胡虜偏狂悍，邊兵不敢閑。防秋朝伏弩，縱火夜搜山。", "雁逆風鼙振，沙飛獵騎還。安西雖有路，難更出陽關。", "征役已不定，又緣無定河。塞深烽砦密，山亂犬羊多。", "漢卒聞笳泣，胡兒擊劍歌。番情終未測，今昔謾言和。"]'),
('yuding-28','題張喬升平裏居','許棠','唐','御定全唐诗','yuding','','[]','下馬似無人，開門只一身。心同孤鶴靜，行過老僧真。',48,'御定全唐詩/json/603.json','["下馬似無人，開門只一身。心同孤鶴靜，行過老僧真。", "亂水藏幽徑，高原隔遠津。匡廬曾共隱，相見自相親。"]'),
('yuding-29','題鄭拾遺南齋','許棠','唐','御定全唐诗','yuding','','[]','明時無事諫，豈是隱明君。每值離丹陛，多陪宴白雲。',48,'御定全唐詩/json/603.json','["明時無事諫，豈是隱明君。每值離丹陛，多陪宴白雲。", "門連蕭洞僻，地與曲江分。滿院皆檉竹，期棲鸞鶴群。"]'),
('yuding-30','渭上送人南歸','許棠','唐','御定全唐诗','yuding','','[]','遠役與歸愁，同來渭水頭。南浮應到海，北去阻無州。',48,'御定全唐詩/json/603.json','["遠役與歸愁，同來渭水頭。南浮應到海，北去阻無州。", "楚雨天連地，胡風夏甚秋。江人如見問，為話複貧遊。"]'),
('yuding-31','寄睦州陸郎中','許棠','唐','御定全唐诗','yuding','','[]','下國多高趣，終年半是吟。海濤通越分，部伍雜閩音。',48,'御定全唐詩/json/603.json','["下國多高趣，終年半是吟。海濤通越分，部伍雜閩音。", "曉郭雲藏市，春山鳥護林。東浮雖未遂，日日至中心。"]'),
('yuding-32','投徐端公','許棠','唐','御定全唐诗','yuding','','[]','無謀尋舊友，強喜亦如愁。丹桂阻丹懇，白衣成白頭。',48,'御定全唐詩/json/603.json','["無謀尋舊友，強喜亦如愁。丹桂阻丹懇，白衣成白頭。", "窮吳迷釣業，大漢事貧游。霄漢期提引，龍鍾未擬休。"]'),
('yuding-33','出塞門','許棠','唐','御定全唐诗','yuding','','[]','步步經戎虜，防兵不離身。山多曾戰處，路斷野行人。',48,'御定全唐詩/json/603.json','["步步經戎虜，防兵不離身。山多曾戰處，路斷野行人。", "暴雨聲同瀑，奔沙勢異塵。片時懷萬慮，白髮數莖新。"]'),
('yuding-34','新年呈友','許棠','唐','御定全唐诗','yuding','','[]','一月月相似，一年年不同。清晨窺古鏡，旅貌近衰翁。',48,'御定全唐詩/json/603.json','["一月月相似，一年年不同。清晨窺古鏡，旅貌近衰翁。", "處世閑難得，關身事半空。浮生能幾許，莫惜醉春風。"]'),
('yuding-35','銀州北書事','許棠','唐','御定全唐诗','yuding','','[]','南辭採石遠，北背乞銀深。磧路雖多險，江人不廢吟。',48,'御定全唐詩/json/603.json','["南辭採石遠，北背乞銀深。磧路雖多險，江人不廢吟。", "雕依孤堠立，鷗向迥沙沈。因共邊人熟，行行起戰心。"]'),
('yuding-36','寄趙能卿','許棠','唐','御定全唐诗','yuding','','[]','我命同君命，君詩似我詩。俱無中道計，各失半生期。',48,'御定全唐詩/json/603.json','["我命同君命，君詩似我詩。俱無中道計，各失半生期。", "素業滄江遠，清時白髮垂。蹉跎一如此，何處卜棲遲。"]'),
('yuding-37','夏州道中','許棠','唐','御定全唐诗','yuding','','[]','茫茫沙漠廣，漸遠赫連城。堡迥烽相見，河移浪旋生。',48,'御定全唐詩/json/603.json','["茫茫沙漠廣，漸遠赫連城。堡迥烽相見，河移浪旋生。", "無蟬嘶折柳，有寇似防兵。不耐饑寒迫，終誰至此行。"]'),
('yuding-38','經故楊太尉舊居','許棠','唐','御定全唐诗','yuding','','[]','在漢信垂功，于唐道更隆。一川留古跡，多代仰高風。',48,'御定全唐詩/json/603.json','["在漢信垂功，于唐道更隆。一川留古跡，多代仰高風。", "樹折巢墮鳥，階荒草覆蟲。行人過豈少，獨駐夕陽中。"]'),
('yuding-39','東歸次採石江','許棠','唐','御定全唐诗','yuding','','[]','東下經牛渚，依然是故關。客程臨岸盡，鄉思入鷗閑。',48,'御定全唐詩/json/603.json','["東下經牛渚，依然是故關。客程臨岸盡，鄉思入鷗閑。", "雨漲巴來浪，雲增楚際山。漁翁知未達，相顧不開顏。"]'),
('yuding-40','隴上書事','許棠','唐','御定全唐诗','yuding','','[]','城疊連雲壑，人家似隱居。樹飛鸚鵡眾，川下鶺鴒疏。',48,'御定全唐詩/json/603.json','["城疊連雲壑，人家似隱居。樹飛鸚鵡眾，川下鶺鴒疏。", "滴夢關山雨，資餐隴水魚。誰知江徼客，此景倍相於。"]'),
('yuding-41','陳情獻江西李常侍五首','許棠','唐','御定全唐诗','yuding','','[]','二十二三年，游秦複滯燕。徒陪群彥後，自苦此生前。',240,'御定全唐詩/json/603.json','["二十二三年，游秦複滯燕。徒陪群彥後，自苦此生前。", "徑折啼猿樹，岩荒噴月泉。東堂曾受薦，垂白志猶堅。", "淅淅複棲棲，人間只自迷。終年愁遠道，到老去何蹊。", "始見紅葉落，又聞黃鳥啼。不因趨大旆，誰肯暫提攜。", "童蒙即苦辛，未識杏園春。謾倚無為日，還成不偶人。", "鄉程長恨遠，旅夢亦愁貧。天地雖雲廣，殊難寄此身。", "春闈久已滯，秋賦又逢停。選士疑長阻，傷時自不寧。", "秦城還逐夢，楚徼影隨形。此去吟雖苦，何人更肯聽。", "孤立時全塞，求名勢轉難。身多離下國，分合阻長安。", "越鳥啼春早，蠻花送雨寒。丘門沾顧重，未別欲闌幹。"]'),
('yuding-42','經八合阪','許棠','唐','御定全唐诗','yuding','','[]','躡險入高空，初疑勢不窮。又緣千嶂盡，還共七盤同。',48,'御定全唐詩/json/603.json','["躡險入高空，初疑勢不窮。又緣千嶂盡，還共七盤同。", "下辨東流水，平隨北去鴻。天然無此道，應免患窮通。"]'),
('yuding-43','送友人北游','許棠','唐','御定全唐诗','yuding','','[]','北出陰關去，何人肯待君。無青山擁晉，半濁水通汾。',48,'御定全唐詩/json/603.json','["北出陰關去，何人肯待君。無青山擁晉，半濁水通汾。", "雁塞雖多雁，雲州卻少雲。茲游殊不惡，莫恨暫離群。"]'),
('yuding-44','登淩歊台','許棠','唐','御定全唐诗','yuding','','[]','平蕪望已極，況複倚淩歊。江截吳山斷，天臨楚澤遙。',48,'御定全唐詩/json/603.json','["平蕪望已極，況複倚淩歊。江截吳山斷，天臨楚澤遙。", "雲帆高出樹，水市迥分橋。立久斜陽盡，無言似寂寥。"]'),
('yuding-45','曲江三月三日','許棠','唐','御定全唐诗','yuding','','[]','滿國賞芳辰，飛蹄複走輪。好花皆折盡，明日恐無春。',48,'御定全唐詩/json/603.json','["滿國賞芳辰，飛蹄複走輪。好花皆折盡，明日恐無春。", "鳥避連雲幄，魚驚遠浪塵。如何當此節，獨自作愁人。"]'),
('yuding-46','贈棲白上人','許棠','唐','御定全唐诗','yuding','','[]','閑身卻不閑，日日對天顏。已住城中寺，難歸海上山。',48,'御定全唐詩/json/603.json','["閑身卻不閑，日日對天顏。已住城中寺，難歸海上山。", "詩傳華夏外，偈布市朝間。欲問空門事，空門豈有關。"]'),
('yuding-47','野步','許棠','唐','御定全唐诗','yuding','','[]','閑賞步易遠，野吟聲自高。路無人到跡，林有鶴遺毛。',48,'御定全唐詩/json/603.json','["閑賞步易遠，野吟聲自高。路無人到跡，林有鶴遺毛。", "物外趣都別，塵中心枉勞。沿溪收墮果，坐石喚饑猱。"]'),
('yuding-48','過湍溝谷','許棠','唐','御定全唐诗','yuding','','[]','西去窮胡處，岩崖境不常。石形相對聳，天勢一條長。',48,'御定全唐詩/json/603.json','["西去窮胡處，岩崖境不常。石形相對聳，天勢一條長。", "棧底鳴流水，林端斂夕陽。雖隨兵馬至，未免畏豺狼。"]'),
('yuding-49','送友人游蜀','許棠','唐','御定全唐诗','yuding','','[]','巴興千萬尋，此去若為心。蟋蟀既將定，彌猴應正吟。',48,'御定全唐詩/json/603.json','["巴興千萬尋，此去若為心。蟋蟀既將定，彌猴應正吟。", "劍門秋斷雁，褒穀夜多砧。自古西南路，艱難直至今。"]'),
('yuding-50','題秦州城','許棠','唐','御定全唐诗','yuding','','[]','聖澤滋遐徼，河堤四向通。大荒收虜帳，遺土複秦風。',48,'御定全唐詩/json/603.json','["聖澤滋遐徼，河堤四向通。大荒收虜帳，遺土複秦風。", "亂燒迷歸路，遙山似夢中。此時懷感切，極目思無窮。"]'),
('yuding-51','寄敬亭山清越上人','許棠','唐','御定全唐诗','yuding','','[]','南朝山半寺，謝脁故鄉鄰。嶺上非無主，秋詩複有人。',48,'御定全唐詩/json/603.json','["南朝山半寺，謝脁故鄉鄰。嶺上非無主，秋詩複有人。", "高禪星月近，野火虎狼馴。舊許陪閑社，終應待此身。"]'),
('yuding-52','秋江霽望','許棠','唐','御定全唐诗','yuding','','[]','高秋偏入望，霽景倍關情。落木滿江水，離人懷渭城。',48,'御定全唐詩/json/603.json','["高秋偏入望，霽景倍關情。落木滿江水，離人懷渭城。", "山高孤戍斷，野極暮天平。漁父時相問，羞真道姓名。"]'),
('yuding-53','隴州旅中書事寄李中丞','許棠','唐','御定全唐诗','yuding','','[]','三伏客吟過，長安未擬還。蛩聲秋不動，燕別思仍閑。',48,'御定全唐詩/json/603.json','["三伏客吟過，長安未擬還。蛩聲秋不動，燕別思仍閑。", "亂葉隨寒雨，孤蟾起暮關。經時高嶺外，來往旆旌間。"]'),
('yuding-54','秋日歸舊山','許棠','唐','御定全唐诗','yuding','','[]','山雲蟬滿樹，欲住更何安。上國回將晚，孤峰別自難。',48,'御定全唐詩/json/603.json','["山雲蟬滿樹，欲住更何安。上國回將晚，孤峰別自難。", "磧遙鴻未到，江近夜先寒。泉石雖堪戀，行人不願看。"]'),
('yuding-55','下黃耳盤','許棠','唐','御定全唐诗','yuding','','[]','獨下黃盤路，多虞部落連。雲晴仍著地，樹古自參天。',48,'御定全唐詩/json/603.json','["獨下黃盤路，多虞部落連。雲晴仍著地，樹古自參天。", "亂鳥飛人上，驚麋起馬前。行行無郡邑，唯見虎狼煙。"]'),
('yuding-56','旅懷','許棠','唐','御定全唐诗','yuding','','[]','終年唯旅舍，只似已無家。白髮除還出，丹霄去轉賒。',48,'御定全唐詩/json/603.json','["終年唯旅舍，只似已無家。白髮除還出，丹霄去轉賒。", "夏游窮塞路，春醉負秦花。應是穹蒼意，空教老若耶。"]'),
('yuding-57','題金山寺','許棠','唐','御定全唐诗','yuding','','[]','四面波濤匝，中樓日月鄰。上窮如出世，下瞷忽驚神。',48,'御定全唐詩/json/603.json','["四面波濤匝，中樓日月鄰。上窮如出世，下瞷忽驚神。", "刹礙長空鳥，船通外國人。房房皆疊石，風掃永無塵。"]'),
('yuding-58','送王侍禦赴宣城','許棠','唐','御定全唐诗','yuding','','[]','朝回離九陌，島外賞殘春。經宿留閑客，看雲作主人。',48,'御定全唐詩/json/603.json','["朝回離九陌，島外賞殘春。經宿留閑客，看雲作主人。", "時清難議隱，位重亦甘貧。岩洞真仙境，應休別臥鄰。"]'),
('yuding-59','題汧湖二首','許棠','唐','御定全唐诗','yuding','','[]','偶得湖中趣，都忘隴坻愁。邊聲風下雁，楚思浪移舟。',96,'御定全唐詩/json/603.json','["偶得湖中趣，都忘隴坻愁。邊聲風下雁，楚思浪移舟。", "靜極亭連寺，涼多島近樓。吟遊終不厭，還似曲江頭。", "隴首時無事，湖邊日縱吟。遊魚來複去，浴鳥出還沉。", "蜃氣藏孤嶼，波光到遠林。無人見垂釣，暗起洞庭心。"]'),
('yuding-60','宿青山館','許棠','唐','御定全唐诗','yuding','','[]','下馬青山下，無言有所思。雲藏李白墓，苔暗謝公詩。',48,'御定全唐詩/json/603.json','["下馬青山下，無言有所思。雲藏李白墓，苔暗謝公詩。", "烈燒飛荒野，棲鳧宿廣陂。東來與西去，皆是不閒時。"]'),
('yuding-61','宿同州厲評事舊業寄華下','許棠','唐','御定全唐诗','yuding','','[]','從戎依遠地，無日見家山。地近風沙處，城當甸服間。',48,'御定全唐詩/json/603.json','["從戎依遠地，無日見家山。地近風沙處，城當甸服間。", "阻河通渭水，曲苑帶秦關。待月登樓夜，何人相伴閑。"]'),
('yuding-62','聞蟬十二韻','許棠','唐','御定全唐诗','yuding','','[]','造化生微物，常能應候鳴。初離何處樹，又發去年聲。',144,'御定全唐詩/json/603.json','["造化生微物，常能應候鳴。初離何處樹，又發去年聲。", "未蛻唯愁動，才飛似解驚。聞來鄰海徼，恨起過邊城。", "騷屑隨風遠，悠揚類雪輕。報秋涼漸至，嘶月思偏清。", "互默疑相答，微搖似欲行。繁音人已厭，朽殼蟻猶爭。", "朝士嚴冠飾，宮嬪逞鬢名。亂依西日噪，多引北歸情。", "筱露凝潛吸，蛛絲忽迸縈。此時吟立者，不覺萬愁生。"]'),
('yuding-63','冬杪歸陵陽別業五首','許棠','唐','御定全唐诗','yuding','','[]','無媒歸別業，所向自乖心。閭裏故人少，田園荒草深。',240,'御定全唐詩/json/603.json','["無媒歸別業，所向自乖心。閭裏故人少，田園荒草深。", "浪翻全失岸，竹迸別成林。鷗鳥猶相識，時來聽苦吟。", "眠雲終未遂，策馬暫休期。上國勞魂夢，中心甚別離。", "冰封岩溜斷，雪壓砌松欹。骨肉嗟名晚，看歸卻淚垂。", "學劍雖無術，吟詩似有魔。已貧甘事晚，臨老愛閑多。", "雞犬唯隨鹿，兒童只衣蓑。時因尋野叟，狂醉複狂歌。", "鄉國亂離後，交親半旅遊。遠聞誠可念，歸見豈無愁。", "敗葦迷荒徑，寒蓑沒壞舟。衡門終不掩，倚杖看波流。", "游秦複滯燕，不覺近衰年。旅貌同柴毀，行衣對骨穿。", "籬寒多啄雀，木落斷浮煙。楚夜聞鳴雁，猶疑在塞天。"]'),
('yuding-64','送王侍禦赴宣城','許棠','唐','御定全唐诗','yuding','','[]','戴豸卻驅雞，東南上句溪。路過金穀口，帆轉石城西。',48,'御定全唐詩/json/603.json','["戴豸卻驅雞，東南上句溪。路過金穀口，帆轉石城西。", "水樹連天暗，山禽繞郡啼。江人諳舊化，那複俟招攜。"]'),
('yuding-65','春日烏延道中','許棠','唐','御定全唐诗','yuding','','[]','邊窮厄未窮，複此逐歸鴻。去路多相似，行人半不同。',48,'御定全唐詩/json/603.json','["邊窮厄未窮，複此逐歸鴻。去路多相似，行人半不同。", "山川藏北狄，草木背東風。虛負男兒志，無因立戰功。"]'),
('yuding-66','寄華陰劉拾遺','許棠','唐','御定全唐诗','yuding','','[]','堅心持諫諍，自古亦艱難。寄邑雖行化，眠雲似去官。',48,'御定全唐詩/json/603.json','["堅心持諫諍，自古亦艱難。寄邑雖行化，眠雲似去官。", "河分中野斷，嶽入半天寒。瀑布冰成日，誰陪吟複看。"]'),
('yuding-67','憶江南','許棠','唐','御定全唐诗','yuding','','[]','南楚西秦遠，名遲別歲深。欲歸難遂去，閑憶自成吟。',48,'御定全唐詩/json/603.json','["南楚西秦遠，名遲別歲深。欲歸難遂去，閑憶自成吟。", "雷電閑傾雨，猿猱鬥墮林。眠雲機尚在，未忍負初心。"]'),
('yuding-0','送前汝州李侍禦罷歸宣城','許棠','唐','御定全唐诗','yuding','','[]','吟詩早得名，戴豸又加榮。下國閑歸去，他人少此情。',48,'御定全唐詩/json/604.json','["吟詩早得名，戴豸又加榮。下國閑歸去，他人少此情。", "雲移寒嶠出，燒夾夜江明。重引池塘思，還登謝脁城。"]'),
('yuding-1','失題','許棠','唐','御定全唐诗','yuding','','[]','獨夜長城下，孤吟近北辰。半天初去雁，窮磧遠來人。',48,'御定全唐詩/json/604.json','["獨夜長城下，孤吟近北辰。半天初去雁，窮磧遠來人。", "月黯氛埃積，風膻帳幕鄰。惟聞防虜寇，不語暗傷神。"]'),
('yuding-2','送裴拾遺宰下邽','許棠','唐','御定全唐诗','yuding','','[]','受謫因廷諫，茲行不出關。直廬辭玉陛，上馬向仙山。',48,'御定全唐詩/json/604.json','["受謫因廷諫，茲行不出關。直廬辭玉陛，上馬向仙山。", "地古桑麻廣，城偏僕禦閑。縣齋高枕臥，猶夢犯天顏。"]'),
('yuding-3','隗囂宮晚望','許棠','唐','御定全唐诗','yuding','','[]','西顧伊蘭近，方驚滯極邊。水隨空穀轉，山向夕陽偏。',48,'御定全唐詩/json/604.json','["西顧伊蘭近，方驚滯極邊。水隨空穀轉，山向夕陽偏。", "磧鳥多依地，胡雲不滿天。秋風動衰草，只覺犬羊膻。"]'),
('yuding-4','江上行','許棠','唐','御定全唐诗','yuding','','[]','片席隨高鳥，連天積浪間。葦寬雲不匝，風廣雨無閑。',48,'御定全唐詩/json/604.json','["片席隨高鳥，連天積浪間。葦寬雲不匝，風廣雨無閑。", "戍影臨孤浦，潮痕在半山。東原歸未得，荏苒滯江關。"]'),
('yuding-5','登山','許棠','唐','御定全唐诗','yuding','','[]','信步上鳥道，不知身忽高。近空無世界，當楚見波濤。',48,'御定全唐詩/json/604.json','["信步上鳥道，不知身忽高。近空無世界，當楚見波濤。", "頂峭松多瘦，崖懸石盡牢。獼猴呼獨散，隔水向人號。"]'),
('yuding-6','哭宣城元征君','許棠','唐','御定全唐诗','yuding','','[]','高眠終不起，遠趣固難知。琴劍今無主，園林舊許誰。',48,'御定全唐詩/json/604.json','["高眠終不起，遠趣固難知。琴劍今無主，園林舊許誰。", "苔封僧坐石，葦漲鶴翹池。後代傳青史，方欽道德垂。"]'),
('yuding-7','寄建州姚員外','許棠','唐','御定全唐诗','yuding','','[]','誣譖遭遐謫，明君即自知。鄉遙辭劍外，身獨向天涯。',48,'御定全唐詩/json/604.json','["誣譖遭遐謫，明君即自知。鄉遙辭劍外，身獨向天涯。", "嶺堠蠻雲積，閩空瘴雨垂。南來終不遂，日探北歸期。"]'),
('yuding-8','送厲校書從事鳳翔','許棠','唐','御定全唐诗','yuding','','[]','赴辟依丞相，超榮事豈同。城池當隴右，山水是關中。',48,'御定全唐詩/json/604.json','["赴辟依丞相，超榮事豈同。城池當隴右，山水是關中。", "日有來巴使，秋高出塞鴻。旬休隨大旆，應到九成宮。"]'),
('yuding-9','春夜同厲文學先輩會宿','許棠','唐','御定全唐诗','yuding','','[]','江漢久分路，京關重聚吟。更為他夜約，方盡昔年心。',48,'御定全唐詩/json/604.json','["江漢久分路，京關重聚吟。更為他夜約，方盡昔年心。", "月隔明河遠，花藏宿鳥深。無眠將及曙，多是說山陰。"]'),
('yuding-10','長安書情','許棠','唐','御定全唐诗','yuding','','[]','疏散過閒人，同人不在秦。近來驚白髮，方解惜青春。',48,'御定全唐詩/json/604.json','["疏散過閒人，同人不在秦。近來驚白髮，方解惜青春。", "僻寺居將遍，權門到絕因。行藏如此輩，何以謂謀身。"]'),
('yuding-11','過故洛城','許棠','唐','御定全唐诗','yuding','','[]','七百數還窮，城池一旦空。夕陽唯照草，危堞不勝風。',48,'御定全唐詩/json/604.json','["七百數還窮，城池一旦空。夕陽唯照草，危堞不勝風。", "岸斷河聲別，田荒野色同。去來皆過客，何處問遺宮。"]'),
('yuding-12','寄廬山賈處士','許棠','唐','御定全唐诗','yuding','','[]','時泰亦高眠，人皆謂不然。窮經休望辟，餌術止期仙。',48,'御定全唐詩/json/604.json','["時泰亦高眠，人皆謂不然。窮經休望辟，餌術止期仙。", "彭蠡波涵月，爐峰雪照天。常聞風雨夜，到曉在漁船。"]'),
('yuding-13','下第東歸留別鄭侍郎','許棠','唐','御定全唐诗','yuding','','[]','無才副至公，豈是命難通。分合吟詩老，家宜逐浪空。',48,'御定全唐詩/json/604.json','["無才副至公，豈是命難通。分合吟詩老，家宜逐浪空。", "別心懸闕下，歸念極吳東。唯畏重回日，初情恐不同。"]'),
('yuding-14','泗上早發','許棠','唐','御定全唐诗','yuding','','[]','獨起無人見，長河夜泛時。平蕪疑自動，落月似相隨。',48,'御定全唐詩/json/604.json','["獨起無人見，長河夜泛時。平蕪疑自動，落月似相隨。", "楚外離空早，關西去已遲。漁歌聞不絕，卻軫洞庭思。"]'),
('yuding-15','贈天臺僧','許棠','唐','御定全唐诗','yuding','','[]','赤城霞外寺，不忘舊登年。石上吟分海，樓中語近天。',48,'御定全唐詩/json/604.json','["赤城霞外寺，不忘舊登年。石上吟分海，樓中語近天。", "重遊空有夢，再隱定無緣。獨夜休行道，星辰靜照禪。"]'),
('yuding-16','冬夜與友人會宿','許棠','唐','御定全唐诗','yuding','','[]','君初離雁塞，我久滯雕陰。隔閏俱勞夢，通宵各話心。',48,'御定全唐詩/json/604.json','["君初離雁塞，我久滯雕陰。隔閏俱勞夢，通宵各話心。", "禁風吹漏出，原樹映星沉。白晝常多事，無妨到曉吟。"]'),
('yuding-17','送元遂上人歸吳中','許棠','唐','御定全唐诗','yuding','','[]','落發在王畿，承恩著紫衣。印心誰受請，講疏自攜歸。',48,'御定全唐詩/json/604.json','["落發在王畿，承恩著紫衣。印心誰受請，講疏自攜歸。", "泛浦龍驚錫，禪雲虎繞扉。吳中知久別，庵樹想成圍。"]'),
('yuding-18','贈志空上人','許棠','唐','御定全唐诗','yuding','','[]','了了在心中，南宗與北宗。行高無外染，骨瘦是真容。',48,'御定全唐詩/json/604.json','["了了在心中，南宗與北宗。行高無外染，骨瘦是真容。", "飯野盂埋雪，禪雲杖倚松。常修不住性，必擬老何峰。"]'),
('yuding-19','邊城晚望','許棠','唐','御定全唐诗','yuding','','[]','廣漠杳無窮，孤城四面空。馬行高磧上，日墮迥沙中。',48,'御定全唐詩/json/604.json','["廣漠杳無窮，孤城四面空。馬行高磧上，日墮迥沙中。", "逼曉人移帳，當川樹列風。迢迢河外路，知直去崆峒。"]'),
('yuding-20','汴上暮秋','許棠','唐','御定全唐诗','yuding','','[]','獨立長堤上，西風滿客衣。日臨秋草廣，山接遠天微。',48,'御定全唐詩/json/604.json','["獨立長堤上，西風滿客衣。日臨秋草廣，山接遠天微。", "岸葉隨波盡，沙雲與鳥飛。秦人寧有素，去意自知歸。"]'),
('yuding-21','春日言懷','許棠','唐','御定全唐诗','yuding','','[]','東風萬物新，獨未到幽人。賦命自多蹇，陽和非不均。',48,'御定全唐詩/json/604.json','["東風萬物新，獨未到幽人。賦命自多蹇，陽和非不均。", "五陵三月暮，百越一家貧。早誤閑眠處，無愁異此身。"]'),
('yuding-22','奉天寒食書事','許棠','唐','御定全唐诗','yuding','','[]','處處無煙火，人家似暫空。曉林花落雨，寒穀鳥啼風。',48,'御定全唐詩/json/604.json','["處處無煙火，人家似暫空。曉林花落雨，寒穀鳥啼風。", "故里芳洲外，殘春甸服中。誰知獨西去，步步泣途窮。"]'),
('yuding-23','長安寓居','許棠','唐','御定全唐诗','yuding','','[]','貧寄帝城居，交朋日自疏。愁迎離磧雁，夢逐出關書。',48,'御定全唐詩/json/604.json','["貧寄帝城居，交朋日自疏。愁迎離磧雁，夢逐出關書。", "經雨蟬聲盡，兼風杵韻餘。誰知江徼塞，所憶在樵漁。"]'),
('yuding-24','寫懷','許棠','唐','御定全唐诗','yuding','','[]','此生居此世，堪笑複堪悲。在處有岐路，何人無別離。',48,'御定全唐詩/json/604.json','["此生居此世，堪笑複堪悲。在處有岐路，何人無別離。", "長當多難日，愁過少年時。窮達都判了，休閒鑷白髭。"]'),
('yuding-25','白菊','許棠','唐','御定全唐诗','yuding','','[]','所尚雪霜姿，非關落帽期。香飄風外別，影到月中疑。',48,'御定全唐詩/json/604.json','["所尚雪霜姿，非關落帽期。香飄風外別，影到月中疑。", "發在林凋後，繁當露冷時。人間稀有此，自古乃無詩。"]'),
('yuding-26','中秋夜對月','許棠','唐','御定全唐诗','yuding','','[]','月月勢皆圓，中秋朗最偏。萬方期一夕，到曉是經年。',48,'御定全唐詩/json/604.json','["月月勢皆圓，中秋朗最偏。萬方期一夕，到曉是經年。", "影蔽星芒盡，光分物狀全。惟應苦吟者，目斷向遙天。"]'),
('yuding-27','陪郢州張員外宴白雪樓','許棠','唐','御定全唐诗','yuding','','[]','高情日日閑，多宴雪樓間。灑檻江幹雨，當筵天際山。',48,'御定全唐詩/json/604.json','["高情日日閑，多宴雪樓間。灑檻江幹雨，當筵天際山。", "帶帆分浪色，駐樂話朝班。豈料羈浮者，樽前得解顏。"]'),
('yuding-28','和薛侍禦題興善寺松','許棠','唐','御定全唐诗','yuding','','[]','何年劚到城，滿國響高名。半寺陰常匝，鄰坊景亦清。',48,'御定全唐詩/json/604.json','["何年劚到城，滿國響高名。半寺陰常匝，鄰坊景亦清。", "代多無朽勢，風定有餘聲。自得天然狀，非同澗底生。"]'),
('yuding-29','題鄭侍郎岩隱十韻','許棠','唐','御定全唐诗','yuding','','[]','朝退常歸隱，真修大隱情。園林應得趣，岩谷自為名。',120,'御定全唐詩/json/604.json','["朝退常歸隱，真修大隱情。園林應得趣，岩谷自為名。", "野步難尋寺，閑吟少在城。樹藏幽洞黑，花照遠村明。", "海石分湖路，風泉遞雨聲。性高憐散逸，官達厭公卿。", "架引藤重長，階延筍迸生。青門無到客，紫閣有來鶯。", "物外身雖隱，區中望本清。終難依此境，坐臥避鈞衡。"]'),
('yuding-30','宿靈山蘭若','許棠','唐','御定全唐诗','yuding','','[]','江心天半寺，一夕萬緣空。地出浮雲上，星搖積浪中。',48,'御定全唐詩/json/604.json','["江心天半寺，一夕萬緣空。地出浮雲上，星搖積浪中。", "滴漚垂閣雨，吹檜送帆風。旦夕聞清磬，唯應是釣翁。"]'),
('yuding-31','親仁裏雙鷺','許棠','唐','御定全唐诗','yuding','','[]','雙去雙來日已頻，只應知我是江人。對欹雪頂思尋水，',40,'御定全唐詩/json/604.json','["雙去雙來日已頻，只應知我是江人。對欹雪頂思尋水，", "天然不與凡禽類，傍砌聽吟性自馴。"]'),
('yuding-32','成紀書事二首','許棠','唐','御定全唐诗','yuding','','[]','東吳遠別客西秦，懷舊傷時暗灑巾。滿野多成無主塚，',80,'御定全唐詩/json/604.json','["東吳遠別客西秦，懷舊傷時暗灑巾。滿野多成無主塚，", "閑與將軍議戎事，伊蘭猶未絕胡塵。", "蹉跎遠入犬羊中，荏苒將成白首翁。三楚田園歸未得，", "難問開元向前事，依稀猶認隗囂宮。"]'),
('yuding-33','秦中遇友人','許棠','唐','御定全唐诗','yuding','','[]','半生南走複西馳，愁過楊朱罷泣岐。遠夢亦羞歸海徼，',40,'御定全唐詩/json/604.json','["半生南走複西馳，愁過楊朱罷泣岐。遠夢亦羞歸海徼，", "旦暮唯聞語征戰，看看已欲廢吟詩。"]'),
('yuding-34','過分水嶺','許棠','唐','御定全唐诗','yuding','','[]','隴山高共鳥行齊，瞰險盤空甚躡梯。雲勢崩騰時向背，',40,'御定全唐詩/json/604.json','["隴山高共鳥行齊，瞰險盤空甚躡梯。雲勢崩騰時向背，", "此去秦川無別路，隔崖窮穀卻難迷。"]'),
('yuding-35','講德陳情上淮南李僕射八首','許棠','唐','御定全唐诗','yuding','','[]','天降賢人佐聖時，自然聲教滿華夷。英明不獨中朝仰，',320,'御定全唐詩/json/604.json','["天降賢人佐聖時，自然聲教滿華夷。英明不獨中朝仰，", "梁城東下雖經戰，風俗猶傳守舊規。", "多朝軒冕冠乾坤，四海皆推聖最尊。楚玉已曾分卞玉，", "嘗念蒼生如赤子，九州無處不沾恩。", "未領春闈望早清，況聯戎閫控強兵。風威遍佈江山靜，", "東南自此全無事，只為期年政已成。", "帝念淮壖疫疹頻，牢籠山海委名臣。古來比德由無侶，", "多年疲瘵全蘇息，須到謳謠日滿秦。", "三紀吟詩望一名，丹霄待得白頭成。已期到老還沾祿，", "朱門舊是登龍客，初脫魚鱗膽尚驚。", "東來淮海拜旌旟，不把公卿一字書。曾侍晚齋吟對雪，", "唯恥舊橋題處在，榮歸無計似相如。", "平生南北逐蓬飄，待得名成鬢已凋。寒浦一從拋釣艇，", "愁策羸蹄更歸去，亂山流水滿翻潮。", "丹霄空把桂枝歸，白首依前著布衣。當路公卿誰見待，", "應念無媒居選限，二年須更守漁磯。"]'),
('yuding-36','獻獨孤尚書','許棠','唐','御定全唐诗','yuding','','[]','虛拋南楚滯西秦，白首依前衣白身。退鷁已經三十載，',40,'御定全唐詩/json/604.json','["虛拋南楚滯西秦，白首依前衣白身。退鷁已經三十載，", "今日鞠躬高旆下，欲傾肝膽杳無因。"]'),
('yuding-37','將過單于','許棠','唐','御定全唐诗','yuding','','[]','荒磧連天堡戍稀，日憂蕃寇卻忘機。江山不到處皆到，',40,'御定全唐詩/json/604.json','["荒磧連天堡戍稀，日憂蕃寇卻忘機。江山不到處皆到，", "並州去路殊迢遞，風雨何當達近畿。"]'),
('yuding-38','貞女祠','許棠','唐','御定全唐诗','yuding','','[]','何穴藏貞骨，荒祠見舊顏。精靈應自在，雲雨不相關。',48,'御定全唐詩/json/604.json','["何穴藏貞骨，荒祠見舊顏。精靈應自在，雲雨不相關。", "落石泉多咽，無風樹盡閑。唯疑千古後，為瑞向人間。"]'),
('yuding-39','宿華山','許棠','唐','御定全唐诗','yuding','','[]','異境良難測，非仙豈合遊。星辰方滿嶽，風雨忽移舟。',48,'御定全唐詩/json/604.json','["異境良難測，非仙豈合遊。星辰方滿嶽，風雨忽移舟。", "噴月泉垂壁，棲松鶴在樓。因知修養處，不必在嵩丘。"]'),
('yuding-40','送張員外西川從事','許棠','唐','御定全唐诗','yuding','','[]','為郎不入朝，自是赴嘉招。豸角初離首，金章已在腰。',48,'御定全唐詩/json/604.json','["為郎不入朝，自是赴嘉招。豸角初離首，金章已在腰。", "劍橫陰綠野，棧響近丹霄。迎驛應相續，懸愁去路遙。"]'),
('yuding-41','題慈恩寺元遂上人院','許棠','唐','御定全唐诗','yuding','','[]','竹檻匝回廊，城中似外方。月雲開作片，枝鳥立成行。',48,'御定全唐詩/json/604.json','["竹檻匝回廊，城中似外方。月雲開作片，枝鳥立成行。", "徑接河源潤，庭容塔影涼。天臺頻去說，誰占最高房。"]'),
('yuding-42','送杜倉曹往滄洲覲叔常侍','許棠','唐','御定全唐诗','yuding','','[]','浮陽橫巨浸，南巷擁旌旃。別帶秦城雨，行聞魏國蟬。',48,'御定全唐詩/json/604.json','["浮陽橫巨浸，南巷擁旌旃。別帶秦城雨，行聞魏國蟬。", "磧鴻來每後，朝日見常先。東鄙雲霞廣，高林間水天。"]'),
('yuding-43','雕陰道中作','許棠','唐','御定全唐诗','yuding','','[]','五月綏州北，途程少鬱蒸。馬依膻草聚，人抱濁河澄。',48,'御定全唐詩/json/604.json','["五月綏州北，途程少鬱蒸。馬依膻草聚，人抱濁河澄。", "跡固長城壘，冤深太子陵。往來經此地，悲苦有誰能。"]'),
('yuding-44','留別從弟郴','許棠','唐','御定全唐诗','yuding','','[]','同承太嶽胤，俱值太平時。丹陛懷趨計，滄洲負去期。',48,'御定全唐詩/json/604.json','["同承太嶽胤，俱值太平時。丹陛懷趨計，滄洲負去期。", "久貧成蹭蹬，多病惜支離。宗分兼交分，吾知汝亦知。"]'),
('yuding-45','尋山','許棠','唐','御定全唐诗','yuding','','[]','躡履複支筇，深山草木中。隔溪遙避虎，當塢忽聞鐘。',48,'御定全唐詩/json/604.json','["躡履複支筇，深山草木中。隔溪遙避虎，當塢忽聞鐘。", "落葉多相似，幽禽半不同。群猱呼卻散，如此異林翁。"]'),
('yuding-46','送徐侍禦充南詔判官','許棠','唐','御定全唐诗','yuding','','[]','西去安夷落，乘軺從節行。彤庭傳聖旨，異域化戎情。',96,'御定全唐詩/json/604.json','["西去安夷落，乘軺從節行。彤庭傳聖旨，異域化戎情。", "瘴路窮巴徼，蠻川過嶠城。地偏風自雜，天漏月稀明。", "危棧連空動，長江到底清。笑宜防狒狒，言好聽猩猩。", "撫論如敦行，歸情自合盟。回期佩印綬，何更見新正。"]'),
('yuding-47','送省玄上人歸江東','許棠','唐','御定全唐诗','yuding','','[]','釋律周儒禮，嚴持用戒身。安禪思剡石，留偈別都人。',48,'御定全唐詩/json/604.json','["釋律周儒禮，嚴持用戒身。安禪思剡石，留偈別都人。", "雨合吳江黑，潮移海路新。瓶盂自此去，應不更還秦。"]'),
('yuding-48','送劉校書游東魯','許棠','唐','御定全唐诗','yuding','','[]','內閣勞讎校，東邦忽縱遊。才偏精二雅，分合遇諸侯。',48,'御定全唐詩/json/604.json','["內閣勞讎校，東邦忽縱遊。才偏精二雅，分合遇諸侯。", "暗海龜蒙雨，連空趙魏秋。如經麟見處，駐馬瞰荒丘。"]'),
('yuding-49','送金吾侍禦奉使日東','許棠','唐','御定全唐诗','yuding','','[]','還鄉兼作使，到日倍榮親。向化雖多國，如公有幾人。',48,'御定全唐詩/json/604.json','["還鄉兼作使，到日倍榮親。向化雖多國，如公有幾人。", "孤山無返照，積水合蒼旻。膝下知難住，金章已系身。"]'),
('yuding-50','題甘露寺','許棠','唐','御定全唐诗','yuding','','[]','丹檻拂丹霄，人寰下瞰遙。何年增造化，萬古出塵囂。',120,'御定全唐詩/json/604.json','["丹檻拂丹霄，人寰下瞰遙。何年增造化，萬古出塵囂。", "地勢盤三楚，江聲換幾朝。滿欄皆異藥，到頂盡飛橋。", "澤廣方雲夢，山孤數沃焦。中宵霞始散，經臘木稀凋。", "鐸動天風度，窗明海氣消。帶鼙分迥堞，當日辨翻潮。", "鳥去沉葭菼，帆來映泬。浮生自多事，無計免回鑣。"]'),
('yuding-51','冬夜懷真裏友人會宿','許棠','唐','御定全唐诗','yuding','','[]','靜語與高吟，搜神又爽心。各來依帝裏，相對似山陰。',48,'御定全唐詩/json/604.json','["靜語與高吟，搜神又爽心。各來依帝裏，相對似山陰。", "漏永星河沒，堂寒月彩深。從容不易到，莫惜曙鐘侵。"]'),
('yuding-52','陪友人夏夜對月','許棠','唐','御定全唐诗','yuding','','[]','後伏中宵月，高秋滿魄齊。輪移仙掌外，影下玉繩西。',48,'御定全唐詩/json/604.json','["後伏中宵月，高秋滿魄齊。輪移仙掌外，影下玉繩西。", "蟬雀飛多誤，星螢出自迷。煩蒸驚頓絕，吟玩畏聞雞。"]'),
('yuding-53','送從弟籌任告成尉','許棠','唐','御定全唐诗','yuding','','[]','海上從戎罷，嵩陽佐縣初。故人皆羨去，吾祖舊曾居。',48,'御定全唐詩/json/604.json','["海上從戎罷，嵩陽佐縣初。故人皆羨去，吾祖舊曾居。", "地古多生藥，溪靈不聚魚。唯應尋隱者，閑寺講仙書。"]'),
('yuding-54','秋日陪陸校書遊玉泉','許棠','唐','御定全唐诗','yuding','','[]','共愛泉源異，頻來不覺勞。散光垂草細，繁響出風高。',48,'御定全唐詩/json/604.json','["共愛泉源異，頻來不覺勞。散光垂草細，繁響出風高。", "沫滯潭花片，沙遺浴鳥毛。塵間喧與悶，須向此中逃。"]'),
('yuding-55','送防州鄔員外','許棠','唐','御定全唐诗','yuding','','[]','千溪與萬嶂，繚繞複崢嶸。太守勞車馬，何從駐旆旌。',48,'御定全唐詩/json/604.json','["千溪與萬嶂，繚繞複崢嶸。太守勞車馬，何從駐旆旌。", "椒香近滿郭，漆貨遠通京。唯滌雙塵耳，東南聽政聲。"]'),
('yuding-56','過穆陵關','許棠','唐','御定全唐诗','yuding','','[]','荒關無守吏，亦恥白衣過。地廣人耕絕，天寒雁下多。',48,'御定全唐詩/json/604.json','["荒關無守吏，亦恥白衣過。地廣人耕絕，天寒雁下多。", "東西方自感，雨雪更相和。日暮聊攄思，搖鞭一放歌。"]'),
('yuding-57','江上遇友人','許棠','唐','御定全唐诗','yuding','','[]','闕下分離日，杏園花半開。江邊相值夜，榆塞雁初來。',48,'御定全唐詩/json/604.json','["闕下分離日，杏園花半開。江邊相值夜，榆塞雁初來。", "坐久河沉鬥，吟長月浸杯。鱸魚非不戀，共有客程催。"]'),
('yuding-58','憶宛陵舊居','許棠','唐','御定全唐诗','yuding','','[]','舊憶陵陽北，林園近板橋。江晴帆影滿，野迥鶴聲遙。',48,'御定全唐詩/json/604.json','["舊憶陵陽北，林園近板橋。江晴帆影滿，野迥鶴聲遙。", "島徑通山市，汀扉上海潮。秦城歸去夢，夜夜到漁樵。"]'),
('yuding-59','題聞琴館','許棠','唐','御定全唐诗','yuding','','[]','城非宓賤邑，館亦號聞琴。乃是前賢意，常留化俗心。',48,'御定全唐詩/json/604.json','["城非宓賤邑，館亦號聞琴。乃是前賢意，常留化俗心。", "代公存綠綺，誰更寄清音。此跡應無改，寥寥畢古今。"]'),
('yuding-60','寄江上弟妹','許棠','唐','御定全唐诗','yuding','','[]','無成歸未得，不是不謀歸。垂老登雲路，猶勝守釣磯。',48,'御定全唐詩/json/604.json','["無成歸未得，不是不謀歸。垂老登雲路，猶勝守釣磯。", "大荒身去數，窮海信來稀。孤立皆難進，非關命獨違。"]'),
('yuding-61','題李昌符豐樂幽居','許棠','唐','御定全唐诗','yuding','','[]','詩家依闕下，野景似山中。蘭菊俱含露，杉梧為奏風。',48,'御定全唐詩/json/604.json','["詩家依闕下，野景似山中。蘭菊俱含露，杉梧為奏風。", "破門韋曲對，淺岸禦溝通。莫歎連年屈，君須遇至公。"]'),
('yuding-62','青山晚望','許棠','唐','御定全唐诗','yuding','','[]','昔人懷感處，此地倍魂消。四海經搖落，三吳正寂寥。',48,'御定全唐詩/json/604.json','["昔人懷感處，此地倍魂消。四海經搖落，三吳正寂寥。", "風移殘燒遠，帆帶夕陽遙。欲繼前賢跡，誰能似隱招。"]'),
('yuding-63','宣城送進士鄭徽赴舉','許棠','唐','御定全唐诗','yuding','','[]','長安去是歸，上馬肯沾衣。水國車通少，秦人楚薦稀。',48,'御定全唐詩/json/604.json','["長安去是歸，上馬肯沾衣。水國車通少，秦人楚薦稀。", "鴻方離北鄙，葉下已西畿。好整丹霄步，知音在紫微。"]'),
('yuding-64','言懷','許棠','唐','御定全唐诗','yuding','','[]','萬事不關心，終朝但苦吟。久貧慚負債，漸老愛山深。',48,'御定全唐詩/json/604.json','["萬事不關心，終朝但苦吟。久貧慚負債，漸老愛山深。", "日月銷天外，帆檣棄海陰。榮枯應已定，無複系浮沉。"]'),
('yuding-65','汴河十二韻','許棠','唐','御定全唐诗','yuding','','[]','昔年開汴水，元應別有由。或兼通楚塞，寧獨為揚州。',144,'御定全唐詩/json/604.json','["昔年開汴水，元應別有由。或兼通楚塞，寧獨為揚州。", "直斷平蕪色，橫分積石流。所思千里便，豈計萬方憂。", "首甚資功濟，終難弭宴遊。空懷龍舸下，不見錦帆收。", "浪倒長汀柳，風欹遠岸樓。奔逾懷許竭，澄澈泗濱休。", "路要多行客，魚稀少釣舟。日開天際晚，雁合磧西秋。", "一派注滄海，幾人生白頭。常期身事畢，於此泳東浮。"]'),
('yuding-66','旅中送人歸九華','許棠','唐','御定全唐诗','yuding','','[]','分與仙山背，多年負翠微。無因隨鹿去，只是送人歸。',48,'御定全唐詩/json/604.json','["分與仙山背，多年負翠微。無因隨鹿去，只是送人歸。", "頂木晴摩日，根嵐曉潤衣。會於猿鳥外，相對掩高扉。"]'),
('yuding-67','送友人歸江南','許棠','唐','御定全唐诗','yuding','','[]','皇州五更鼓，月落西南維。此時有行客，別我孤舟歸。',36,'御定全唐詩/json/604.json','["皇州五更鼓，月落西南維。此時有行客，別我孤舟歸。", "上國身無主，下第誠可悲。"]'),
('yuding-68','洞庭湖','許棠','唐','御定全唐诗','yuding','','[]','空江浩蕩景蕭然，盡日菰蒲泊釣船。青草浪高三月渡，',40,'御定全唐詩/json/604.json','["空江浩蕩景蕭然，盡日菰蒲泊釣船。青草浪高三月渡，", "猶有漁人數家住，不成村落夕陽邊。"]'),
('yuding-69','句','許棠','唐','御定全唐诗','yuding','','[]','曉嶂猿開戶，寒湫鹿舐冰。',36,'御定全唐詩/json/604.json','["曉嶂猿開戶，寒湫鹿舐冰。", "當空吟待月，到晚坐看山。", "一年三領郡，領郡管仙山。"]'),
('yuding-0','放歌行','邵謁','唐','御定全唐诗','yuding','','[]','龜為秉靈亡，魚為弄珠死。心中自有賊，莫怨任公子。',36,'御定全唐詩/json/605.json','["龜為秉靈亡，魚為弄珠死。心中自有賊，莫怨任公子。", "屈原若不賢，焉得沉湘水。"]'),
('yuding-1','長安寒食','邵謁','唐','御定全唐诗','yuding','','[]','春日照九衢，春風媚羅綺。萬騎出都門，擁在香塵裏。',60,'御定全唐詩/json/605.json','["春日照九衢，春風媚羅綺。萬騎出都門，擁在香塵裏。", "莫辭吊枯骨，千載長如此。安知今日身，不是昔時鬼。", "但看平地遊，亦見摧輈死。"]'),
('yuding-2','貞女墓','邵謁','唐','御定全唐诗','yuding','','[]','生持節操心，死作堅貞鬼。至今墳上春，草木無花卉。',24,'御定全唐詩/json/605.json','["生持節操心，死作堅貞鬼。至今墳上春，草木無花卉。"]'),
('yuding-3','自歎','邵謁','唐','御定全唐诗','yuding','','[]','春蠶未成繭，已賀箱籠實。蟢子徒有絲，終年不成匹。',84,'御定全唐詩/json/605.json','["春蠶未成繭，已賀箱籠實。蟢子徒有絲，終年不成匹。", "每念古人言，有得則有失。我命獨如何，憔悴長如一。", "白日九衢中，幽獨暗如漆。流泉有枯時，窮賤無盡日。", "惆悵複惆悵，幾回新月出。"]'),
('yuding-4','送徐群宰望江','邵謁','唐','御定全唐诗','yuding','','[]','古人力文學，所務安疲甿。今人力文學，所務惟公卿。',180,'御定全唐詩/json/605.json','["古人力文學，所務安疲甿。今人力文學，所務惟公卿。", "大賢重邦本，屈跡官武城。勸民勤機杼，自然國用並。", "但見富貴者，知食不知耕。忽爾秋不熟，儲廩焉得盈。", "貢藝既精苦，用心必公平。吾道不遺賢，霄漢期芳馨。", "一夫若有德，千古稱其英。陶潛雖理邑，崔烈徒台衡。", "濁者必惡清，瞽者必惡明。孤松自有色，豈奪眾草榮。", "為刀若不利，焉得宰牛名。為絲若不直，焉得琴上聲。", "好去立高節，重來振羽翎。"]'),
('yuding-5','秋夕','邵謁','唐','御定全唐诗','yuding','','[]','萬里憑夢歸，骨肉皆在眼。覺來益惆悵，不信長安遠。',60,'御定全唐詩/json/605.json','["萬里憑夢歸，骨肉皆在眼。覺來益惆悵，不信長安遠。", "人人但為農，我獨常逢旱。惡命如漏卮，滴滴添不滿。", "天末雁來時，一叫一腸斷。"]'),
('yuding-6','覽孟東野集','邵謁','唐','御定全唐诗','yuding','','[]','蚌死留夜光，劍折留鋒鋩。哲人歸大夜，千古傳珪璋。',60,'御定全唐詩/json/605.json','["蚌死留夜光，劍折留鋒鋩。哲人歸大夜，千古傳珪璋。", "珪璋遍四海，人倫多變改。題花花已無，玩月月猶在。", "不知天地間，白日幾時昧。"]'),
('yuding-7','送友人江行','邵謁','唐','御定全唐诗','yuding','','[]','送君若浪水，疊疊愁思起。夢魂如月明，相送秋江裏。',24,'御定全唐詩/json/605.json','["送君若浪水，疊疊愁思起。夢魂如月明，相送秋江裏。"]'),
('yuding-8','下第有感','邵謁','唐','御定全唐诗','yuding','','[]','古人有遺言，天地如掌闊。我行三十載，青雲路未達。',84,'御定全唐詩/json/605.json','["古人有遺言，天地如掌闊。我行三十載，青雲路未達。", "嘗聞讀書者，所貴免征伐。誰知失意時，痛於刃傷骨。", "身如石上草，根蒂淺難活。人人皆愛春，我獨愁花發。", "如何歸故山，相攜采薇蕨。"]'),
('yuding-9','論政','邵謁','唐','御定全唐诗','yuding','','[]','賢哉三握發，為有天下憂。孫弘不開閣，丙吉甯問牛。',96,'御定全唐詩/json/605.json','["賢哉三握發，為有天下憂。孫弘不開閣，丙吉甯問牛。", "內政由股肱，外政由諸侯。股肱政若行，諸侯政自修。", "一物不得所，蟻穴滿山丘。莫言萬木死，不因一葉秋。", "朱雲若不直，漢帝終自由。子嬰一失國，渭水東悠悠。"]'),
('yuding-10','戰城南','邵謁','唐','御定全唐诗','yuding','','[]','武皇重征伐，戰士輕生死。朝爭刃上功，暮作泉下鬼。',48,'御定全唐詩/json/605.json','["武皇重征伐，戰士輕生死。朝爭刃上功，暮作泉下鬼。", "悲風吊枯骨，明月照荒壘。千載留長聲，嗚咽城南水。"]'),
('yuding-11','贈鄭殷處士','邵謁','唐','御定全唐诗','yuding','','[]','善琴不得聽，嘉玉不得名。知音既已死，良匠亦未生。',72,'御定全唐詩/json/605.json','["善琴不得聽，嘉玉不得名。知音既已死，良匠亦未生。", "退居一河湄，山中物景清。魚沉池水碧，鶴去松枝輕。", "長材靡入用，大廈失巨楹。顏子不得祿，誰謂天道平。"]'),
('yuding-12','古樂府','邵謁','唐','御定全唐诗','yuding','','[]','對酒彈古琴，弦中發新音。新音不可辨，十指幽怨深。',72,'御定全唐詩/json/605.json','["對酒彈古琴，弦中發新音。新音不可辨，十指幽怨深。", "妾顏不自保，四時如車輪。不知今夜月，曾照幾時人。", "露滴芙蓉香，香銷心亦死。良時無可留，殘紅謝池水。"]'),
('yuding-13','經安容先生舊居','邵謁','唐','御定全唐诗','yuding','','[]','羽化留遺蹤，千載蹤難沒。一泉岩下水，幾度換明月。',60,'御定全唐詩/json/605.json','["羽化留遺蹤，千載蹤難沒。一泉岩下水，幾度換明月。", "松老不改柯，龍久皆變骨。雲雨有歸時，雞犬無還日。", "至今青山中，寂寞桃花發。"]'),
('yuding-14','望行人','邵謁','唐','御定全唐诗','yuding','','[]','登樓恐不高，及高君已遠。雲行郎即行，雲歸郎不返。',60,'御定全唐詩/json/605.json','["登樓恐不高，及高君已遠。雲行郎即行，雲歸郎不返。", "嗟為樓上人，望望不相近。若作轍中泥，不放郎車轉。", "白日下西山，望盡妾腸斷。"]'),
('yuding-15','歲豐','邵謁','唐','御定全唐诗','yuding','','[]','皇天降豐年，本憂貧士食。貧士無良疇，安能得稼穡。',60,'御定全唐詩/json/605.json','["皇天降豐年，本憂貧士食。貧士無良疇，安能得稼穡。", "工傭輸富家，日落長歎息。為供豪者糧，役盡匹夫力。", "天地莫施恩，施恩強者得。"]'),
('yuding-16','金谷園懷古','邵謁','唐','御定全唐诗','yuding','','[]','在富莫驕奢，驕奢多自亡。為女莫騁容，騁容多自傷。',108,'御定全唐詩/json/605.json','["在富莫驕奢，驕奢多自亡。為女莫騁容，騁容多自傷。", "如何金穀園，鬱鬱椒蘭房。昨夜綺羅列，今日池館荒。", "竹死不變節，花落有餘香。美人抱義死，千載名猶彰。", "嬌歌無遺音，明月留清光。浮雲易改色，衰草難重芳。", "不學韓侯婦，銜冤報宋王。"]'),
('yuding-17','春日有感','邵謁','唐','御定全唐诗','yuding','','[]','我心如蘖苦，他見如薺甘。火未到身者，痛楚難共諳。',48,'御定全唐詩/json/605.json','["我心如蘖苦，他見如薺甘。火未到身者，痛楚難共諳。", "但言貧者拙，不言富者貪。誰知苦寒女，力盡為桑蠶。"]'),
('yuding-18','學仙詞','邵謁','唐','御定全唐诗','yuding','','[]','上仙傳秘訣，澹薄與無營。煉藥□□□，變姓不變形。',60,'御定全唐詩/json/605.json','["上仙傳秘訣，澹薄與無營。煉藥□□□，變姓不變形。", "三屍既無累，百慮自不生。是知寸心中，有路通上清。", "祖龍好仙術，燒卻黃金精。"]'),
('yuding-19','妓女','邵謁','唐','御定全唐诗','yuding','','[]','天若許人登，青山高不止。地若許人窮，黃泉深無水。',96,'御定全唐詩/json/605.json','["天若許人登，青山高不止。地若許人窮，黃泉深無水。", "量諸造化情，物成皆有以。如何上青冥，視之平若砥。", "日下騁琅玕，空中無羅綺。但見勢騰淩，將為長如此。", "炫耀一時間，逡巡九泉裏。一種為埃塵，不學墮樓死。"]'),
('yuding-20','寒女行','邵謁','唐','御定全唐诗','yuding','','[]','寒女命自薄，生來多賤微。家貧人不聘，一身無所歸。',108,'御定全唐詩/json/605.json','["寒女命自薄，生來多賤微。家貧人不聘，一身無所歸。", "養蠶多苦心，繭熟他人絲。織素徒苦力，素成他人衣。", "青樓富家女，才生便有主。終日著羅綺，何曾識機杼。", "清夜聞歌聲，聽之淚如雨。他人如何歡，我意又何苦。", "所以問皇天，皇天竟無語。"]'),
('yuding-21','覽鏡','邵謁','唐','御定全唐诗','yuding','','[]','一照一回悲，再照顏色衰。日月自流水，不知身老時。',48,'御定全唐詩/json/605.json','["一照一回悲，再照顏色衰。日月自流水，不知身老時。", "昨日照紅顏，今朝照白絲。白絲與紅顏，相去咫尺間。"]'),
('yuding-22','輕薄行','邵謁','唐','御定全唐诗','yuding','','[]','薄薄身上衣，輕輕浮雲質。長安一花開，九陌馬蹄疾。',36,'御定全唐詩/json/605.json','["薄薄身上衣，輕輕浮雲質。長安一花開，九陌馬蹄疾。", "誰言公子車，不是天上力。"]'),
('yuding-23','苦別離','邵謁','唐','御定全唐诗','yuding','','[]','十五為君婚，二十入君門。自從入戶後，見君長出門。',84,'御定全唐詩/json/605.json','["十五為君婚，二十入君門。自從入戶後，見君長出門。", "朝看相送人，暮看相送人。若遣折楊柳，此地樹無根。", "願為陌上土，得作馬蹄塵。願為曲木枝，得作雙車輪。", "安得太行山，移來君馬前。"]'),
('yuding-24','覽張騫傳','邵謁','唐','御定全唐诗','yuding','','[]','采藥不得根，尋河不得源。此時虛白首，徒感武皇恩。',60,'御定全唐詩/json/605.json','["采藥不得根，尋河不得源。此時虛白首，徒感武皇恩。", "桑田未聞改，日月曾幾昏。仙骨若求得，壟頭無新墳。", "不見杜陵草，至今空自繁。"]'),
('yuding-25','白頭吟','邵謁','唐','御定全唐诗','yuding','','[]','漢家天宇闊，日月不暫閑。常將古今骨，裨作北邙山。',36,'御定全唐詩/json/605.json','["漢家天宇闊，日月不暫閑。常將古今骨，裨作北邙山。", "山高勢已極，猶自凋朱顏。"]'),
('yuding-26','瞽者歎','邵謁','唐','御定全唐诗','yuding','','[]','我心豈不平，我目自不明。徒雲備雙足，天下何由行。',24,'御定全唐詩/json/605.json','["我心豈不平，我目自不明。徒雲備雙足，天下何由行。"]'),
('yuding-27','送從弟長安下第南歸覲親','邵謁','唐','御定全唐诗','yuding','','[]','白日不得照，戴天如戴盆。青雲未見路，丹車勞出門。',180,'御定全唐詩/json/605.json','["白日不得照，戴天如戴盆。青雲未見路，丹車勞出門。", "采薇秦山鎮，養親湘水源。心中豈不切，其如行路難。", "為文清益峻，為心直且安。芝蘭未入用，馨香志獨存。", "他門種桃李，猶能蔭子孫。我家有棠陰，枝葉竟不繁。", "心醉豈因酒，愁多徒見萱。征徒忽告歸，執袂殷勤論。", "在鳥終為鳳，為魚須化鯤。富貴豈長守，貧賤寧有根。", "丈夫志不大，何以佐乾坤。晝短疾於箭，早來獻天言。", "莫戀蒼梧畔，野煙橫破村。"]'),
('yuding-28','少年行','邵謁','唐','御定全唐诗','yuding','','[]','丈夫十八九，膽氣欺韓彭。報仇不用劍，輔國不用兵。',64,'御定全唐詩/json/605.json','["丈夫十八九，膽氣欺韓彭。報仇不用劍，輔國不用兵。", "以目為水鑒，以心作權衡。願君似堯舜，能使天下平。", "何必走馬誇弓矢，然後致得人心爭。"]'),
('yuding-29','漢宮井','邵謁','唐','御定全唐诗','yuding','','[]','轆轤聲絕離宮靜，班姬幾度照金井。',32,'御定全唐詩/json/605.json','["轆轤聲絕離宮靜，班姬幾度照金井。", "梧桐老去殘花開，猶似當時美人影。"]'),
('yuding-30','顯茂樓','邵謁','唐','御定全唐诗','yuding','','[]','秦山渭水尚悠悠，如何草樹迷宮闕。',32,'御定全唐詩/json/605.json','["秦山渭水尚悠悠，如何草樹迷宮闕。", "繁華朱翠盡東流，唯有望樓對明月。"]'),
('yuding-31','紫閣峰','邵謁','唐','御定全唐诗','yuding','','[]','壯國山河倚空碧，迥拔煙霞侵太白。',32,'御定全唐詩/json/605.json','["壯國山河倚空碧，迥拔煙霞侵太白。", "綠崖下視千萬尋，青天只據百餘尺。"]'),
('yuding-0','送李員外頻之建州','林寬','唐','御定全唐诗','yuding','','[]','勾踐江頭月，客星台畔松。為郎久不見，出守暫相逢。',48,'御定全唐詩/json/606.json','["勾踐江頭月，客星台畔松。為郎久不見，出守暫相逢。", "鳥泊牽灘索，花空押號鐘。遠人思化切，休上武夷峰。"]'),
('yuding-1','送許棠先輩歸宣州','林寬','唐','御定全唐诗','yuding','','[]','發枯窮律韻，字字合塤篪。日月所到處，姓名無不知。',48,'御定全唐詩/json/606.json','["發枯窮律韻，字字合塤篪。日月所到處，姓名無不知。", "鶯啼謝守壘，苔老謫仙碑。詩道喪來久，東歸為吊之。"]'),
('yuding-2','窮冬太學','林寬','唐','御定全唐诗','yuding','','[]','投跡依槐館，荒亭草合時。雪深鳶嘯急，薪濕鼎吟遲。',48,'御定全唐詩/json/606.json','["投跡依槐館，荒亭草合時。雪深鳶嘯急，薪濕鼎吟遲。", "默坐同誰話，非僧不我知。匡廬瀑布畔，何日副心期。"]'),
('yuding-3','陪鄭諴郎中假日省中寓直','林寬','唐','御定全唐诗','yuding','','[]','憲廳名最重，假日許從容。床滿諸司印，庭高五粒松。',48,'御定全唐詩/json/606.json','["憲廳名最重，假日許從容。床滿諸司印，庭高五粒松。", "井尋芸吏汲，茶拆岳僧封。鳥度簾旌暮，猶吟隔苑鐘。"]'),
('yuding-4','送謝石先輩歸宣州','林寬','唐','御定全唐诗','yuding','','[]','名隨春色遠，湖外已先知。花盡方辭醉，鶯殘是放時。',48,'御定全唐詩/json/606.json','["名隨春色遠，湖外已先知。花盡方辭醉，鶯殘是放時。", "天寒千尺岳，頷白半聯詩。筍蕨猶堪采，榮歸及養期。"]'),
('yuding-5','下第寄歐陽瓚','林寬','唐','御定全唐诗','yuding','','[]','詩人道僻命多奇，更值干戈亂起時。',32,'御定全唐詩/json/606.json','["詩人道僻命多奇，更值干戈亂起時。", "莫作江甯王少府，一生吟苦竟誰知。"]'),
('yuding-6','寄何紹餘','林寬','唐','御定全唐诗','yuding','','[]','雁過君猶未入城，清賢門下舊知名。風波凍馬遙逢見，',40,'御定全唐詩/json/606.json','["雁過君猶未入城，清賢門下舊知名。風波凍馬遙逢見，", "芙蓉苑北曲江岸，期看終南新雪晴。"]'),
('yuding-7','送人宰浦城','林寬','唐','御定全唐诗','yuding','','[]','東南猶阻寇，梨嶺更誰登。作宰應無俸，歸船必有僧。',48,'御定全唐詩/json/606.json','["東南猶阻寇，梨嶺更誰登。作宰應無俸，歸船必有僧。", "灘平眠獺石，燒斷飲猿藤。歲盡校殊最，方當見異能。"]'),
('yuding-8','省試臘後望春宮','林寬','唐','御定全唐诗','yuding','','[]','皇都初度臘，鳳輦出深宮。高憑樓臺上，遙瞻灞滻中。',72,'御定全唐詩/json/606.json','["皇都初度臘，鳳輦出深宮。高憑樓臺上，遙瞻灞滻中。", "仗凝霜彩白，袍映日華紅。柳眼方開凍，鶯聲漸轉風。", "禦溝穿斷靄，驪岫照斜空。時見宸遊興，因觀稼穡功。"]'),
('yuding-9','寄省中知己','林寬','唐','御定全唐诗','yuding','','[]','門掩清曹晚，靜將烏府鄰。花開封印早，雪下典衣頻。',48,'御定全唐詩/json/606.json','["門掩清曹晚，靜將烏府鄰。花開封印早，雪下典衣頻。", "怪木風吹閣，廢巢時落薪。每憐吾道苦，長說向同人。"]'),
('yuding-10','朱坡','林寬','唐','御定全唐诗','yuding','','[]','朱坡坡上望，不似在秦京。漸覺溪山秀，更高魚鳥情。',48,'御定全唐詩/json/606.json','["朱坡坡上望，不似在秦京。漸覺溪山秀，更高魚鳥情。", "夜吟禪子室，曉爨獵人鐺。恃此偷佳賞，九衢蜩未鳴。"]'),
('yuding-11','酬陳樵見寄','林寬','唐','御定全唐诗','yuding','','[]','失意閑眠起更遲，又將羈薄謝深知。囊書旋入酒家盡，',40,'御定全唐詩/json/606.json','["失意閑眠起更遲，又將羈薄謝深知。囊書旋入酒家盡，", "元和才子多如此，除卻清吟何所為。"]'),
('yuding-12','華清宮','林寬','唐','御定全唐诗','yuding','','[]','殿角鐘殘立宿鴉，朝元歸駕望無涯。',32,'御定全唐詩/json/606.json','["殿角鐘殘立宿鴉，朝元歸駕望無涯。", "香泉空浸宮前草，未到春時爭發花。"]'),
('yuding-13','終南山','林寬','唐','御定全唐诗','yuding','','[]','標奇聳峻壯長安，影入千門萬戶寒。',32,'御定全唐詩/json/606.json','["標奇聳峻壯長安，影入千門萬戶寒。", "徒自倚天生氣色，塵中誰為舉頭看。"]'),
('yuding-14','歌風台','林寬','唐','御定全唐诗','yuding','','[]','蒿棘空存百尺基，酒酣曾唱大風詞。',32,'御定全唐詩/json/606.json','["蒿棘空存百尺基，酒酣曾唱大風詞。", "莫言馬上得天下，自古英雄盡解詩。"]'),
('yuding-15','送人歸日東','林寬','唐','御定全唐诗','yuding','','[]','滄溟西畔望，一望一心摧。地即同正朔，天教阻往來。',48,'御定全唐詩/json/606.json','["滄溟西畔望，一望一心摧。地即同正朔，天教阻往來。", "波翻夜作電，鯨吼晝為雷。門外人參徑，到時花幾開。"]'),
('yuding-16','寓興','林寬','唐','御定全唐诗','yuding','','[]','西母一杯酒，空言浩劫春。英雄歸厚土，日月照閒人。',48,'御定全唐詩/json/606.json','["西母一杯酒，空言浩劫春。英雄歸厚土，日月照閒人。", "衰草珠璣塚，冷灰龍鳳身。茂陵驪岫晚，過者暗傷神。"]'),
('yuding-17','少年行','林寬','唐','御定全唐诗','yuding','','[]','柳煙侵禦道，門映夾城開。白日莫空過，青春不再來。',48,'御定全唐詩/json/606.json','["柳煙侵禦道，門映夾城開。白日莫空過，青春不再來。", "報仇沖雪去，乘醉臂鷹回。看取歌鐘地，殘陽滿壞台。"]'),
('yuding-18','塞上還答友人','林寬','唐','御定全唐诗','yuding','','[]','無端遊絕塞，歸鬢已蒼然。戎羯圍中過，風沙馬上眠。',48,'御定全唐詩/json/606.json','["無端遊絕塞，歸鬢已蒼然。戎羯圍中過，風沙馬上眠。", "草衰頻過燒，耳冷不聞蟬。從此甘貧坐，休言更到邊。"]'),
('yuding-19','哭棲白供奉','林寬','唐','御定全唐诗','yuding','','[]','侍輦才難得，三朝有上人。琢詩方到骨，至死不離貧。',48,'御定全唐詩/json/606.json','["侍輦才難得，三朝有上人。琢詩方到骨，至死不離貧。", "風帳孤螢入，霜階積葉頻。夕陽門半掩，過此亦無因。"]'),
('yuding-20','送升道靖恭相公分司','林寬','唐','御定全唐诗','yuding','','[]','東風時不遇，果見致君難。海嶽影猶動，鶤鵬勢未安。',48,'御定全唐詩/json/606.json','["東風時不遇，果見致君難。海嶽影猶動，鶤鵬勢未安。", "星沉關鎖冷，雞唱驛燈殘。誰似二賓客，門閑嵩洛寒。"]'),
('yuding-21','關下早行','林寬','唐','御定全唐诗','yuding','','[]','軋軋推危轍，聽雞獨早行。風吹宿靄散，月照華山明。',48,'御定全唐詩/json/606.json','["軋軋推危轍，聽雞獨早行。風吹宿靄散，月照華山明。", "白首東西客，黃河晝夜清。相逢皆有事，唯我是閒情。"]'),
('yuding-22','曲江','林寬','唐','御定全唐诗','yuding','','[]','曲江初碧草初青，萬轂千蹄匝岸行。傾國妖姬雲鬢重，',40,'御定全唐詩/json/606.json','["曲江初碧草初青，萬轂千蹄匝岸行。傾國妖姬雲鬢重，", "柳絮杏花留不得，隨風處處逐歌聲。"]'),
('yuding-23','長安遣懷','林寬','唐','御定全唐诗','yuding','','[]','醉下高樓醒複登，任從浮薄笑才能。',32,'御定全唐詩/json/606.json','["醉下高樓醒複登，任從浮薄笑才能。", "青龍寺裏三門上，立為南山不為僧。"]'),
('yuding-24','送僧游太白峰','林寬','唐','御定全唐诗','yuding','','[]','雲深游太白，莫惜遍探奇。頂上多靈跡，塵中少客知。',48,'御定全唐詩/json/606.json','["雲深游太白，莫惜遍探奇。頂上多靈跡，塵中少客知。", "懸崖倚凍瀑，飛狖過孤枝。出定更何事，相逢必有詩。"]'),
('yuding-25','哭造微禪師','林寬','唐','御定全唐诗','yuding','','[]','神遷不火葬，新塔露疏檉。是物皆磨滅，唯師出死生。',48,'御定全唐詩/json/606.json','["神遷不火葬，新塔露疏檉。是物皆磨滅，唯師出死生。", "虛堂散釣叟，怪木哭山精。林下路長在，無因更此行。"]'),
('yuding-26','獻同年孔郎中','林寬','唐','御定全唐诗','yuding','','[]','炊瓊爇桂帝關居，賣盡寒衣典盡書。驅馬每尋霜影裏，',40,'御定全唐詩/json/606.json','["炊瓊爇桂帝關居，賣盡寒衣典盡書。驅馬每尋霜影裏，", "一顧深恩身未殺，爭期皎日負吹噓。"]'),
('yuding-27','聞雁','林寬','唐','御定全唐诗','yuding','','[]','接影橫空背雪飛，聲聲寒出玉關遲。',32,'御定全唐詩/json/606.json','["接影橫空背雪飛，聲聲寒出玉關遲。", "上陽宮裏三千夢，月冷風清聞過時。"]');
